CHEMISTRY_CAPTURE_PATTERN = re.compile(r"^(?P<prefix><=|<|≤)?\s*(?P<number>\d+(?:[.,]\d+)?)\s*%?$")
CHEMISTRY_CAPTURE_FIELD_ORDER = [
    "Si",
    "Fe",
    "Cu",
    "Mn",
    "Mg",
    "Cr",
    "Ni",
    "Zn",
    "Ti",
    "Cd",
    "Hg",
    "Pb",
    "V",
    "Bi",
    "Sn",
    "Zr",
    "Be",
    "Zr+Ti",
    "Mn+Cr",
    "Bi+Pb",
]
PROPERTY_CAPTURE_FIELD_ORDER = ["Rm", "Rp0.2", "A%", "HB", "IACS%", "Rp0.2 / Rm"]


def parse_property_number(value: str | None) -> float | None:
    if value is None:
        return None
    normalized = str(value).strip().replace(" ", "").replace(",", ".")
    if not normalized:
        return None
    try:
        parsed = float(normalized)
    except (TypeError, ValueError):
        return None
    return parsed if math.isfinite(parsed) else None


