def _normalize_chemistry_capture_value(value: str | None) -> str | None:
    raw = _string_or_none(value)
    if raw is None:
        return None
    compact = raw.replace(" ", "").replace("≤", "<=")
    match = CHEMISTRY_CAPTURE_PATTERN.match(compact)
    if not match:
        return None
    prefix = match.group("prefix") or ""
    number = (match.group("number") or "").replace(".", ",")
    if "," not in number and number.startswith("0") and len(number) > 1:
        number = f"0,{number[1:]}"
    if not number:
        return None
    return f"{prefix}{number}"


def _safe_chemistry_float(value: str | None) -> float | None:
    normalized = _normalize_chemistry_capture_value(value)
    if normalized is None:
        return None
    numeric = normalized.replace("<=", "").replace("<", "").replace("≤", "").replace(",", ".")
    try:
        return float(numeric)
    except ValueError:
        return None


def _normalize_property_field_name(field_name: str | None) -> str | None:
    cleaned = _string_or_none(field_name)
    if cleaned is None:
        return None
    compact = cleaned.replace(" ", "")
    if compact == "Rp0.2/Rm":
        return "Rp0.2 / Rm"
    return cleaned


def _normalize_property_capture_value(value: str | None) -> str | None:
    token = _extract_numeric_token(value)
    if token is None:
        return None
    return token.replace(".", ",")


def _extract_capture_candidates_from_crop(
    crop: Image.Image,
    *,
    click_x: int,
    click_y: int,
    left_offset: int,
    top_offset: int,
    normalizer,
) -> list[dict[str, object]]:
    candidates: list[dict[str, object]] = []
    seen: set[tuple[str, int, int, int, int]] = set()

    for config in ("--psm 11", "--psm 6"):
        try:
            data = pytesseract.image_to_data(crop, lang="eng+ita+deu", config=config, output_type=pytesseract.Output.DICT)
        except (OSError, pytesseract.TesseractNotFoundError):
            continue

        tokens = data.get("text") or []
        block_nums = data.get("block_num") or []
        par_nums = data.get("par_num") or []
        line_nums = data.get("line_num") or []
        lefts = data.get("left") or []
        tops = data.get("top") or []
        widths = data.get("width") or []
        heights = data.get("height") or []

        line_tokens: dict[tuple[int, int, int], list[dict[str, int | str]]] = {}
        for index, raw_token in enumerate(tokens):
            token = _string_or_none(raw_token)
            if token is None:
                continue
            try:
                line_key = (int(block_nums[index]), int(par_nums[index]), int(line_nums[index]))
                x0 = int(lefts[index])
                y0 = int(tops[index])
                width = int(widths[index])
                height = int(heights[index])
            except (TypeError, ValueError, IndexError):
                continue
            if width <= 0 or height <= 0:
                continue
            line_tokens.setdefault(line_key, []).append(
                {
                    "text": token,
                    "x0": x0,
                    "y0": y0,
                    "x1": x0 + width,
                    "y1": y0 + height,
                }
            )

        for items in line_tokens.values():
            ordered = sorted(items, key=lambda item: int(item["x0"]))
            for idx, item in enumerate(ordered):
                raw_text = str(item["text"])
                prefixed_text = raw_text
                if idx > 0:
                    previous = str(ordered[idx - 1]["text"]).replace(" ", "")
                    if previous in {"<", "<=", "≤"}:
                        prefixed_text = f"{previous}{raw_text}"
                normalized_value = normalizer(prefixed_text) or normalizer(raw_text)
                if normalized_value is None:
                    continue

                x0 = left_offset + int(item["x0"])
                y0 = top_offset + int(item["y0"])
                x1 = left_offset + int(item["x1"])
                y1 = top_offset + int(item["y1"])
                key = (normalized_value, x0, y0, x1, y1)
                if key in seen:
                    continue
                seen.add(key)
                center_x = (x0 + x1) // 2
                center_y = (y0 + y1) // 2
                distance = abs(center_x - click_x) + abs(center_y - click_y)
                candidates.append(
                    {
                        "value": normalized_value,
                        "raw_text": prefixed_text,
                        "bbox": f"{x0},{y0},{x1},{y1}",
                        "distance": distance,
                    }
                )

    return candidates


def capture_chemistry_value_from_page(*, page: DocumentPage, payload: ChemistryCaptureRequest) -> ChemistryCaptureResponse:
    image_path = get_document_page_image_path(page)
    if not image_path.exists():
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Document page image not available")

    try:
        with Image.open(image_path) as image:
            width, height = image.size
            click_x = min(max(int(width * payload.x_ratio), 0), max(width - 1, 0))
            click_y = min(max(int(height * payload.y_ratio), 0), max(height - 1, 0))
            half_width = max(140, int(width * 0.08))
            half_height = max(34, int(height * 0.03))
            left = max(0, click_x - half_width)
            top = max(0, click_y - half_height)
            right = min(width, click_x + half_width)
            bottom = min(height, click_y + half_height)
            crop = image.crop((left, top, right, bottom))
    except OSError as exc:
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Unable to read document page image") from exc

    candidates = _extract_capture_candidates_from_crop(
        crop,
        click_x=click_x,
        click_y=click_y,
        left_offset=left,
        top_offset=top,
        normalizer=_normalize_chemistry_capture_value,
    )
    if candidates:
        best = min(candidates, key=lambda item: int(item["distance"]))
        return ChemistryCaptureResponse(
            page_id=page.id,
            page_number=page.numero_pagina,
            value=cast(str | None, best.get("value")),
            raw_text=cast(str | None, best.get("raw_text")),
            bbox=cast(str | None, best.get("bbox")),
        )

    try:
        fallback_text = pytesseract.image_to_string(crop, lang="eng+ita+deu", config="--psm 6")
    except (OSError, pytesseract.TesseractNotFoundError):
        fallback_text = ""
    fallback_value = _normalize_chemistry_capture_value(fallback_text)
    return ChemistryCaptureResponse(
        page_id=page.id,
        page_number=page.numero_pagina,
        value=fallback_value,
        raw_text=_string_or_none(fallback_text),
        bbox=f"{left},{top},{right},{bottom}",
    )


def _ocr_crop_lines(crop: Image.Image) -> list[str]:
    seen: set[str] = set()
    lines: list[str] = []

    grayscale = ImageOps.grayscale(crop)
    autocontrasted = ImageOps.autocontrast(grayscale)
    enlarged = autocontrasted.resize(
        (max(1, autocontrasted.width * 2), max(1, autocontrasted.height * 2)),
        Image.Resampling.LANCZOS,
    )
    thresholded = enlarged.point(lambda value: 255 if value > 180 else 0)

    variants = (
        crop,
        grayscale,
        autocontrasted,
        enlarged,
        thresholded,
    )

    for image_variant in variants:
        for config in ("--psm 6", "--psm 4", "--psm 11"):
            try:
                text = pytesseract.image_to_string(image_variant, lang="eng+ita+deu", config=config)
            except (OSError, pytesseract.TesseractNotFoundError):
                continue
            for raw_line in text.splitlines():
                cleaned = _string_or_none(_normalize_mojibake_numeric_text(raw_line))
                if cleaned is None or cleaned in seen:
                    continue
                seen.add(cleaned)
                lines.append(cleaned)
    return lines


def _serialize_chemistry_capture_values(matches: dict[str, dict[str, str | int]]) -> dict[str, str]:
    serialized: dict[str, str] = {}
    for field_name in CHEMISTRY_CAPTURE_FIELD_ORDER:
        payload = matches.get(field_name)
        if payload is None:
            continue
        final_value = _string_or_none(cast(str | None, payload.get("final"))) or _string_or_none(cast(str | None, payload.get("raw")))
        normalized = _normalize_chemistry_capture_value(final_value)
        if normalized is None:
            continue
        serialized[field_name] = normalized
    return serialized


def _serialize_properties_capture_values(matches: dict[str, dict[str, str | int]]) -> dict[str, str]:
    serialized: dict[str, str] = {}
    for field_name in PROPERTY_CAPTURE_FIELD_ORDER:
        payload = matches.get(field_name)
        if payload is None:
            continue
        final_value = _string_or_none(cast(str | None, payload.get("final"))) or _string_or_none(cast(str | None, payload.get("raw")))
        normalized = _normalize_property_capture_value(final_value)
        if normalized is None:
            continue
        serialized[field_name] = normalized
    return serialized


def capture_chemistry_table_from_page(*, page: DocumentPage, payload: ChemistryTableCaptureRequest) -> ChemistryTableCaptureResponse:
    image_path = get_document_page_image_path(page)
    if not image_path.exists():
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Document page image not available")

    try:
        with Image.open(image_path) as image:
            width, height = image.size
            left_ratio = min(payload.x1_ratio, payload.x2_ratio)
            right_ratio = max(payload.x1_ratio, payload.x2_ratio)
            top_ratio = min(payload.y1_ratio, payload.y2_ratio)
            bottom_ratio = max(payload.y1_ratio, payload.y2_ratio)
            left = max(0, min(int(width * left_ratio), width - 1))
            top = max(0, min(int(height * top_ratio), height - 1))
            right = min(width, max(int(width * right_ratio), left + 1))
            bottom = min(height, max(int(height * bottom_ratio), top + 1))
            crop = image.crop((left, top, right, bottom))
    except OSError as exc:
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Unable to read document page image") from exc

    lines = _ocr_crop_lines(crop)
    supplier_name = None
    if page.document is not None:
        supplier_name = (
            page.document.supplier.ragione_sociale
            if page.document.supplier is not None
            else page.document.nome_file_originale
        )
    template = resolve_supplier_template(supplier_name) if supplier_name else None

    if template is not None and template.supplier_key == "metalba":
        metalba_matches = _parse_metalba_chemistry_from_lines(lines, page.id)
        raw_lines_for_response = lines
        if len(metalba_matches) < 5:
            page_text = _best_page_text(page)
            if page_text:
                page_lines = [line.strip() for line in page_text.splitlines() if line.strip()]
                page_matches = _parse_metalba_chemistry_from_lines(page_lines, page.id)
                if len(page_matches) > len(metalba_matches):
                    metalba_matches = page_matches
                    raw_lines_for_response = page_lines
        if metalba_matches:
            values = _serialize_chemistry_capture_values(metalba_matches)
            return ChemistryTableCaptureResponse(
                page_id=page.id,
                page_number=page.numero_pagina,
                orientation="horizontal",
                bbox=f"{left},{top},{right},{bottom}",
                raw_lines=raw_lines_for_response,
                values=values,
                items=_build_chemistry_overlay_preview_items_for_page(page=page, field_values=values),
            )

    if template is not None and template.supplier_key == "neuman":
        neuman_matches = _parse_neuman_chemistry_from_lines(lines, page.id)
        raw_lines_for_response = lines
        if len(neuman_matches) < 5:
            page_text = _best_page_text(page)
            if page_text:
                page_lines = [line.strip() for line in page_text.splitlines() if line.strip()]
                page_matches = _parse_neuman_chemistry_from_lines(page_lines, page.id)
                if len(page_matches) > len(neuman_matches):
                    neuman_matches = page_matches
                    raw_lines_for_response = page_lines
        if neuman_matches:
            values = _serialize_chemistry_capture_values(neuman_matches)
            return ChemistryTableCaptureResponse(
                page_id=page.id,
                page_number=page.numero_pagina,
                orientation="horizontal",
                bbox=f"{left},{top},{right},{bottom}",
                raw_lines=raw_lines_for_response,
                values=values,
                items=_build_chemistry_overlay_preview_items_for_page(page=page, field_values=values),
            )

    if template is not None and template.supplier_key == "aww":
        aww_matches = _parse_aww_chemistry_from_lines(lines, page.id)
        raw_lines_for_response = lines
        if len(aww_matches) < 5:
            page_text = _best_page_text(page)
            if page_text:
                page_lines = [line.strip() for line in page_text.splitlines() if line.strip()]
                page_matches = _parse_aww_chemistry_from_lines(page_lines, page.id)
                if len(page_matches) > len(aww_matches):
                    aww_matches = page_matches
                    raw_lines_for_response = page_lines
        if aww_matches:
            values = _serialize_chemistry_capture_values(aww_matches)
            return ChemistryTableCaptureResponse(
                page_id=page.id,
                page_number=page.numero_pagina,
                orientation="horizontal",
                bbox=f"{left},{top},{right},{bottom}",
                raw_lines=raw_lines_for_response,
                values=values,
                items=_build_chemistry_overlay_preview_items_for_page(page=page, field_values=values),
            )

    horizontal_matches = _parse_chemistry_from_lines(lines, page.id)
    vertical_matches = _parse_vertical_chemistry_from_lines(lines, page.id)
    horizontal_count = len(horizontal_matches)
    vertical_count = len(vertical_matches)

    if horizontal_count > vertical_count:
        orientation = "horizontal"
        chosen = horizontal_matches
    elif vertical_count > horizontal_count:
        orientation = "vertical"
        chosen = vertical_matches
    else:
        orientation = "unknown" if horizontal_count == 0 else "horizontal"
        chosen = horizontal_matches or vertical_matches

    logger.warning(
        "chemistry_table_capture_debug page_id=%s bbox=%s,%s,%s,%s horizontal=%s vertical=%s orientation=%s raw_lines=%s values=%s",
        page.id,
        left,
        top,
        right,
        bottom,
        horizontal_count,
        vertical_count,
        orientation,
        lines,
        list(_serialize_chemistry_capture_values(chosen).keys()),
    )

    values = _serialize_chemistry_capture_values(chosen)

    return ChemistryTableCaptureResponse(
        page_id=page.id,
        page_number=page.numero_pagina,
        orientation=orientation,
        bbox=f"{left},{top},{right},{bottom}",
        raw_lines=lines,
        values=values,
        items=_build_chemistry_overlay_preview_items_for_page(page=page, field_values=values),
    )


