def capture_properties_table_from_page(*, page: DocumentPage, payload: PropertiesTableCaptureRequest) -> PropertiesTableCaptureResponse:
    image_path = get_document_page_image_path(page)
    if not image_path.exists():
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Document page image not available")

    try:
        with Image.open(image_path) as image:
            width, height = image.size
            left_ratio = min(payload.x1_ratio, payload.x2_ratio)
            right_ratio = max(payload.x1_ratio, payload.x2_ratio)
            top_ratio = min(payload.y1_ratio, payload.y2_ratio)
            bottom_ratio = max(payload.y1_ratio, payload.y2_ratio)
            left = max(0, min(int(width * left_ratio), width - 1))
            top = max(0, min(int(height * top_ratio), height - 1))
            right = min(width, max(int(width * right_ratio), left + 1))
            bottom = min(height, max(int(height * bottom_ratio), top + 1))
            crop = image.crop((left, top, right, bottom))
    except OSError as exc:
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Unable to read document page image") from exc

    lines = _ocr_crop_lines(crop)
    supplier_name = None
    if page.document is not None:
        supplier_name = (
            page.document.supplier.ragione_sociale
            if page.document.supplier is not None
            else page.document.nome_file_originale
        )
    template = resolve_supplier_template(supplier_name) if supplier_name else None

    if template is not None and template.supplier_key == "neuman":
        neuman_matches = _parse_neuman_properties_from_lines(lines, page.id)
        raw_lines_for_response = lines
        if not _has_complete_measured_properties(neuman_matches):
            page_text = _best_page_text(page)
            if page_text:
                page_lines = [line.strip() for line in page_text.splitlines() if line.strip()]
                page_matches = _parse_neuman_properties_from_lines(page_lines, page.id)
                if len(page_matches) > len(neuman_matches):
                    neuman_matches = page_matches
                    raw_lines_for_response = page_lines
        if neuman_matches:
            values = _serialize_properties_capture_values(neuman_matches)
            return PropertiesTableCaptureResponse(
                page_id=page.id,
                page_number=page.numero_pagina,
                orientation="horizontal",
                bbox=f"{left},{top},{right},{bottom}",
                raw_lines=raw_lines_for_response,
                values=values,
                items=_build_properties_overlay_preview_items_for_page(page=page, field_values=values),
            )

    if template is not None and template.supplier_key == "aww":
        aww_matches = _parse_aww_properties_from_lines(lines, page.id)
        raw_lines_for_response = lines
        if not _has_complete_measured_properties(aww_matches):
            page_text = _best_page_text(page)
            if page_text:
                page_lines = [line.strip() for line in page_text.splitlines() if line.strip()]
                page_matches = _parse_aww_properties_from_lines(page_lines, page.id)
                if len(page_matches) > len(aww_matches):
                    aww_matches = page_matches
                    raw_lines_for_response = page_lines
        if aww_matches:
            values = _serialize_properties_capture_values(aww_matches)
            return PropertiesTableCaptureResponse(
                page_id=page.id,
                page_number=page.numero_pagina,
                orientation="horizontal",
                bbox=f"{left},{top},{right},{bottom}",
                raw_lines=raw_lines_for_response,
                values=values,
                items=_build_properties_overlay_preview_items_for_page(page=page, field_values=values),
            )

    horizontal_matches: dict[str, dict[str, str | int]] = {}
    for field_name, payload_match in _parse_properties_from_numeric_cluster(lines, page.id).items():
        normalized_field_name = _normalize_property_field_name(field_name)
        if normalized_field_name is not None:
            horizontal_matches.setdefault(normalized_field_name, payload_match)
    for field_name, payload_match in _parse_properties_from_compact_lines(lines, page.id).items():
        normalized_field_name = _normalize_property_field_name(field_name)
        if normalized_field_name is not None:
            horizontal_matches.setdefault(normalized_field_name, payload_match)
    for field_name, payload_match in _parse_properties_from_spec_lines(lines, page.id).items():
        normalized_field_name = _normalize_property_field_name(field_name)
        if normalized_field_name is not None:
            horizontal_matches.setdefault(normalized_field_name, payload_match)

    vertical_matches = {
        normalized_field_name: payload_match
        for field_name, payload_match in _parse_vertical_properties_from_lines(lines, page.id).items()
        if (normalized_field_name := _normalize_property_field_name(field_name)) is not None
    }
    horizontal_count = len(horizontal_matches)
    vertical_count = len(vertical_matches)

    if horizontal_count > vertical_count:
        orientation = "horizontal"
        chosen = horizontal_matches
    elif vertical_count > horizontal_count:
        orientation = "vertical"
        chosen = vertical_matches
    else:
        orientation = "unknown" if horizontal_count == 0 else "horizontal"
        chosen = horizontal_matches or vertical_matches

    values = _serialize_properties_capture_values(chosen)

    return PropertiesTableCaptureResponse(
        page_id=page.id,
        page_number=page.numero_pagina,
        orientation=orientation,
        bbox=f"{left},{top},{right},{bottom}",
        raw_lines=lines,
        values=values,
        items=_build_properties_overlay_preview_items_for_page(page=page, field_values=values),
    )


def build_chemistry_overlay_preview(
    db: Session,
    *,
    row: AcquisitionRow,
) -> ChemistryOverlayPreviewResponse:
    certificate_document_id = row.document_certificato_id
    if certificate_document_id is None:
        return ChemistryOverlayPreviewResponse(items=[])

    certificate_document = get_document(db, certificate_document_id)
    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)

    field_values: dict[str, str] = {}
    for value in row.values:
        if value.blocco != "chimica":
            continue
        normalized = _normalize_chemistry_capture_value(
            value.valore_finale or value.valore_standardizzato or value.valore_grezzo
        )
        if normalized is None:
            continue
        field_values[value.campo] = normalized

    if not field_values:
        return ChemistryOverlayPreviewResponse(items=[])

    template = resolve_supplier_template(_row_supplier_name(row))
    supplier_key = template.supplier_key if template is not None else None
    if supplier_key == "zalco":
        best_zalco_items: list[ChemistryOverlayPreviewItemResponse] = []
        for page in certificate_document.pages:
            if not page.immagine_pagina_storage_key:
                continue
            zalco_items = _build_zalco_chemistry_overlay_items_from_compact_table(
                page=page,
                field_values=field_values,
                row=row,
            )
            if _count_chemistry_overlay_fields(zalco_items) > _count_chemistry_overlay_fields(best_zalco_items):
                best_zalco_items = zalco_items
        if _count_chemistry_overlay_fields(best_zalco_items) >= min(len(field_values), 6):
            return ChemistryOverlayPreviewResponse(items=best_zalco_items)

    best_match: tuple[DocumentPage, dict[str, object], list[str], int, int] | None = None
    best_score: tuple[int, int, int] = (0, 0, 0)
    for page in certificate_document.pages:
        if not page.immagine_pagina_storage_key:
            continue
        staged_match = _find_best_chemistry_overlay_match(
            page=page,
            field_values=field_values,
            supplier_key=supplier_key,
        )
        if staged_match is None:
            continue
        line_box, matched_fields, image_width, image_height, score = staged_match
        if score > best_score:
            best_score = score
            best_match = (page, line_box, matched_fields, image_width, image_height)

    if best_match is None or best_score[1] < 3:
        if supplier_key == "arconic_hannover":
            for page in certificate_document.pages:
                if not page.immagine_pagina_storage_key:
                    continue
                items = _build_arconic_chemistry_overlay_items_from_table_geometry(
                    page=page,
                    field_values=field_values,
                )
                if items:
                    return ChemistryOverlayPreviewResponse(items=items)
        return ChemistryOverlayPreviewResponse(items=[])

    page, line_box, matched_fields, image_width, image_height = best_match
    if supplier_key == "zalco":
        zalco_items = _build_zalco_chemistry_overlay_items_from_analysis_block(
            page=page,
            field_values=field_values,
            row=row,
        )
        if _count_chemistry_overlay_fields(zalco_items) > len(matched_fields):
            return ChemistryOverlayPreviewResponse(items=zalco_items)
    items = _build_chemistry_overlay_items(
        page=page,
        line_box=line_box,
        field_values=field_values,
        matched_fields=matched_fields,
        image_width=image_width,
        image_height=image_height,
        supplier_key=template.supplier_key if template is not None else None,
    )
    return ChemistryOverlayPreviewResponse(items=items)


def _build_chemistry_overlay_preview_items_for_page(
    *,
    page: DocumentPage,
    field_values: dict[str, str],
    supplier_key: str | None = None,
) -> list[ChemistryOverlayPreviewItemResponse]:
    if not field_values or not page.immagine_pagina_storage_key:
        return []
    staged_match = _find_best_chemistry_overlay_match(
        page=page,
        field_values=field_values,
        supplier_key=supplier_key,
    )
    if staged_match is None:
        if supplier_key == "arconic_hannover":
            return _build_arconic_chemistry_overlay_items_from_table_geometry(
                page=page,
                field_values=field_values,
            )
        return []
    line_box, matched_fields, image_width, image_height, score = staged_match
    if score[1] < 3:
        return []
    return _build_chemistry_overlay_items(
        page=page,
        line_box=line_box,
        field_values=field_values,
        matched_fields=matched_fields,
        image_width=image_width,
        image_height=image_height,
        supplier_key=supplier_key,
    )


def build_properties_overlay_preview(
    db: Session,
    *,
    row: AcquisitionRow,
) -> PropertiesOverlayPreviewResponse:
    certificate_document_id = row.document_certificato_id
    if certificate_document_id is None:
        return PropertiesOverlayPreviewResponse(items=[])

    certificate_document = get_document(db, certificate_document_id)
    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)

    field_values: dict[str, str] = {}
    for value in row.values:
        if value.blocco != "proprieta":
            continue
        normalized = _normalize_property_capture_value(
            value.valore_finale or value.valore_standardizzato or value.valore_grezzo
        )
        field_name = _normalize_property_field_name(value.campo)
        if normalized is None or field_name is None:
            continue
        field_values[field_name] = normalized

    if not field_values:
        return PropertiesOverlayPreviewResponse(items=[])

    template = resolve_supplier_template(_row_supplier_name(row))
    supplier_key = template.supplier_key if template is not None else None
    best_match: tuple[DocumentPage, dict[str, object], list[str], int, int] | None = None
    best_score: tuple[int, int, int] = (0, 0, 0)
    for page in certificate_document.pages:
        if not page.immagine_pagina_storage_key:
            continue
        staged_match = _find_best_properties_overlay_match(page=page, field_values=field_values)
        if staged_match is None:
            continue
        line_box, matched_fields, image_width, image_height, score = staged_match
        if score > best_score:
            best_score = score
            best_match = (page, line_box, matched_fields, image_width, image_height)

    items: list[PropertiesOverlayPreviewItemResponse] = []
    if best_match is not None and best_score[1] >= 2:
        page, line_box, matched_fields, image_width, image_height = best_match
        items = _build_properties_overlay_items(
            page=page,
            line_box=line_box,
            field_values=field_values,
            matched_fields=matched_fields,
            image_width=image_width,
            image_height=image_height,
        )
    if _count_overlay_fields(items) < len(field_values):
        for page in certificate_document.pages:
            if not page.immagine_pagina_storage_key:
                continue
            items = _merge_overlay_preview_items(
                items,
                _build_properties_overlay_items_from_page_words(page=page, field_values=field_values),
            )
            if _count_overlay_fields(items) >= len(field_values):
                break
            items = _merge_overlay_preview_items(
                items,
                _build_properties_overlay_items_from_anchor_line(page=page, field_values=field_values),
            )
            if _count_overlay_fields(items) >= len(field_values):
                break
            items = _merge_overlay_preview_items(
                items,
                _build_properties_overlay_items_from_column_words(page=page, field_values=field_values),
            )
            if _count_overlay_fields(items) >= len(field_values):
                break
            if supplier_key == "arconic_hannover":
                items = _merge_overlay_preview_items(
                    items,
                    _build_arconic_properties_overlay_items_from_table_geometry(page=page, field_values=field_values),
                )
                if _count_overlay_fields(items) >= len(field_values):
                    break
    return PropertiesOverlayPreviewResponse(items=items)


def build_notes_overlay_preview(
    db: Session,
    *,
    row: AcquisitionRow,
) -> NoteOverlayPreviewResponse:
    certificate_document_id = row.document_certificato_id
    if certificate_document_id is None:
        return NoteOverlayPreviewResponse(items=[])

    certificate_document = get_document(db, certificate_document_id)
    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)

    pages_by_id = {page.id: page for page in certificate_document.pages}
    items: list[NoteOverlayPreviewItemResponse] = []
    for value in row.values:
        if value.blocco != "note" or value.document_evidence_id is None:
            continue
        evidence = db.get(DocumentEvidence, value.document_evidence_id)
        if evidence is None or evidence.document_page_id is None:
            continue
        item = _build_note_overlay_item_from_evidence(
            pages=certificate_document.pages,
            field=value.campo,
            evidence=evidence,
            expected_value=value.valore_finale or value.valore_standardizzato or value.valore_grezzo,
        )
        if item is not None:
            items.append(item)

    return NoteOverlayPreviewResponse(items=items)


def build_document_core_overlay_preview(
    db: Session,
    *,
    row: AcquisitionRow,
    source: str,
) -> DocumentCoreOverlayPreviewResponse:
    source_key = (source or "").strip().lower()
    if source_key not in {"ddt", "certificato"}:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid document core overlay source")

    if source_key == "ddt":
        document_id = row.document_ddt_id
        block_name = "ddt"
        supplier_key = _resolve_row_supplier_key(row)
        field_map = {
            "lega": ("lega",),
            "diametro": ("diametro",),
            "cdq": ("cdq", "numero_certificato_ddt"),
            "colata": ("colata",),
            "ddt": ("ddt",),
            "peso": ("peso",),
            "ordine": ("ordine",),
        }
    else:
        document_id = row.document_certificato_id
        block_name = "match"
        supplier_key = _resolve_row_supplier_key(row)
        field_map = {
            "lega_base": ("lega_certificato",),
            "diametro": ("diametro_certificato",),
            "cdq": ("numero_certificato_certificato",),
            "colata": ("colata_certificato",),
            "ddt": ("ddt_certificato",),
            "peso": ("peso_certificato",),
            "ordine": ("ordine_cliente_certificato",),
        }

    if document_id is None:
        return DocumentCoreOverlayPreviewResponse(items=[])

    document = get_document(db, document_id)
    if not document.pages:
        document = _index_document_from_path(db, document)
    document = _ensure_document_page_images(db, document)

    if source_key == "ddt":
        live_matches = reader_detect_ddt_core_matches(document.pages, supplier_key=supplier_key)
    else:
        live_matches = reader_detect_certificate_core_matches(document.pages, supplier_key=supplier_key)

    value_map = {
        value.campo: value
        for value in (
            db.query(ReadValue)
            .filter(
                ReadValue.acquisition_row_id == row.id,
                ReadValue.blocco == block_name,
            )
            .all()
        )
    }

    live_field_items: list[DocumentCoreOverlayPreviewItemResponse] = []
    material_candidate_items: list[DocumentCoreOverlayPreviewItemResponse] = []
    if source_key == "ddt":
        live_field_items.extend(
            _build_ddt_document_core_overlay_items_from_split_candidate(
                db=db,
                row=row,
                document=document,
            )
        )
        if not live_field_items:
            live_field_items.extend(
                _build_ddt_document_core_overlay_items_from_row_window(
                    row=row,
                    document=document,
                )
            )

    for ui_field, candidate_fields in field_map.items():
        if any(item.field == ui_field for item in live_field_items):
            continue
        if source_key == "ddt" and ui_field == "ordine" and live_field_items:
            # In multi-row DDTs, a document-level order match can belong to a
            # different material row. Only row-scoped builders may add it.
            continue
        selected_match: dict[str, object] | None = None
        for candidate_field in candidate_fields:
            candidate_match = cast(dict[str, object] | None, live_matches.get(candidate_field))
            if candidate_match is not None:
                selected_match = candidate_match
                break
        if selected_match is None:
            continue
        page_id = cast(int | None, selected_match.get("page_id"))
        snippet = _string_or_none(cast(str | None, selected_match.get("snippet")))
        if page_id is None or snippet is None:
            continue
        if ui_field == "ordine" and not _document_core_match_snippet_contains_final_value(selected_match, snippet):
            continue
        item = _build_document_core_overlay_item_from_snippet(
            pages=document.pages,
            field=ui_field,
            preferred_page_id=page_id,
            snippet=snippet,
        )
        if item is not None and _document_core_overlay_item_allowed(
            item=item,
            source_key=source_key,
            document=document,
        ):
            if ui_field in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS:
                material_candidate_items.append(item)
                continue
            live_field_items.append(item)

    if not any(item.field == "material_block" for item in live_field_items):
        collapsed_material = _collapse_document_core_material_items(material_candidate_items)
        live_field_items.extend(item for item in collapsed_material if item.field == "material_block")

    if source_key == "certificato" and not any(item.field == "material_block" for item in live_field_items):
        live_field_items.extend(
            _build_certificate_document_core_material_items_from_text_window(
                row=row,
                document=document,
                value_map=value_map,
            )
        )

    if source_key == "certificato" and not any(item.field == "material_block" for item in live_field_items):
        live_field_items.extend(
            _build_certificate_document_core_overlay_items_from_identity_window(
                row=row,
                document=document,
                value_map=value_map,
            )
        )

    anchored_material_items = _build_document_core_material_items_from_anchored_ocr(
        row=row,
        document=document,
        source_key=source_key,
        supplier_key=supplier_key,
        value_map=value_map,
    )
    if anchored_material_items:
        live_field_items = [item for item in live_field_items if item.field != "material_block"]
        live_field_items.extend(anchored_material_items)

    value_window_items = _build_document_core_overlay_items_from_value_ocr_window(
        row=row,
        document=document,
        source_key=source_key,
        value_map=value_map,
    )
    if value_window_items:
        live_field_items = _merge_document_core_overlay_items_prefer_existing(
            live_field_items,
            value_window_items,
            replace_material_block=True,
        )

    items: list[DocumentCoreOverlayPreviewItemResponse] = list(live_field_items)
    seen_fields = {item.field for item in items}
    for ui_field, candidate_fields in field_map.items():
        if ui_field in seen_fields:
            continue
        if ui_field in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS:
            continue
        selected_value: ReadValue | None = None
        for candidate_field in candidate_fields:
            candidate_value = value_map.get(candidate_field)
            if candidate_value is not None and candidate_value.document_evidence_id is not None:
                selected_value = candidate_value
                break
        if selected_value is None or selected_value.document_evidence_id is None:
            continue
        evidence = db.get(DocumentEvidence, selected_value.document_evidence_id)
        if evidence is None or evidence.document_page_id is None:
            continue
        note_item = _build_note_overlay_item_from_evidence(
            pages=document.pages,
            field=ui_field,
            evidence=evidence,
        )
        if note_item is None:
            continue
        items.append(
            DocumentCoreOverlayPreviewItemResponse(
                page_id=note_item.page_id,
                page_number=note_item.page_number,
                field=ui_field,
                bbox=note_item.bbox,
                image_width=note_item.image_width,
                image_height=note_item.image_height,
            )
        )
        seen_fields.add(ui_field)

    for ui_field, candidate_fields in field_map.items():
        if ui_field in seen_fields:
            continue
        if ui_field in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS:
            continue
        selected_text: str | None = None
        for candidate_field in candidate_fields:
            selected_text = _read_value_display_text(value_map.get(candidate_field))
            if selected_text is not None:
                break
        token = _normalize_row_signature_token(selected_text)
        if not token or len(token) < 3:
            continue
        item = _build_document_core_overlay_item_from_snippet(
            pages=document.pages,
            field=ui_field,
            preferred_page_id=None,
            snippet=selected_text or "",
        )
        if item is not None and _document_core_overlay_item_allowed(
            item=item,
            source_key=source_key,
            document=document,
        ):
            items.append(item)
            seen_fields.add(ui_field)

    items = _collapse_document_core_material_items(items)
    return DocumentCoreOverlayPreviewResponse(items=items)


def _merge_document_core_overlay_items_prefer_existing(
    existing: list[DocumentCoreOverlayPreviewItemResponse],
    candidates: list[DocumentCoreOverlayPreviewItemResponse],
    *,
    replace_material_block: bool = False,
) -> list[DocumentCoreOverlayPreviewItemResponse]:
    merged = list(existing)
    if replace_material_block and any(item.field == "material_block" for item in candidates):
        merged = [item for item in merged if item.field != "material_block"]
    seen_fields = {item.field for item in merged}
    for item in candidates:
        if item.field in seen_fields:
            continue
        merged.append(item)
        seen_fields.add(item.field)
    return merged


def _document_core_overlay_item_allowed(
    *,
    item: DocumentCoreOverlayPreviewItemResponse,
    source_key: str,
    document: Document,
) -> bool:
    if source_key != "certificato":
        return True
    bbox = _parse_document_core_bbox(item.bbox)
    if bbox is None:
        return False
    page = next((candidate for candidate in document.pages if candidate.id == item.page_id), None)
    page_height = float(item.image_height or page.altezza or 0) if page is not None else float(item.image_height or 0)
    if page_height <= 0:
        return True
    _, top, _, bottom = bbox
    center_ratio = ((top + bottom) / 2) / page_height
    if item.field in {"material_block", "cdq", "ddt", "ordine"}:
        return center_ratio <= 0.48
    if item.field in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS:
        return center_ratio <= 0.52
    return True


_DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS = {"lega", "lega_base", "diametro", "colata", "peso"}


def _append_material_block_overlay_item(
    *,
    items: list[DocumentCoreOverlayPreviewItemResponse],
    field_names: list[str],
    page_id: int,
    page_number: int,
    bbox: str,
    image_width: int,
    image_height: int,
) -> None:
    material_fields = [field_name for field_name in field_names if field_name in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS]
    if len(set(material_fields)) < 2:
        return
    items.append(
        DocumentCoreOverlayPreviewItemResponse(
            page_id=page_id,
            page_number=page_number,
            field="material_block",
            bbox=bbox,
            image_width=image_width,
            image_height=image_height,
        )
    )


def _collapse_document_core_material_items(
    items: list[DocumentCoreOverlayPreviewItemResponse],
) -> list[DocumentCoreOverlayPreviewItemResponse]:
    if any(item.field == "material_block" for item in items):
        return items

    material_items = [item for item in items if item.field in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS]
    if len({item.field for item in material_items}) < 2:
        return items

    grouped: dict[tuple[int, int, str], list[DocumentCoreOverlayPreviewItemResponse]] = {}
    for item in material_items:
        grouped.setdefault((item.page_id, item.page_number, item.bbox), []).append(item)

    selected_group = max(grouped.values(), key=lambda group: len({item.field for item in group}))
    if len({item.field for item in selected_group}) < 2:
        selected_group = _select_nearby_document_core_material_group(material_items)
    if len({item.field for item in selected_group}) < 2:
        return items

    merged_bbox = _merge_document_core_overlay_bboxes(selected_group)
    if merged_bbox is None:
        return items
    reference = selected_group[0]
    collapsed = [
        DocumentCoreOverlayPreviewItemResponse(
            page_id=reference.page_id,
            page_number=reference.page_number,
            field="material_block",
            bbox=merged_bbox,
            image_width=reference.image_width,
            image_height=reference.image_height,
        )
    ]
    selected_keys = {(item.page_id, item.page_number, item.bbox, item.field) for item in selected_group}
    collapsed.extend(
        item
        for item in items
        if (item.page_id, item.page_number, item.bbox, item.field) not in selected_keys
    )
    return collapsed


def _select_nearby_document_core_material_group(
    material_items: list[DocumentCoreOverlayPreviewItemResponse],
) -> list[DocumentCoreOverlayPreviewItemResponse]:
    best_group: list[DocumentCoreOverlayPreviewItemResponse] = []
    by_page: dict[int, list[DocumentCoreOverlayPreviewItemResponse]] = {}
    for item in material_items:
        by_page.setdefault(item.page_id, []).append(item)

    for page_items in by_page.values():
        parsed: list[tuple[DocumentCoreOverlayPreviewItemResponse, float, float, float, float]] = []
        for item in page_items:
            bbox = _parse_document_core_bbox(item.bbox)
            if bbox is None:
                continue
            parsed.append((item, *bbox))
        if len(parsed) < 2:
            continue
        for anchor, left, top, right, bottom in parsed:
            anchor_center = (top + bottom) / 2
            page_height = max(float(anchor.image_height or 0), 1.0)
            vertical_limit = max(220.0, page_height * 0.07)
            group = [
                item
                for item, _, item_top, _, item_bottom in parsed
                if abs(((item_top + item_bottom) / 2) - anchor_center) <= vertical_limit
            ]
            if len({item.field for item in group}) > len({item.field for item in best_group}):
                best_group = group
    return best_group


def _parse_document_core_bbox(bbox: str | None) -> tuple[float, float, float, float] | None:
    parts = [float(part) for part in str(bbox or "").split(",") if part.strip()]
    if len(parts) != 4:
        return None
    left, top, right, bottom = parts
    if right <= left or bottom <= top:
        return None
    return left, top, right, bottom


def _merge_document_core_overlay_bboxes(items: list[DocumentCoreOverlayPreviewItemResponse]) -> str | None:
    parsed = [_parse_document_core_bbox(item.bbox) for item in items]
    boxes = [box for box in parsed if box is not None]
    if not boxes:
        return None
    left = min(box[0] for box in boxes)
    top = min(box[1] for box in boxes)
    right = max(box[2] for box in boxes)
    bottom = max(box[3] for box in boxes)
    return f"{int(left)},{int(top)},{int(right)},{int(bottom)}"


def _read_value_display_text(value: ReadValue | None) -> str | None:
    if value is None:
        return None
    return (
        _string_or_none(value.valore_finale)
        or _string_or_none(value.valore_standardizzato)
        or _string_or_none(value.valore_grezzo)
    )


def _document_core_match_snippet_contains_final_value(
    selected_match: dict[str, object],
    snippet: str,
) -> bool:
    final_value = _string_or_none(cast(str | None, selected_match.get("final")))
    if final_value is None:
        final_value = _string_or_none(cast(str | None, selected_match.get("standardized")))
    if final_value is None:
        return True
    token = _normalize_row_signature_token(final_value)
    if not token or len(token) < 3:
        return True
    return token in _normalize_row_signature_token(snippet)


def _build_document_core_overlay_items_from_value_ocr_window(
    *,
    row: AcquisitionRow,
    document: Document,
    source_key: str,
    value_map: dict[str, ReadValue],
) -> list[DocumentCoreOverlayPreviewItemResponse]:
    if source_key == "certificato":
        field_values = {
            "lega_base": _read_value_display_text(value_map.get("lega_certificato")) or row.lega_base,
            "diametro": _read_value_display_text(value_map.get("diametro_certificato")) or row.diametro,
            "cdq": _read_value_display_text(value_map.get("numero_certificato_certificato")) or row.cdq,
            "colata": _read_value_display_text(value_map.get("colata_certificato")) or row.colata,
            "ddt": _read_value_display_text(value_map.get("ddt_certificato")) or row.ddt,
            "peso": _read_value_display_text(value_map.get("peso_certificato")) or row.peso,
            "ordine": _read_value_display_text(value_map.get("ordine_cliente_certificato")) or row.ordine,
        }
        field_weights = {
            "cdq": 80,
            "colata": 75,
            "ddt": 65,
            "ordine": 60,
            "peso": 55,
            "diametro": 45,
            "lega_base": 40,
        }
        minimum_score = 120
        max_window_size = 8
    else:
        field_values = {
            "lega": row.lega_base,
            "diametro": row.diametro,
            "cdq": row.cdq,
            "colata": row.colata,
            "ddt": row.ddt,
            "peso": row.peso,
            "ordine": row.ordine,
        }
        field_weights = {
            "ddt": 80,
            "cdq": 75,
            "colata": 75,
            "peso": 65,
            "ordine": 60,
            "diametro": 45,
            "lega": 40,
        }
        minimum_score = 115
        max_window_size = 6

    selected = _select_best_document_core_value_ocr_window(
        pages=document.pages,
        field_values=field_values,
        field_weights=field_weights,
        minimum_score=minimum_score,
        max_window_size=max_window_size,
    )
    if selected is None:
        return []

    page, window, matched_fields, image_width, image_height = selected
    material_window = _select_best_document_core_material_subwindow(window=window, field_values=field_values) or window
    field_bboxes = {}
    for field_name in matched_fields:
        lookup_window = material_window if field_name in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS else window
        field_bboxes[field_name] = _document_core_field_bbox_from_ocr_window(
            window=lookup_window,
            field_name=field_name,
            value=field_values.get(field_name),
        )
    fallback_bbox = _document_core_bbox_from_line_boxes(window)
    if fallback_bbox is None:
        return []

    items: list[DocumentCoreOverlayPreviewItemResponse] = []
    material_fields = [field_name for field_name in matched_fields if field_name in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS]
    material_bboxes = [
        bbox
        for field_name, bbox in field_bboxes.items()
        if field_name in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS and bbox is not None
    ]
    if len(set(material_fields)) >= 2:
        material_bbox = _merge_document_core_overlay_bbox_values(material_bboxes) or fallback_bbox
        items.append(
            DocumentCoreOverlayPreviewItemResponse(
                page_id=page.id,
                page_number=page.numero_pagina,
                field="material_block",
                bbox=material_bbox,
                image_width=image_width,
                image_height=image_height,
            )
        )

    for field_name in ("cdq", "ddt", "ordine"):
        if field_name not in matched_fields:
            continue
        items.append(
            DocumentCoreOverlayPreviewItemResponse(
                page_id=page.id,
                page_number=page.numero_pagina,
                field=field_name,
                bbox=field_bboxes.get(field_name) or fallback_bbox,
                image_width=image_width,
                image_height=image_height,
            )
        )
    return items


def _select_best_document_core_value_ocr_window(
    *,
    pages: list[DocumentPage],
    field_values: dict[str, str | None],
    field_weights: dict[str, int],
    minimum_score: int,
    max_window_size: int,
) -> tuple[DocumentPage, list[dict[str, object]], list[str], int, int] | None:
    field_tokens: list[tuple[str, str, int]] = []
    for field_name, value in field_values.items():
        token = _normalize_row_signature_token(value)
        if not token:
            continue
        if field_name == "diametro" and len(token) < 2:
            continue
        field_tokens.append((field_name, token, field_weights.get(field_name, 30)))
    if not field_tokens:
        return None

    best: tuple[DocumentPage, list[dict[str, object]], list[str], int, int, int] | None = None
    for page in pages:
        if not page.immagine_pagina_storage_key:
            continue
        line_boxes, image_width, image_height = _extract_ocr_line_boxes(page, psms=(4, 6))
        line_boxes = sorted(
            line_boxes,
            key=lambda box: (int(box.get("y0") or 0), int(box.get("x0") or 0)),
        )
        max_window = min(max_window_size, len(line_boxes))
        for window_size in range(1, max_window + 1):
            for start in range(0, len(line_boxes) - window_size + 1):
                window = line_boxes[start : start + window_size]
                window_lines = [
                    _normalize_row_signature_token(_document_core_line_box_text(line_box))
                    for line_box in window
                ]
                window_key = " ".join(window_lines)
                if not window_key:
                    continue

                matched_fields: list[str] = []
                score = 0
                for field_name, token, weight in field_tokens:
                    if _document_core_window_contains_token(
                        field_name=field_name,
                        window_lines=window_lines,
                        window_key=window_key,
                        token=token,
                    ):
                        matched_fields.append(field_name)
                        score += weight

                unique_fields = list(dict.fromkeys(matched_fields))
                if len(unique_fields) < 2:
                    continue
                score += 20 * len(unique_fields)
                if {"cdq", "colata"} <= set(unique_fields):
                    score += 35
                if {"peso", "diametro"} <= set(unique_fields):
                    score += 25
                if {"colata", "peso"} <= set(unique_fields):
                    score += 25
                score -= _document_core_material_negative_score(window_key)
                if score < minimum_score:
                    continue
                if best is None or score > best[5]:
                    best = (page, window, unique_fields, int(image_width or 0), int(image_height or 0), score)

    if best is None:
        return None
    page, window, fields, image_width, image_height, _score = best
    return page, window, fields, image_width, image_height


def _select_best_document_core_material_subwindow(
    *,
    window: list[dict[str, object]],
    field_values: dict[str, str | None],
) -> list[dict[str, object]] | None:
    material_fields = [field_name for field_name in field_values if field_name in _DOCUMENT_CORE_MATERIAL_BLOCK_FIELDS]
    best_line: dict[str, object] | None = None
    best_score = 0
    for line_box in window:
        line_key = _normalize_row_signature_token(_document_core_line_box_text(line_box))
        if not line_key:
            continue
        score = 0
        for field_name in material_fields:
            token = _normalize_row_signature_token(field_values.get(field_name))
            if not token:
                continue
            if _document_core_window_contains_token(
                field_name=field_name,
                window_lines=[line_key],
                window_key=line_key,
                token=token,
            ):
                score += 1
        # Colata e peso aiutano a scegliere la riga materiale giusta nei DDT multiriga.
        for field_name in ("colata", "peso", "cdq"):
            token = _normalize_row_signature_token(field_values.get(field_name))
            if token and _document_core_window_contains_token(
                field_name=field_name,
                window_lines=[line_key],
                window_key=line_key,
                token=token,
            ):
                score += 1
        if score > best_score:
            best_line = line_box
            best_score = score
    if best_line is None or best_score < 2:
        return None
    return [best_line]


def _document_core_field_bbox_from_ocr_window(
    *,
    window: list[dict[str, object]],
    field_name: str,
    value: str | None,
) -> str | None:
    token = _normalize_row_signature_token(value)
    if not token:
        return None
    matching_words: list[dict[str, object]] = []
    for line_box in window:
        line_key = _normalize_row_signature_token(_document_core_line_box_text(line_box))
        if not _document_core_window_contains_token(
            field_name=field_name,
            window_lines=[line_key],
            window_key=line_key,
            token=token,
        ):
            continue
        for word in cast(list[dict[str, object]], line_box.get("words") or []):
            word_key = _normalize_row_signature_token(str(word.get("normalized") or word.get("text") or ""))
            if not word_key:
                continue
            if field_name == "diametro":
                if word_key in token or token in word_key or word_key in {"DIA", "DIAM", "DIAMETER", "MM", "RD"}:
                    matching_words.append(word)
            elif word_key in token or token in word_key:
                matching_words.append(word)
        if matching_words:
            break
        line_bbox = _document_core_bbox_from_line_boxes([line_box])
        if line_bbox is not None:
            return line_bbox
    if not matching_words:
        return None
    return _document_core_bbox_from_words(matching_words)


def _document_core_bbox_from_words(words: list[dict[str, object]]) -> str | None:
    if not words:
        return None
    left = min(int(word.get("left") or 0) for word in words)
    top = min(int(word.get("top") or 0) for word in words)
    right = max(int(word.get("left") or 0) + int(word.get("width") or 0) for word in words)
    bottom = max(int(word.get("top") or 0) + int(word.get("height") or 0) for word in words)
    if right <= left or bottom <= top:
        return None
    return f"{left},{top},{right},{bottom}"


def _merge_document_core_overlay_bbox_values(bbox_values: list[str | None]) -> str | None:
    boxes = [_parse_document_core_bbox(bbox) for bbox in bbox_values if bbox]
    boxes = [box for box in boxes if box is not None]
    if not boxes:
        return None
    left = min(box[0] for box in boxes)
    top = min(box[1] for box in boxes)
    right = max(box[2] for box in boxes)
    bottom = max(box[3] for box in boxes)
    return f"{int(left)},{int(top)},{int(right)},{int(bottom)}"


def _build_document_core_material_items_from_anchored_ocr(
    *,
    row: AcquisitionRow,
    document: Document,
    source_key: str,
    supplier_key: str | None,
    value_map: dict[str, ReadValue],
) -> list[DocumentCoreOverlayPreviewItemResponse]:
    if source_key == "certificato":
        field_values = {
            "lega_base": _read_value_display_text(value_map.get("lega_certificato")) or row.lega_base,
            "diametro": _read_value_display_text(value_map.get("diametro_certificato")) or row.diametro,
            "colata": _read_value_display_text(value_map.get("colata_certificato")) or row.colata,
            "peso": _read_value_display_text(value_map.get("peso_certificato")) or row.peso,
        }
    else:
        field_values = {
            "lega_base": row.lega_base,
            "diametro": row.diametro,
            "colata": row.colata,
            "peso": row.peso,
        }

    minimum_fields = 1 if source_key == "certificato" and supplier_key == "aww" else 2
    selected = _select_best_document_core_material_ocr_window(
        pages=document.pages,
        field_values=field_values,
        minimum_fields=minimum_fields,
    )
    if selected is None:
        return []

    page, bbox, image_width, image_height = selected
    return [
        DocumentCoreOverlayPreviewItemResponse(
            page_id=page.id,
            page_number=page.numero_pagina,
            field="material_block",
            bbox=bbox,
            image_width=image_width,
            image_height=image_height,
        )
    ]


def _select_best_document_core_material_ocr_window(
    *,
    pages: list[DocumentPage],
    field_values: dict[str, str | None],
    minimum_fields: int,
) -> tuple[DocumentPage, str, int, int] | None:
    field_tokens: list[tuple[str, str, int]] = []
    for field_name, value, weight in (
        ("lega_base", field_values.get("lega_base"), 70),
        ("diametro", field_values.get("diametro"), 70),
        ("colata", field_values.get("colata"), 55),
        ("peso", field_values.get("peso"), 45),
    ):
        token = _normalize_row_signature_token(value)
        if not token:
            continue
        if field_name == "diametro" and len(token) < 2:
            continue
        field_tokens.append((field_name, token, weight))

    if not field_tokens:
        return None

    best: tuple[DocumentPage, str, int, int, int] | None = None
    for page in pages:
        if not page.immagine_pagina_storage_key:
            continue
        image_path = get_document_page_image_path(page)
        with Image.open(image_path) as image:
            image_width, image_height = image.size
        line_boxes, _, _ = _extract_ocr_line_boxes(page, psms=(4, 6))
        line_boxes = sorted(
            line_boxes,
            key=lambda box: (int(box.get("y0") or 0), int(box.get("x0") or 0)),
        )
        max_window = min(8, len(line_boxes))
        for window_size in range(1, max_window + 1):
            for start in range(0, len(line_boxes) - window_size + 1):
                window = line_boxes[start : start + window_size]
                normalized_lines = [_normalize_row_signature_token(_document_core_line_box_text(line)) for line in window]
                window_key = " ".join(normalized_lines)
                if not window_key:
                    continue
                anchor_score = _document_core_material_anchor_score(window_key)
                if anchor_score <= 0:
                    continue
                matched_fields: list[str] = []
                score = anchor_score
                for field_name, token, weight in field_tokens:
                    if _document_core_window_contains_token(
                        field_name=field_name,
                        window_lines=normalized_lines,
                        window_key=window_key,
                        token=token,
                    ):
                        matched_fields.append(field_name)
                        score += weight
                unique_fields = list(dict.fromkeys(matched_fields))
                if len(unique_fields) < minimum_fields:
                    continue
                if minimum_fields == 1 and len(unique_fields) == 1 and anchor_score < 55:
                    continue
                score += 25 * len(unique_fields)
                score -= _document_core_material_negative_score(window_key)
                if score < 90:
                    continue
                bbox = _document_core_material_bbox_from_window(window=window, field_tokens=field_tokens)
                if bbox is None:
                    bbox = _document_core_bbox_from_line_boxes(window)
                if bbox is None:
                    continue
                candidate = (page, bbox, image_width, image_height, score)
                if best is None or score > best[4]:
                    best = candidate

    if best is None:
        return None
    page, bbox, image_width, image_height, _ = best
    return page, bbox, image_width, image_height


def _document_core_line_box_text(line_box: dict[str, object]) -> str:
    words = cast(list[dict[str, object]], line_box.get("words") or [])
    return " ".join(str(word.get("text") or "") for word in words)


def _document_core_material_anchor_score(window_key: str) -> int:
    anchors = {
        "ESTRUSO": 35,
        "BARRA": 35,
        "TONDA": 25,
        "DIAM": 35,
        "DIAMETER": 35,
        "ABMESSUNG": 35,
        "ALLOY": 35,
        "LEGA": 35,
        "LEGIERUNG": 30,
        "WERKSTOFF": 45,
        "MATERIAL": 35,
        "PHYSSTATE": 25,
        "ZUSTAND": 35,
        "SECTIONDESC": 25,
        "DESCRIZIONEPROFILO": 25,
    }
    return min(sum(weight for token, weight in anchors.items() if token in window_key), 140)


def _document_core_material_negative_score(window_key: str) -> int:
    negatives = (
        "HEADQUARTERS",
        "SEDE",
        "PHONE",
        "FAX",
        "PEC",
        "EMAIL",
        "WWW",
        "ADDRESS",
        "CAPITALE",
        "PIVA",
        "ITALIA",
        "ITALY",
        "METALBA",
        "SOCIETA",
        "STRADA",
        "TEL",
        "TELEFONO",
        "VIA",
        "DESTINAZIONEMERCE",
        "SPETTLE",
        "VETTORI",
        "FIRMA",
    )
    return 80 * sum(1 for token in negatives if token in window_key)


def _document_core_material_bbox_from_window(
    *,
    window: list[dict[str, object]],
    field_tokens: list[tuple[str, str, int]],
) -> str | None:
    relevant_words: list[dict[str, object]] = []
    for line_box in window:
        words = cast(list[dict[str, object]], line_box.get("words") or [])
        line_key = _normalize_row_signature_token(_document_core_line_box_text(line_box))
        for word in words:
            word_text = str(word.get("text") or "")
            word_key = _normalize_row_signature_token(word_text)
            if not word_key:
                continue
            if _document_core_word_is_material_anchor(word_key):
                relevant_words.append(word)
                continue
            for field_name, token, _ in field_tokens:
                if field_name == "diametro" and _document_core_diameter_token_matches(line=line_key, token=token):
                    if word_key in token or token in word_key or word_key in {"DIAM", "DIAMETER", "MM"}:
                        relevant_words.append(word)
                        break
                elif len(word_key) >= 2 and (word_key in token or token in word_key):
                    relevant_words.append(word)
                    break

    if not relevant_words:
        return None
    left = min(int(word.get("left") or 0) for word in relevant_words)
    top = min(int(word.get("top") or 0) for word in relevant_words)
    right = max(int(word.get("left") or 0) + int(word.get("width") or 0) for word in relevant_words)
    bottom = max(int(word.get("top") or 0) + int(word.get("height") or 0) for word in relevant_words)
    if right <= left or bottom <= top:
        return None
    pad_x = 18
    pad_y = 12
    return f"{max(left - pad_x, 0)},{max(top - pad_y, 0)},{right + pad_x},{bottom + pad_y}"


def _document_core_word_is_material_anchor(word_key: str) -> bool:
    anchors = {
        "ESTRUSO",
        "BARRA",
        "TONDA",
        "DIAM",
        "DIAMETER",
        "ABMESSUNG",
        "ALLOY",
        "LEGA",
        "LEGIERUNG",
        "WERKSTOFF",
        "MATERIAL",
        "PHYSSTATE",
        "ZUSTAND",
        "SECTION",
        "DESC",
        "DESCRIZIONE",
        "PROFILO",
    }
    return word_key in anchors


def _document_core_bbox_from_line_boxes(line_boxes: list[dict[str, object]]) -> str | None:
    if not line_boxes:
        return None
    left = min(int(box.get("x0") or 0) for box in line_boxes)
    top = min(int(box.get("y0") or 0) for box in line_boxes)
    right = max(int(box.get("x1") or 0) for box in line_boxes)
    bottom = max(int(box.get("y1") or 0) for box in line_boxes)
    if right <= left or bottom <= top:
        return None
    return f"{left},{top},{right},{bottom}"


