def _extract_grupa_kety_ddt_row_groups_with_vision(
    db: Session,
    *,
    ddt_document: Document,
    openai_api_key: str,
) -> list[ReaderRowSplitCandidateResponse]:
    if not ddt_document.pages:
        ddt_document = _index_document_from_path(db, ddt_document)
    ddt_document = _ensure_document_page_images(db, ddt_document)

    image_pages = [page for page in ddt_document.pages if page.immagine_pagina_storage_key]
    if not image_pages:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="DDT has no image pages available for AI")

    crop_definitions = _build_grupa_kety_ddt_group_crops(image_pages)
    if not crop_definitions:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Unable to prepare Grupa Kety DDT pages for AI")

    local_matches = reader_detect_ddt_core_matches(ddt_document.pages, supplier_key="grupa_kety")
    fallback_ddt = _string_or_none(cast(dict[str, object], local_matches.get("ddt") or {}).get("final"))
    ddt_number_raw, raw_rows, ai_document_payload_raw = _extract_grupa_kety_ddt_row_groups_from_openai(
        crop_definitions,
        openai_api_key=openai_api_key,
    )
    return _sanitize_grupa_kety_ai_row_groups(
        ddt_number_raw=_prefer_grupa_kety_ddt_number(fallback_ddt, ddt_number_raw),
        raw_rows=raw_rows,
        ai_document_payload_raw=ai_document_payload_raw,
    )


def _prefer_grupa_kety_ddt_number(local_ddt: str | None, ai_ddt: str | None) -> str | None:
    return _string_or_none(ai_ddt) or _string_or_none(local_ddt)


def _build_grupa_kety_ddt_group_crops(
    pages: list[DocumentPage],
) -> dict[str, dict[str, str | int]]:
    crops: dict[str, dict[str, str | int]] = {}
    image_pages = [page for page in sorted(pages, key=lambda item: item.numero_pagina) if page.immagine_pagina_storage_key]
    if not image_pages:
        return crops

    for index, page in enumerate(image_pages):
        image_path = get_document_page_image_path(page)
        with Image.open(image_path) as image:
            masked_page = _build_grupa_kety_masked_page(image)
            storage_key = _save_ddt_crop(page, masked_page, f"grupa_kety_masked_page_{page.numero_pagina}")
            width, height = masked_page.size
            role_specs = [("row_groups_page", "row_groups_page")]
            if index == 0:
                role_specs.insert(0, ("header_page", "header_page"))
            else:
                role_specs.insert(0, ("continuation_page", "continuation_page"))
            for suffix, role in role_specs:
                label = f"page{page.numero_pagina}_{suffix}"
                crops[label] = {
                    "label": label,
                    "role": role,
                    "page_id": page.id,
                    "page_number": page.numero_pagina,
                    "storage_key": storage_key,
                    "bbox": f"0,0,{width},{height}",
                }
    return crops


def _extract_grupa_kety_ddt_row_groups_from_openai(
    crops: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> tuple[str | None, list[dict[str, object]], str]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi queste immagini di un Delivery Note / Packing Slip Grupa Kety e ricostruisci le righe acquisition. "
                "Regola utente: una riga acquisition coincide con un certificato/lotto logico, non con ogni sotto-riga di spedizione. "
                "Se lo stesso certificato/lotto compare su piu sotto-righe, aggregale in una sola riga e somma i Net weight della stessa coppia certificato+Heat. "
                "Esempio: 10033541_22815 e 10033541_22816 con Heat 25E-7871 diventano una sola riga Cdq 10033541/25, Colata 25E-7871, Peso totale somma. "
                "Delivery Note o Packing Slip e' il DDT. Se vedi anche Shipment ID, non usarlo come DDT. "
                "ddt_number_raw deve essere il valore accanto a Delivery Note/Packing Slip, non il valore accanto a Shipment ID. "
                "PO Number / Customer Order Number / Order date e' ordine. "
                "Il Cdq viene dal numero certificato visibile, oppure dal root lotto piu anno della Heat: 10033539 + 25E-7870 => 10033539/25. "
                "La Colata e' Batch/Melt o Heat della stessa riga, es. 25E-7870 o H6245. "
                "Diametro e lega/stato vengono dalla descrizione materiale: Extruded Round Bar 44.00, Alloy 7150, Temper F. "
                "Non usare dati autista, timbri o firme. Non usare nome file. Non fare match con certificati. "
                "Usa solo testo/segni realmente visibili; se un campo non e chiaro, restituisci null. "
                "Restituisci solo JSON con questa struttura: "
                "{\"ddt_number_raw\":\"string|null\",\"rows\":[{\"row_index\":1,"
                "\"certificate_number_raw\":\"string|null\",\"lot_batch_raw\":\"string|null\",\"heat_raw\":\"string|null\","
                "\"alloy_raw\":\"string|null\",\"temper_raw\":\"string|null\",\"diameter_raw\":\"string|null\","
                "\"customer_part_raw\":\"string|null\",\"customer_order_raw\":\"string|null\","
                "\"net_weight_raw\":\"string|null\",\"source_crops\":[\"label\"]}]}"
            ),
        }
    ]
    for crop_label, crop in crops.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": f"Crop label: {crop_label}; role: {crop.get('role') or 'unknown'}; page_number: {crop.get('page_number') or 'unknown'}",
            }
        )
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Grupa Kety DDT row-group AI request failed") from exc

    return (*_parse_openai_json_payload_for_grupa_kety_row_groups(response.output_text), response.output_text)


def _parse_openai_json_payload_for_grupa_kety_row_groups(payload: str) -> tuple[str | None, list[dict[str, object]]]:
    text = payload.strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text)
        text = re.sub(r"\s*```$", "", text)
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, re.DOTALL)
        if not match:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Grupa Kety DDT row-group AI")
        try:
            data = json.loads(match.group(0))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Grupa Kety DDT row-group AI") from exc
    if not isinstance(data, dict):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Unexpected Grupa Kety DDT row-group AI payload")
    rows_payload = data.get("rows")
    if not isinstance(rows_payload, list):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Missing rows in Grupa Kety DDT row-group AI payload")

    rows: list[dict[str, object]] = []
    for index, raw_row in enumerate(rows_payload, start=1):
        if not isinstance(raw_row, dict):
            continue
        source_crops = raw_row.get("source_crops")
        normalized_sources = [
            item
            for item in (_string_or_none(source_crop) for source_crop in (source_crops if isinstance(source_crops, list) else []))
            if item is not None
        ]
        try:
            row_index = int(raw_row.get("row_index")) if raw_row.get("row_index") is not None else index
        except (TypeError, ValueError):
            row_index = index
        rows.append(
            {
                "row_index": row_index,
                "certificate_number_raw": _string_or_none(raw_row.get("certificate_number_raw")),
                "lot_batch_raw": _string_or_none(raw_row.get("lot_batch_raw")),
                "heat_raw": _string_or_none(raw_row.get("heat_raw")),
                "alloy_raw": _string_or_none(raw_row.get("alloy_raw")),
                "temper_raw": _string_or_none(raw_row.get("temper_raw")),
                "diameter_raw": _string_or_none(raw_row.get("diameter_raw")),
                "customer_part_raw": _string_or_none(raw_row.get("customer_part_raw")),
                "customer_order_raw": _string_or_none(raw_row.get("customer_order_raw")),
                "net_weight_raw": _string_or_none(raw_row.get("net_weight_raw")),
                "source_crops": normalized_sources,
            }
        )
    return _string_or_none(data.get("ddt_number_raw")), rows


def _sanitize_grupa_kety_ai_row_groups(
    *,
    ddt_number_raw: str | None,
    raw_rows: list[dict[str, object]],
    ai_document_payload_raw: str | None = None,
) -> list[ReaderRowSplitCandidateResponse]:
    normalized_ddt = _normalize_grupa_kety_ddt_number(ddt_number_raw)
    grouped: dict[tuple[str | None, str | None], dict[str, object]] = {}

    for raw_row in raw_rows:
        lot_root = _normalize_grupa_kety_lot_root(
            _string_or_none(raw_row.get("certificate_number_raw")) or _string_or_none(raw_row.get("lot_batch_raw"))
        )
        heat = _normalize_grupa_kety_heat(_string_or_none(raw_row.get("heat_raw")))
        key = (lot_root, heat)
        if key == (None, None):
            key = (_string_or_none(raw_row.get("certificate_number_raw")), _string_or_none(raw_row.get("lot_batch_raw")))
        bucket = grouped.setdefault(
            key,
            {
                "rows": [],
                "weight_total": 0.0,
                "has_weight": False,
                "source_crops": [],
            },
        )
        cast(list[dict[str, object]], bucket["rows"]).append(raw_row)
        weight = _parse_weight_float(_string_or_none(raw_row.get("net_weight_raw")))
        if weight is not None:
            bucket["weight_total"] = float(bucket["weight_total"]) + weight
            bucket["has_weight"] = True
        for source in cast(list[str], raw_row.get("source_crops") or []):
            if source not in cast(list[str], bucket["source_crops"]):
                cast(list[str], bucket["source_crops"]).append(source)

    candidates: list[ReaderRowSplitCandidateResponse] = []
    for index, bucket in enumerate(grouped.values(), start=1):
        rows = cast(list[dict[str, object]], bucket["rows"])
        first = rows[0]
        certificate_raw = _first_string(*(row.get("certificate_number_raw") for row in rows))
        lot_raw = _first_string(*(row.get("lot_batch_raw") for row in rows))
        heat_raw = _first_string(*(row.get("heat_raw") for row in rows))
        heat = _normalize_grupa_kety_heat(heat_raw)
        lot_root = _normalize_grupa_kety_lot_root(certificate_raw or lot_raw)
        cdq = _normalize_grupa_kety_certificate_number(certificate_raw, lot_root=lot_root, heat=heat)
        alloy = _normalize_grupa_kety_alloy(
            _first_string(*(row.get("alloy_raw") for row in rows)),
            _first_string(*(row.get("temper_raw") for row in rows)),
        )
        diameter = _normalize_grupa_kety_diameter(_first_string(*(row.get("diameter_raw") for row in rows)))
        weight = _format_weight_float(float(bucket["weight_total"])) if bucket.get("has_weight") else _normalize_weight_value(_string_or_none(first.get("net_weight_raw")))
        raw_payload = {
            "rows": rows,
            "aggregated_weight": weight,
            "ddt_number_raw": ddt_number_raw,
        }
        candidate = ReaderRowSplitCandidateResponse(
            candidate_index=index,
            supplier_key="grupa_kety",
            ddt_number=normalized_ddt,
            cdq=cdq,
            lot_batch_no=lot_root,
            colata=heat,
            heat_no=heat,
            lega=alloy,
            diametro=diameter,
            peso_netto=weight,
            customer_order_no=_normalize_grupa_kety_order(_first_string(*(row.get("customer_order_raw") for row in rows))),
            article_code=_string_or_none(_first_string(*(row.get("customer_part_raw") for row in rows))),
            snippets=cast(list[str], bucket["source_crops"])[:6],
            ai_row_payload_raw=json.dumps(raw_payload, ensure_ascii=False),
            ai_document_payload_raw=ai_document_payload_raw,
        )
        if any(getattr(candidate, field_name) is not None for field_name in ("cdq", "colata", "lot_batch_no", "peso_netto", "ddt_number")):
            candidates.append(candidate)
    return candidates


def _apply_grupa_kety_ai_candidate_to_row(
    db: Session,
    *,
    row: AcquisitionRow,
    ai_candidate: ReaderRowSplitCandidateResponse,
    actor_id: int,
    document_id: int,
) -> bool:
    raw_payload: dict[str, object] = {}
    if ai_candidate.ai_row_payload_raw:
        _create_ai_payload_evidence(
            db=db,
            row_id=row.id,
            document_id=document_id,
            document_page_id=row.ddt_document.pages[0].id if row.ddt_document and row.ddt_document.pages else None,
            blocco="ddt",
            payload_text=ai_candidate.ai_row_payload_raw,
            actor_id=actor_id,
            confidence=0.72,
        )
        try:
            parsed_payload = json.loads(ai_candidate.ai_row_payload_raw)
            if isinstance(parsed_payload, dict):
                raw_payload = parsed_payload
        except json.JSONDecodeError:
            raw_payload = {}

    field_values = {
        "ddt": ai_candidate.ddt_number,
        "numero_certificato_ddt": ai_candidate.cdq,
        "cdq": ai_candidate.cdq,
        "colata": ai_candidate.colata,
        "lot_batch_no": ai_candidate.lot_batch_no,
        "heat_no": ai_candidate.heat_no,
        "ordine": ai_candidate.customer_order_no,
        "customer_order_no": ai_candidate.customer_order_no,
        "article_code": ai_candidate.article_code,
        "lega": ai_candidate.lega,
        "diametro": ai_candidate.diametro,
        "peso": ai_candidate.peso_netto,
        "delivery_note_raw": ai_candidate.ddt_number,
        "ai_row_payload": json.dumps(raw_payload, ensure_ascii=False) if raw_payload else None,
    }
    changed_fields = 0
    for field_name, field_value in field_values.items():
        normalized_value = _string_or_none(field_value)
        if normalized_value is None:
            continue
        if _has_stable_value_protected_from_ai(row, "ddt", field_name):
            continue
        _upsert_read_value_model(
            db=db,
            acquisition_row_id=row.id,
            blocco="ddt",
            campo=field_name,
            valore_grezzo=normalized_value,
            valore_standardizzato=normalized_value,
            valore_finale=normalized_value,
            stato="proposto",
            document_evidence_id=None,
            metodo_lettura="chatgpt",
            fonte_documentale="ddt",
            confidenza=0.72,
            actor_id=actor_id,
        )
        changed_fields += 1
    if changed_fields == 0:
        return False
    _sync_row_from_ddt_values(db, row)
    _sync_ddt_values_from_row_fields(db, row, actor_id=actor_id)
    _sync_row_statuses(db, row)
    db.add(row)
    _record_history_event(
        db=db,
        acquisition_row_id=row.id,
        blocco="ddt",
        azione="gruppi_riga_ai_applicati",
        user_id=actor_id,
        nota_breve=str(changed_fields),
    )
    return True


def _get_grupa_kety_certificate_ai_payload(
    db: Session,
    *,
    certificate_document: Document,
    openai_api_key: str,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> dict[str, object]:
    cached = certificate_ai_cache.get(certificate_document.id) if certificate_ai_cache is not None else None
    if cached is not None:
        return cached

    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)
    if not _document_has_image_pages(certificate_document):
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    crops = _build_certificate_safe_crops(certificate_document.pages, supplier_key="grupa_kety")
    page_images = _select_aluminium_bozen_certificate_document_images(crops)
    if not page_images:
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    raw_payload = _extract_grupa_kety_certificate_payload_from_openai(
        page_images,
        openai_api_key=openai_api_key,
    )
    payload = _normalize_grupa_kety_certificate_ai_payload(page_images, raw_payload)
    if certificate_ai_cache is not None:
        certificate_ai_cache[certificate_document.id] = payload
    return payload


def _extract_grupa_kety_certificate_payload_from_openai(
    page_images: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> dict[str, object]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi questo certificato Grupa Kety. Usa solo testo visibile: non inventare, non usare nome file. "
                "Campi core: certificate_number e' il numero in alto, es. 10033539/25 o 750027617/23. "
                "packing_slip_raw e' Dowod wysylkowy / Packing Slip / Lot, es. 12594 / 10033539: il primo numero e' DDT, il secondo e' root lotto. "
                "order_no_raw e' Order date / Nr kontraktu klienta se presente, es. 154. "
                "customer_part_raw e' Order No o Item/dimensions quando utile, es. PPO 44MM 7150/F L:5000. "
                "alloy_raw viene da Alloy grade, es. EN AW-7150; temper_raw da Temper; heat_raw da Heat; kg_raw da kg; pieces_raw da Pieces. "
                "diameter_raw viene da Dimensions or drawing o testo articolo, es. 44.00 mm. "
                "Chimica: estrai solo la riga misurata del lotto/Heat, non i limiti min/max. "
                "Proprieta: estrai le righe misurate Sample No. Txxx, non i limiti minimi; se piu righe, restituiscile tutte. "
                "Note: cerca U.S./AMS ultrasonic class, RoHS, radioactive/free. "
                "Restituisci solo JSON con questa struttura: "
                "{\"core\":{\"certificate_number\":\"string|null\",\"packing_slip_raw\":\"string|null\",\"order_no_raw\":\"string|null\","
                "\"customer_part_raw\":\"string|null\",\"alloy_raw\":\"string|null\",\"temper_raw\":\"string|null\",\"heat_raw\":\"string|null\","
                "\"kg_raw\":\"string|null\",\"pieces_raw\":\"string|null\",\"diameter_raw\":\"string|null\"},"
                "\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\",\"Mn\":\"string|null\",\"Mg\":\"string|null\","
                "\"Cr\":\"string|null\",\"Ni\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\",\"Cd\":\"string|null\",\"Hg\":\"string|null\","
                "\"Pb\":\"string|null\",\"V\":\"string|null\",\"Bi\":\"string|null\",\"Sn\":\"string|null\",\"Zr\":\"string|null\",\"Be\":\"string|null\","
                "\"Zr+Ti\":\"string|null\",\"Mn+Cr\":\"string|null\",\"Bi+Pb\":\"string|null\"},"
                "\"mechanical_raw\":{\"measured_rows\":[{\"Rm\":\"string|null\",\"Rp0.2\":\"string|null\",\"A%\":\"string|null\","
                "\"HB\":\"string|null\",\"IACS%\":\"string|null\",\"Rp0.2/Rm\":\"string|null\"}]},"
                "\"notes_raw\":{\"nota_us_control_class_a_raw\":\"string|null\",\"nota_us_control_class_b_raw\":\"string|null\","
                "\"nota_rohs_raw\":\"string|null\",\"nota_radioactive_free_raw\":\"string|null\"}}"
            ),
        }
    ]
    for image_label, crop in page_images.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append({"type": "input_text", "text": f"Image label: {image_label}; page_number: {crop.get('page_number') or 'unknown'}"})
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Grupa Kety certificate AI extraction request failed") from exc

    return _parse_openai_json_payload_for_certificate_bundle(response.output_text)


def _normalize_grupa_kety_certificate_ai_payload(
    page_images: dict[str, dict[str, str | int]],
    raw_payload: dict[str, object],
) -> dict[str, object]:
    first_page_crop = next(iter(page_images.values()), None)
    first_page_id = int(first_page_crop.get("page_id")) if first_page_crop and first_page_crop.get("page_id") else 0
    last_page_crop = next(reversed(page_images.values()), None) if page_images else None
    last_page_id = int(last_page_crop.get("page_id")) if last_page_crop and last_page_crop.get("page_id") else first_page_id
    source_crop = next(iter(page_images.keys()), None)

    core_payload = cast(dict[str, object], raw_payload.get("core") or {})
    core_fields = _sanitize_grupa_kety_vision_certificate_fields(core_payload, source_crop)

    chemistry_payload = cast(dict[str, object], raw_payload.get("chemistry_raw") or {})
    chemistry_matches = _normalize_vision_numeric_matches(
        {
            field_name: {
                "value": _string_or_none(chemistry_payload.get(field_name)),
                "evidence": _string_or_none(chemistry_payload.get(field_name)),
                "source_crop": source_crop,
            }
            for field_name in ("Si", "Fe", "Cu", "Mn", "Mg", "Cr", "Ni", "Zn", "Ti", "Cd", "Hg", "Pb", "V", "Bi", "Sn", "Zr", "Be", "Zr+Ti", "Mn+Cr", "Bi+Pb")
        },
        {
            source_crop or "page1": {
                "page_id": first_page_id,
                "page_number": first_page_crop.get("page_number") if first_page_crop else 1,
            }
        },
    )
    measured_rows = cast(dict[str, object], raw_payload.get("mechanical_raw") or {}).get("measured_rows") or []
    property_matches = _normalize_aluminium_bozen_measured_rows_payload(
        measured_rows if isinstance(measured_rows, list) else [],
        page_id=last_page_id,
    )
    notes_payload = cast(dict[str, object], raw_payload.get("notes_raw") or {})
    note_matches = _normalize_vision_note_matches(
        _build_vision_note_extracted_payload(notes_payload, next(reversed(page_images.keys()), None) if page_images else None),
        {
            next(reversed(page_images.keys()), "page1"): {
                "page_id": last_page_id,
                "page_number": last_page_crop.get("page_number") if last_page_crop else (first_page_crop.get("page_number") if first_page_crop else 1),
            }
        },
    )

    packing_slip = _string_or_none(core_payload.get("packing_slip_raw"))
    certificate_number = _normalize_grupa_kety_certificate_number(_string_or_none(core_payload.get("certificate_number")))
    lot_root = _normalize_grupa_kety_lot_root(certificate_number or packing_slip)
    heat = _normalize_grupa_kety_heat(_string_or_none(core_payload.get("heat_raw")))
    return {
        "match_values": {
            field_name: _string_or_none(field_payload.get("value"))
            for field_name, field_payload in core_fields.items()
        },
        "supplier_fields": {
            "delivery_note_no": _normalize_grupa_kety_ddt_number(packing_slip),
            "lot_number": lot_root,
            "order_no": _normalize_grupa_kety_order(_string_or_none(core_payload.get("order_no_raw"))),
            "heat": heat,
            "customer_part_number": _string_or_none(core_payload.get("customer_part_raw")),
            "certificate_number": certificate_number,
        },
        "core_fields": core_fields,
        "chemistry": chemistry_matches,
        "properties": property_matches,
        "notes": note_matches,
        "debug_raw_output": json.dumps(raw_payload, ensure_ascii=False),
    }


def _sanitize_grupa_kety_vision_certificate_fields(
    core_payload: dict[str, object],
    source_crop: str | None,
) -> dict[str, dict[str, str | None]]:
    certificate_number = _normalize_grupa_kety_certificate_number(_string_or_none(core_payload.get("certificate_number")))
    packing_slip = _string_or_none(core_payload.get("packing_slip_raw"))
    ddt_number = _normalize_grupa_kety_ddt_number(packing_slip)
    order_no = _normalize_grupa_kety_order(_string_or_none(core_payload.get("order_no_raw")))
    heat = _normalize_grupa_kety_heat(_string_or_none(core_payload.get("heat_raw")))
    alloy = _normalize_grupa_kety_alloy(_string_or_none(core_payload.get("alloy_raw")), _string_or_none(core_payload.get("temper_raw")))
    diameter = _normalize_grupa_kety_diameter(_string_or_none(core_payload.get("diameter_raw")) or _string_or_none(core_payload.get("customer_part_raw")))
    weight = _normalize_grupa_kety_weight(_string_or_none(core_payload.get("kg_raw")))
    customer_part = _string_or_none(core_payload.get("customer_part_raw"))

    def _payload(value: str | None, evidence: str | None = None) -> dict[str, str | None]:
        return {"value": value, "evidence": evidence or value, "source_crop": source_crop}

    return {
        "numero_certificato_certificato": _payload(certificate_number),
        "ordine_cliente_certificato": _payload(order_no),
        "articolo_certificato": _payload(customer_part),
        "lega_certificato": _payload(alloy),
        "descrizione_profilo_cliente_certificato": _payload(customer_part),
        "colata_certificato": _payload(heat),
        "peso_certificato": _payload(weight),
        "diametro_certificato": _payload(diameter),
        "ddt_certificato": _payload(ddt_number),
    }


def _first_string(*values: object) -> str | None:
    for value in values:
        cleaned = _string_or_none(value)
        if cleaned is not None:
            return cleaned
    return None


def _normalize_grupa_kety_ddt_number(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    for pattern in (r"\b(?:DELIVERY\s+NOTE|PACKING\s+SLIP)\s*:?\s*(\d{4,9})\b", r"\b(\d{4,9})\s*/\s*\d{7,9}\b", r"\b(\d{4,9})\b"):
        match = re.search(pattern, cleaned, re.IGNORECASE)
        if match is not None:
            return match.group(1)
    return None


def _normalize_grupa_kety_lot_root(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(\d{7,9})(?:\s*/\s*\d{2}|[_-][A-Z0-9]+|[_-]\d+)?\b", cleaned.upper())
    return match.group(1) if match is not None else None


def _normalize_grupa_kety_certificate_number(
    value: str | None,
    *,
    lot_root: str | None = None,
    heat: str | None = None,
) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is not None:
        match = re.search(r"\b(\d{7,9})\s*/\s*(\d{2})\b", cleaned)
        if match is not None:
            return f"{match.group(1)}/{match.group(2)}"
    root = lot_root or _normalize_grupa_kety_lot_root(cleaned)
    if root is None:
        return None
    heat_year = None
    heat_value = _string_or_none(heat)
    if heat_value is not None:
        year_match = re.match(r"(\d{2})[A-Z]-", heat_value.upper())
        if year_match is not None:
            heat_year = year_match.group(1)
    return f"{root}/{heat_year}" if heat_year else root


def _normalize_grupa_kety_heat(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    text = cleaned.upper().replace(" ", "")
    for pattern in (r"\b(\d{2}[A-Z]-\d{3,5})\b", r"\b([A-Z]\d{4,6})\b", r"\b([A-Z]\d{2,}-\d{2,})\b"):
        match = re.search(pattern, text)
        if match is not None:
            return match.group(1)
    return None


def _normalize_grupa_kety_order(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(\d{1,6})\b", cleaned)
    return match.group(1) if match is not None else None


def _normalize_grupa_kety_alloy(alloy_raw: str | None, temper_raw: str | None = None) -> str | None:
    cleaned = " ".join(item for item in (_string_or_none(alloy_raw), _string_or_none(temper_raw)) if item)
    if not cleaned:
        return None
    text = cleaned.upper().replace("EN AW-", " ").replace("EN AW", " ").replace("ALLOY", " ")
    alloy_match = re.search(r"\b(20\d{2}A?|26\d{2}A?|5\d{3}A?|6\d{3}A?|7\d{3}A?)\b", text)
    if alloy_match is None:
        return None
    temper_match = re.search(r"\b(T\d+[A-Z0-9]*|F|H\d+)\b", text)
    return f"{alloy_match.group(1)} {temper_match.group(1)}".strip() if temper_match else alloy_match.group(1)


def _normalize_grupa_kety_diameter(value: str | None) -> str | None:
    return _normalize_diameter_value(value)


def _normalize_grupa_kety_weight(value: str | None) -> str | None:
    parsed = _parse_weight_float(value)
    return _format_weight_float(parsed) if parsed is not None else None


def _parse_weight_float(value: str | None) -> float | None:
    cleaned = _string_or_none(value)
    if cleaned is not None:
        cleaned = re.sub(r"(?<=\d)\s+(?=\d)", "", cleaned)
    normalized = _normalize_weight_value(cleaned)
    if normalized is None:
        return None
    try:
        return float(normalized)
    except ValueError:
        return None


def _format_weight_float(value: float) -> str:
    return str(int(value)) if value.is_integer() else f"{value:.3f}".rstrip("0").rstrip(".")


def _extract_arconic_hannover_ddt_row_groups_with_vision(
    db: Session,
    *,
    ddt_document: Document,
    openai_api_key: str,
) -> list[ReaderRowSplitCandidateResponse]:
    if not ddt_document.pages:
        ddt_document = _index_document_from_path(db, ddt_document)
    ddt_document = _ensure_document_page_images(db, ddt_document)

    image_pages = [page for page in ddt_document.pages if page.immagine_pagina_storage_key]
    if not image_pages:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="DDT has no image pages available for AI")

    crop_definitions = _build_arconic_hannover_ddt_group_crops(image_pages)
    if not crop_definitions:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Unable to prepare Arconic DDT pages for AI",
        )

    local_matches = reader_detect_ddt_core_matches(ddt_document.pages, supplier_key="arconic_hannover")
    fallback_ddt = _string_or_none(cast(dict[str, object], local_matches.get("ddt") or {}).get("final"))

    ddt_number_raw, raw_rows, ai_document_payload_raw = _extract_arconic_hannover_ddt_row_groups_from_openai(
        crop_definitions,
        openai_api_key=openai_api_key,
    )
    return _sanitize_arconic_hannover_ai_row_groups(
        ddt_number_raw=ddt_number_raw or fallback_ddt,
        raw_rows=raw_rows,
        ai_document_payload_raw=ai_document_payload_raw,
    )


def _build_arconic_hannover_ddt_group_crops(
    pages: list[DocumentPage],
) -> dict[str, dict[str, str | int]]:
    crops: dict[str, dict[str, str | int]] = {}
    image_pages = [page for page in sorted(pages, key=lambda item: item.numero_pagina) if page.immagine_pagina_storage_key]
    if not image_pages:
        return crops

    for index, page in enumerate(image_pages):
        image_path = get_document_page_image_path(page)
        with Image.open(image_path) as image:
            masked_page = _build_arconic_hannover_masked_page(image)
            storage_key = _save_ddt_crop(page, masked_page, f"arconic_masked_page_{page.numero_pagina}")
            width, height = masked_page.size
            role_specs = [("row_groups_page", "row_groups_page")]
            if index == 0:
                role_specs.insert(0, ("header_page", "header_page"))
            else:
                role_specs.insert(0, ("continuation_page", "continuation_page"))
            for suffix, role in role_specs:
                label = f"page{page.numero_pagina}_{suffix}"
                crops[label] = {
                    "label": label,
                    "role": role,
                    "page_id": page.id,
                    "page_number": page.numero_pagina,
                    "storage_key": storage_key,
                    "bbox": f"0,0,{width},{height}",
                }
    return crops


def _extract_arconic_hannover_ddt_row_groups_from_openai(
    crops: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> tuple[str | None, list[dict[str, object]], str]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi queste immagini di un Delivery Note Arconic Hannover e ricostruisci tutte le righe logiche materiale. "
                "Una riga acquisition corrisponde alla riga materiale del DDT, non al singolo package. "
                "Non usare annotazioni a penna. Non usare nome file. Non fare match con certificati. "
                "Per distinguere le righe usa insieme: line_no, Customer Item number, Customer Item Description, "
                "Arconic Item number, Die / Dimension, CAST Number, package IDs, peso di riga. "
                "La colata e il CAST Number tecnico, di solito un token che inizia con C; i package IDs sono supporto e non sostituiscono la colata. "
                "Se la descrizione contiene ROUND BAR, ROD, RD087,00, DIA 87 o simili, estraila in customer_item_description_raw e die_dimension_raw. "
                "alloy_raw deve venire dalla descrizione materiale o customer item description se visibile, ad esempio 6082 F. "
                "diameter_raw deve venire da Die / Dimension o descrizione, ad esempio RD087,00 significa diametro 87. "
                "ddt_number_raw e' il Delivery Note. sales_order_raw e' Sales Order Number. customer_po_raw e' Customer Purchase Order. "
                "line_no_raw e' il numero riga tipo 2.1. arconic_item_number_raw e' il codice BG.... customer_item_number_raw e' il codice cliente tipo A.... "
                "net_weight_raw e' il peso netto della riga materiale/line total della stessa riga, non totale documento. "
                "Restituisci solo JSON con questa struttura: "
                "{\"ddt_number_raw\":\"string|null\",\"rows\":[{\"row_index\":1,"
                "\"sales_order_raw\":\"string|null\",\"customer_po_raw\":\"string|null\",\"line_no_raw\":\"string|null\","
                "\"customer_item_number_raw\":\"string|null\",\"customer_item_description_raw\":\"string|null\","
                "\"arconic_item_number_raw\":\"string|null\",\"die_dimension_raw\":\"string|null\","
                "\"alloy_raw\":\"string|null\",\"diameter_raw\":\"string|null\",\"cast_number_raw\":\"string|null\","
                "\"package_ids_raw\":\"string|null\",\"net_weight_raw\":\"string|null\",\"source_crops\":[\"label\"]}]}"
            ),
        }
    ]

    for crop_label, crop in crops.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": (
                    f"Crop label: {crop_label}; "
                    f"role: {crop.get('role') or 'unknown'}; "
                    f"page_number: {crop.get('page_number') or 'unknown'}"
                ),
            }
        )
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Arconic DDT row-group AI request failed") from exc

    return (*_parse_openai_json_payload_for_arconic_row_groups(response.output_text), response.output_text)


def _parse_openai_json_payload_for_arconic_row_groups(payload: str) -> tuple[str | None, list[dict[str, object]]]:
    text = payload.strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text)
        text = re.sub(r"\s*```$", "", text)
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, re.DOTALL)
        if not match:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Arconic DDT row-group AI")
        try:
            data = json.loads(match.group(0))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Arconic DDT row-group AI") from exc

    if not isinstance(data, dict):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Unexpected Arconic DDT row-group AI payload")
    rows_payload = data.get("rows")
    if not isinstance(rows_payload, list):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Missing rows in Arconic DDT row-group AI payload")

    normalized_rows: list[dict[str, object]] = []
    for index, raw_row in enumerate(rows_payload, start=1):
        if not isinstance(raw_row, dict):
            continue
        source_crops = raw_row.get("source_crops")
        normalized_sources = [
            item
            for item in (_string_or_none(source_crop) for source_crop in (source_crops if isinstance(source_crops, list) else []))
            if item is not None
        ]
        raw_row_index = raw_row.get("row_index")
        try:
            normalized_row_index = int(raw_row_index) if raw_row_index is not None else index
        except (TypeError, ValueError):
            normalized_row_index = index
        normalized_rows.append(
            {
                "row_index": normalized_row_index,
                "sales_order_raw": _string_or_none(raw_row.get("sales_order_raw")),
                "customer_po_raw": _string_or_none(raw_row.get("customer_po_raw")),
                "line_no_raw": _string_or_none(raw_row.get("line_no_raw")),
                "customer_item_number_raw": _string_or_none(raw_row.get("customer_item_number_raw")),
                "customer_item_description_raw": _string_or_none(raw_row.get("customer_item_description_raw")),
                "arconic_item_number_raw": _string_or_none(raw_row.get("arconic_item_number_raw")),
                "die_dimension_raw": _string_or_none(raw_row.get("die_dimension_raw")),
                "alloy_raw": _string_or_none(raw_row.get("alloy_raw")),
                "diameter_raw": _string_or_none(raw_row.get("diameter_raw")),
                "cast_number_raw": _string_or_none(raw_row.get("cast_number_raw")),
                "package_ids_raw": _string_or_none(raw_row.get("package_ids_raw")),
                "net_weight_raw": _string_or_none(raw_row.get("net_weight_raw")),
                "source_crops": normalized_sources,
            }
        )
    return _string_or_none(data.get("ddt_number_raw")), normalized_rows


def _sanitize_arconic_hannover_ai_row_groups(
    *,
    ddt_number_raw: str | None,
    raw_rows: list[dict[str, object]],
    ai_document_payload_raw: str | None = None,
) -> list[ReaderRowSplitCandidateResponse]:
    sanitized_rows: list[ReaderRowSplitCandidateResponse] = []
    normalized_ddt = _normalize_arconic_ddt_number(ddt_number_raw)

    for index, raw_row in enumerate(raw_rows, start=1):
        sales_order_raw = _string_or_none(raw_row.get("sales_order_raw"))
        customer_po_raw = _string_or_none(raw_row.get("customer_po_raw"))
        line_no_raw = _string_or_none(raw_row.get("line_no_raw"))
        customer_item_number_raw = _string_or_none(raw_row.get("customer_item_number_raw"))
        customer_item_description_raw = _string_or_none(raw_row.get("customer_item_description_raw"))
        arconic_item_number_raw = _string_or_none(raw_row.get("arconic_item_number_raw"))
        die_dimension_raw = _string_or_none(raw_row.get("die_dimension_raw"))
        alloy_raw = _string_or_none(raw_row.get("alloy_raw"))
        diameter_raw = _string_or_none(raw_row.get("diameter_raw"))
        cast_number_raw = _string_or_none(raw_row.get("cast_number_raw"))
        package_ids_raw = _string_or_none(raw_row.get("package_ids_raw"))
        net_weight_raw = _string_or_none(raw_row.get("net_weight_raw"))
        source_crops = cast(list[str], raw_row.get("source_crops") or [])
        normalized_alloy = (
            _normalize_arconic_alloy_from_text(alloy_raw)
            or _normalize_arconic_alloy_from_text(customer_item_description_raw)
            or _normalize_arconic_alloy_from_text(die_dimension_raw)
        )
        normalized_diameter = (
            _normalize_arconic_diameter_from_text(diameter_raw)
            or _normalize_arconic_diameter_from_text(die_dimension_raw)
            or _normalize_arconic_diameter_from_text(customer_item_description_raw)
        )

        candidate = ReaderRowSplitCandidateResponse(
            candidate_index=index,
            supplier_key="arconic_hannover",
            ddt_number=normalized_ddt,
            customer_order_no=_normalize_arconic_customer_po(customer_po_raw),
            supplier_order_no=_normalize_arconic_sales_order(sales_order_raw),
            product_code=_normalize_arconic_line_no(line_no_raw),
            customer_code=_normalize_arconic_customer_item_number(customer_item_number_raw),
            article_code=_normalize_arconic_item_number(arconic_item_number_raw),
            lega=normalized_alloy,
            diametro=normalized_diameter,
            colata=_normalize_arconic_cast_number(cast_number_raw),
            lot_batch_no=_normalize_arconic_package_ids(package_ids_raw),
            peso_netto=_normalize_value_for_field("ddt", "peso", net_weight_raw),
            snippets=source_crops[:6],
            ai_row_payload_raw=json.dumps(raw_row, ensure_ascii=False),
            ai_document_payload_raw=ai_document_payload_raw,
        )

        if any(
            getattr(candidate, field_name) is not None
            for field_name in (
                "ddt_number",
                "customer_order_no",
                "supplier_order_no",
                "customer_code",
                "article_code",
                "product_code",
                "lega",
                "diametro",
                "colata",
                "peso_netto",
            )
        ):
            sanitized_rows.append(candidate)

    return sanitized_rows


def _get_arconic_hannover_certificate_ai_payload(
    db: Session,
    *,
    certificate_document: Document,
    openai_api_key: str,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> dict[str, object]:
    cached = certificate_ai_cache.get(certificate_document.id) if certificate_ai_cache is not None else None
    if cached is not None:
        return cached

    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)
    if not _document_has_image_pages(certificate_document):
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    crops = _build_certificate_safe_crops(certificate_document.pages, supplier_key="arconic_hannover")
    page_images = _select_aluminium_bozen_certificate_document_images(crops)
    if not page_images:
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    raw_payload = _extract_arconic_hannover_certificate_payload_from_openai(
        page_images,
        openai_api_key=openai_api_key,
    )
    payload = _normalize_arconic_hannover_certificate_ai_payload(page_images, raw_payload)
    if certificate_ai_cache is not None:
        certificate_ai_cache[certificate_document.id] = payload
    return payload


def _extract_arconic_hannover_certificate_payload_from_openai(
    page_images: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> dict[str, object]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi questo certificato Arconic Hannover. Usa solo testo visibile: non inventare e non usare il nome file. "
                "Campi core: cert_number e' Cert Number EEP..., sales_order_number, customer_po, delivery_note_no, line_no, "
                "customer_item_number, arconic_item_number, item_description_raw, alloy_raw, diameter_raw, cast_job_number, net_weight_raw. "
                "La colata e' il CAST/Heat che inizia con C; il job/package dopo slash e' supporto. "
                "Chimica: leggi solo la riga Composition Results in %, escludendo limiti. "
                "Proprieta: se ci sono piu righe misurate, restituiscile in measured_rows; il sistema usera il minimo per campo. "
                "Non inserire valori SPECLIMITS/limiti come misurati. "
                "Restituisci solo JSON con questa struttura: "
                "{\"core\":{\"cert_number\":\"string|null\",\"sales_order_number\":\"string|null\",\"customer_po\":\"string|null\","
                "\"delivery_note_no\":\"string|null\",\"line_no\":\"string|null\",\"customer_item_number\":\"string|null\","
                "\"arconic_item_number\":\"string|null\",\"item_description_raw\":\"string|null\",\"alloy_raw\":\"string|null\","
                "\"diameter_raw\":\"string|null\",\"cast_job_number\":\"string|null\",\"net_weight_raw\":\"string|null\"},"
                "\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\",\"Mn\":\"string|null\",\"Mg\":\"string|null\","
                "\"Cr\":\"string|null\",\"Ni\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\",\"Cd\":\"string|null\",\"Hg\":\"string|null\","
                "\"Pb\":\"string|null\",\"V\":\"string|null\",\"Bi\":\"string|null\",\"Sn\":\"string|null\",\"Zr\":\"string|null\",\"Be\":\"string|null\","
                "\"Zr+Ti\":\"string|null\",\"Mn+Cr\":\"string|null\",\"Bi+Pb\":\"string|null\"},"
                "\"mechanical_raw\":{\"measured_rows\":[{\"Rm\":\"string|null\",\"Rp0.2\":\"string|null\",\"A%\":\"string|null\","
                "\"HB\":\"string|null\",\"IACS%\":\"string|null\",\"Rp0.2/Rm\":\"string|null\"}]},"
                "\"notes_raw\":{\"nota_us_control_class_a_raw\":\"string|null\",\"nota_us_control_class_b_raw\":\"string|null\","
                "\"nota_rohs_raw\":\"string|null\",\"nota_radioactive_free_raw\":\"string|null\"}}"
            ),
        }
    ]

    for image_label, crop in page_images.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append({"type": "input_text", "text": f"Image label: {image_label}; page_number: {crop.get('page_number') or 'unknown'}"})
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Arconic certificate AI extraction request failed") from exc

    return _parse_openai_json_payload_for_certificate_bundle(response.output_text)


def _normalize_arconic_hannover_certificate_ai_payload(
    page_images: dict[str, dict[str, str | int]],
    raw_payload: dict[str, object],
) -> dict[str, object]:
    first_page_crop = next(iter(page_images.values()), None)
    first_page_id = int(first_page_crop.get("page_id")) if first_page_crop and first_page_crop.get("page_id") else 0
    last_page_crop = next(reversed(page_images.values()), None) if page_images else None
    last_page_id = int(last_page_crop.get("page_id")) if last_page_crop and last_page_crop.get("page_id") else first_page_id
    source_crop = next(iter(page_images.keys()), None)

    core_payload = cast(dict[str, object], raw_payload.get("core") or {})
    core_fields = _sanitize_arconic_hannover_vision_certificate_fields(core_payload, source_crop)

    chemistry_payload = cast(dict[str, object], raw_payload.get("chemistry_raw") or {})
    chemistry_matches = _normalize_vision_numeric_matches(
        {
            field_name: {
                "value": _string_or_none(chemistry_payload.get(field_name)),
                "evidence": _string_or_none(chemistry_payload.get(field_name)),
                "source_crop": source_crop,
            }
            for field_name in ("Si", "Fe", "Cu", "Mn", "Mg", "Cr", "Ni", "Zn", "Ti", "Cd", "Hg", "Pb", "V", "Bi", "Sn", "Zr", "Be", "Zr+Ti", "Mn+Cr", "Bi+Pb")
        },
        {
            source_crop or "page1": {
                "page_id": first_page_id,
                "page_number": first_page_crop.get("page_number") if first_page_crop else 1,
            }
        },
    )

    measured_rows = cast(dict[str, object], raw_payload.get("mechanical_raw") or {}).get("measured_rows") or []
    property_matches = _normalize_aluminium_bozen_measured_rows_payload(
        measured_rows if isinstance(measured_rows, list) else [],
        page_id=last_page_id,
    )

    notes_payload = cast(dict[str, object], raw_payload.get("notes_raw") or {})
    note_matches = _normalize_vision_note_matches(
        _build_vision_note_extracted_payload(notes_payload, next(reversed(page_images.keys()), None) if page_images else None),
        {
            next(reversed(page_images.keys()), "page1"): {
                "page_id": last_page_id,
                "page_number": last_page_crop.get("page_number") if last_page_crop else (first_page_crop.get("page_number") if first_page_crop else 1),
            }
        },
    )

    cast_job_raw = _string_or_none(core_payload.get("cast_job_number"))
    cast_number = _normalize_arconic_cast_number(cast_job_raw)
    job_number = _normalize_arconic_package_ids(cast_job_raw)
    return {
        "match_values": {
            field_name: _string_or_none(field_payload.get("value"))
            for field_name, field_payload in core_fields.items()
        },
        "supplier_fields": {
            "delivery_note_no": _normalize_arconic_ddt_number(_string_or_none(core_payload.get("delivery_note_no"))),
            "sales_order_number": _normalize_arconic_sales_order(_string_or_none(core_payload.get("sales_order_number"))),
            "customer_po": _normalize_arconic_customer_po(_string_or_none(core_payload.get("customer_po"))),
            "line_no": _normalize_arconic_line_no(_string_or_none(core_payload.get("line_no"))),
            "customer_item_number": _normalize_arconic_customer_item_number(_string_or_none(core_payload.get("customer_item_number"))),
            "arconic_item_number": _normalize_arconic_item_number(_string_or_none(core_payload.get("arconic_item_number"))),
            "cast_job_number": cast_job_raw,
            "cast_number": cast_number,
            "job_number": job_number,
            "alloy": _normalize_arconic_alloy_from_text(_string_or_none(core_payload.get("alloy_raw")) or _string_or_none(core_payload.get("item_description_raw"))),
            "diameter": _normalize_arconic_diameter_from_text(_string_or_none(core_payload.get("diameter_raw")) or _string_or_none(core_payload.get("item_description_raw"))),
        },
        "core_fields": core_fields,
        "chemistry": chemistry_matches,
        "properties": property_matches,
        "notes": note_matches,
        "debug_raw_output": json.dumps(raw_payload, ensure_ascii=False),
    }


def _sanitize_arconic_hannover_vision_certificate_fields(
    core_payload: dict[str, object],
    source_crop: str | None,
) -> dict[str, dict[str, str | None]]:
    cert_number = _normalize_arconic_certificate_number(_string_or_none(core_payload.get("cert_number")))
    cast_job_raw = _string_or_none(core_payload.get("cast_job_number"))
    job_number = _normalize_arconic_package_ids(cast_job_raw)
    certificate_cdq = _format_arconic_certificate_cdq(cert_number, job_number)
    customer_po = _normalize_arconic_customer_po(_string_or_none(core_payload.get("customer_po")))
    arconic_item = _normalize_arconic_item_number(_string_or_none(core_payload.get("arconic_item_number")))
    customer_item = _normalize_arconic_customer_item_number(_string_or_none(core_payload.get("customer_item_number")))
    description = _string_or_none(core_payload.get("item_description_raw"))
    alloy = _normalize_arconic_alloy_from_text(_string_or_none(core_payload.get("alloy_raw")) or description)
    diameter = _normalize_arconic_diameter_from_text(_string_or_none(core_payload.get("diameter_raw")) or description)
    cast_number = _normalize_arconic_cast_number(cast_job_raw)
    weight = _normalize_value_for_field("match", "peso_certificato", _string_or_none(core_payload.get("net_weight_raw")))
    ddt_number = _normalize_arconic_ddt_number(_string_or_none(core_payload.get("delivery_note_no")))

    def _payload(value: str | None, evidence: str | None = None) -> dict[str, str | None]:
        return {"value": value, "evidence": evidence or value, "source_crop": source_crop}

    return {
        "numero_certificato_certificato": _payload(certificate_cdq),
        "ordine_cliente_certificato": _payload(customer_po),
        "articolo_certificato": _payload(arconic_item),
        "codice_cliente_certificato": _payload(customer_item),
        "descrizione_profilo_cliente_certificato": _payload(description),
        "lega_certificato": _payload(alloy),
        "diametro_certificato": _payload(diameter),
        "colata_certificato": _payload(cast_number),
        "peso_certificato": _payload(weight),
        "ddt_certificato": _payload(ddt_number),
    }


def _normalize_arconic_ddt_number(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\b\d{6,9}\b")


def _normalize_arconic_certificate_number(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\bEEP[0-9A-Z-]+\b")


def _format_arconic_certificate_cdq(cert_number: str | None, package_ids: str | None) -> str | None:
    cert = _string_or_none(cert_number)
    package_token = _string_or_none(package_ids)
    if cert and package_token:
        first_package = package_token.split("|", 1)[0]
        return f"{cert}-{first_package}"
    return cert


def _normalize_arconic_sales_order(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\b\d{6,}\b")


def _normalize_arconic_customer_po(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\b[0-9][0-9A-Z/-]{0,}\b")


def _normalize_arconic_line_no(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\b\d+\.\d+\b")


def _normalize_arconic_customer_item_number(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\bA[0-9A-Z]{5,}\b")


def _normalize_arconic_item_number(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\bBG[0-9A-Z]+\b")


def _normalize_arconic_cast_number(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\bC\d{9,}\b")


def _normalize_arconic_package_ids(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    tokens = re.findall(r"\b\d{8}\b", cleaned)
    return "|".join(dict.fromkeys(tokens)) if tokens else None


def _normalize_arconic_alloy_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    text = cleaned.upper().replace("_", " ").replace("/", " ")
    match = re.search(r"\b(2014A?|2618A?|5005A?|6005A?|6061A?|6082A?|6111A?|7075A?)\s*(?:[- ]|\s+)?(T\d+[A-Z0-9]*|F|H\d+)?\b", text)
    if match is None:
        return None
    alloy = match.group(1)
    temper = match.group(2)
    return f"{alloy} {temper}".strip() if temper else alloy


def _normalize_arconic_diameter_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    text = cleaned.upper()
    for pattern in (
        r"\bRD\s*0*([0-9]{1,3}(?:[.,][0-9]+)?)\b",
        r"\bRD\s*0*([0-9]{1,3})(?=[_\s|/-])",
        r"\bDIA(?:METER)?\s*0*([0-9]{1,3}(?:[.,][0-9]+)?)\b",
        r"\bROUND\s+BAR\s+0*([0-9]{1,3}(?:[.,][0-9]+)?)\b",
        r"\b([0-9]{1,3}(?:[.,][0-9]+)?)\s*MM\b",
    ):
        match = re.search(pattern, text)
        if match is None:
            continue
        normalized = _normalize_numeric_value(match.group(1))
        if normalized is None:
            continue
        try:
            numeric_value = float(normalized)
        except ValueError:
            continue
        if 0 < numeric_value <= 400:
            return str(int(numeric_value)) if numeric_value.is_integer() else normalized
    return None


def _get_metalba_certificate_ai_payload(
    db: Session,
    *,
    certificate_document: Document,
    openai_api_key: str,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> dict[str, object]:
    cached = certificate_ai_cache.get(certificate_document.id) if certificate_ai_cache is not None else None
    if cached is not None:
        return cached

    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)
    if not _document_has_image_pages(certificate_document):
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    crops = _build_certificate_safe_crops(certificate_document.pages, supplier_key="metalba")
    page_images = _select_metalba_certificate_document_images(crops)
    if not page_images:
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    raw_payload = _extract_metalba_certificate_payload_from_openai(
        page_images,
        openai_api_key=openai_api_key,
    )
    payload = _normalize_metalba_certificate_ai_payload(page_images, raw_payload)
    if certificate_ai_cache is not None:
        certificate_ai_cache[certificate_document.id] = payload
    return payload


def _select_metalba_certificate_document_images(
    crops: dict[str, dict[str, str | int]],
) -> dict[str, dict[str, str | int]]:
    return _select_impol_certificate_document_images(crops)


def _extract_metalba_certificate_payload_from_openai(
    page_images: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> dict[str, object]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi questo certificato materiale. "
                "Scopo: estrarre i dati identificativi e tecnici del certificato, leggere composizione chimica, proprieta meccaniche e note tecniche rilevanti. "
                "Presta particolare attenzione a Ordine Cliente, Commessa, Colata Nr., KG e Product description. "
                "Usa solo testo realmente visibile nel documento. Non inventare, non inferire, non normalizzare. "
                "Se un campo non e chiaramente leggibile, restituisci null. "
                "Campi core da estrarre. "
                "numero_certificato: estrai il numero certificato dal campo Nr. "
                "ordine_cliente: estrai il valore del campo Ordine Cliente o Customer Order. "
                "articolo: estrai il codice articolo solo se esiste un campo chiaramente visibile; altrimenti restituisci null. "
                "lega: estrai la lega o stato dal blocco Product description. "
                "descrizione_profilo_cliente: per questo fornitore usa null se non esiste un vero campo equivalente separato. "
                "colata: estrai il valore del campo Colata Nr. della riga misurata. "
                "peso_netto: estrai il valore KG associato alla riga prodotto; non confondere questo dato con altri numeri della tabella. "
                "Campi runtime di supporto da estrarre inoltre. "
                "commessa_raw: estrai il valore del campo Commessa. "
                "product_description_raw: estrai l'intero contenuto raw del blocco Product description; se il contenuto e spezzato su piu righe ma appartiene allo stesso blocco o cella, unisci le righe con uno spazio. "
                "diameter_raw: estrai il diametro dal blocco Product description se compare come BARRA TONDA DIAM. "
                "Chimica: usa solo Si, Fe, Cu, Mn, Mg, Cr, Ni, Zn, Ti, Cd, Hg, Pb, V, Bi, Sn, Zr, Be, Zr+Ti, Mn+Cr, Bi+Pb; restituisci solo i valori misurati veri e ignora Min e Max. "
                "Proprieta meccaniche: considera Rm, Rp0.2, A%, HB, IACS%, Rp0.2/Rm; non usare Min o Max; se ci sono piu righe misurate vere, restituisci tutte le righe misurate raw. "
                "Note: verifica nota_us_control_class_a, nota_us_control_class_b, nota_rohs, nota_radioactive_free; se compaiono sia Class A sia Class B restituisci entrambe. "
                "Restituisci solo JSON con questa struttura: "
                "{\"core\":{\"numero_certificato\":\"string|null\",\"ordine_cliente\":\"string|null\",\"articolo\":\"string|null\","
                "\"lega\":\"string|null\",\"descrizione_profilo_cliente\":\"string|null\",\"colata\":\"string|null\",\"peso_netto\":\"string|null\","
                "\"commessa_raw\":\"string|null\",\"product_description_raw\":\"string|null\",\"diameter_raw\":\"string|null\"},"
                "\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\",\"Mn\":\"string|null\",\"Mg\":\"string|null\","
                "\"Cr\":\"string|null\",\"Ni\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\",\"Cd\":\"string|null\",\"Hg\":\"string|null\","
                "\"Pb\":\"string|null\",\"V\":\"string|null\",\"Bi\":\"string|null\",\"Sn\":\"string|null\",\"Zr\":\"string|null\",\"Be\":\"string|null\",\"Zr+Ti\":\"string|null\",\"Mn+Cr\":\"string|null\","
                "\"Bi+Pb\":\"string|null\"},"
                "\"mechanical_raw\":{\"measured_rows\":[{\"Rm\":\"string|null\",\"Rp0.2\":\"string|null\",\"A%\":\"string|null\",\"HB\":\"string|null\","
                "\"IACS%\":\"string|null\",\"Rp0.2/Rm\":\"string|null\"}]},"
                "\"notes_raw\":{\"nota_us_control_class_a_raw\":\"string|null\",\"nota_us_control_class_b_raw\":\"string|null\","
                "\"nota_rohs_raw\":\"string|null\",\"nota_radioactive_free_raw\":\"string|null\"}}"
            ),
        }
    ]

    for image_label, crop in page_images.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append({"type": "input_text", "text": f"Image label: {image_label}; page_number: {crop.get('page_number') or 'unknown'}"})
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Metalba certificate AI extraction request failed") from exc

    return _parse_openai_json_payload_for_certificate_bundle(response.output_text)


def _normalize_metalba_certificate_ai_payload(
    page_images: dict[str, dict[str, str | int]],
    raw_payload: dict[str, object],
) -> dict[str, object]:
    first_page_crop = next(iter(page_images.values()), None)
    first_page_id = int(first_page_crop.get("page_id")) if first_page_crop and first_page_crop.get("page_id") else 0
    last_page_crop = next(reversed(page_images.values()), None) if page_images else None
    last_page_id = int(last_page_crop.get("page_id")) if last_page_crop and last_page_crop.get("page_id") else first_page_id

    core_payload = cast(dict[str, object], raw_payload.get("core") or {})
    core_fields = _sanitize_metalba_vision_certificate_fields(core_payload, next(iter(page_images.keys()), None))

    chemistry_payload = cast(dict[str, object], raw_payload.get("chemistry_raw") or {})
    chemistry_matches = _normalize_vision_numeric_matches(
        {
            field_name: {
                "value": _string_or_none(chemistry_payload.get(field_name)),
                "evidence": _string_or_none(chemistry_payload.get(field_name)),
                "source_crop": next(iter(page_images.keys()), None),
            }
            for field_name in ("Si", "Fe", "Cu", "Mn", "Mg", "Cr", "Ni", "Zn", "Ti", "Cd", "Hg", "Pb", "V", "Bi", "Sn", "Zr", "Be", "Zr+Ti", "Mn+Cr", "Bi+Pb")
        },
        {
            next(iter(page_images.keys()), "page1"): {
                "page_id": first_page_id,
                "page_number": first_page_crop.get("page_number") if first_page_crop else 1,
            }
        },
    )

    measured_rows_payload = cast(dict[str, object], raw_payload.get("mechanical_raw") or {}).get("measured_rows") or []
    property_matches = _normalize_aluminium_bozen_measured_rows_payload(
        measured_rows_payload if isinstance(measured_rows_payload, list) else [],
        page_id=first_page_id,
    )

    notes_payload = cast(dict[str, object], raw_payload.get("notes_raw") or {})
    note_matches = _normalize_vision_note_matches(
        _build_vision_note_extracted_payload(notes_payload, next(reversed(page_images.keys()), None) if page_images else None),
        {
            next(reversed(page_images.keys()), "page1"): {
                "page_id": last_page_id,
                "page_number": last_page_crop.get("page_number") if last_page_crop else (first_page_crop.get("page_number") if first_page_crop else 1),
            }
        },
    )

    commessa_raw = _string_or_none(core_payload.get("commessa_raw"))
    product_description_raw = _string_or_none(core_payload.get("product_description_raw"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw"))
    diameter_context = " ".join(
        part for part in (product_description_raw, diameter_raw) if _string_or_none(part) is not None
    ) or product_description_raw or diameter_raw
    weight_raw = _string_or_none(core_payload.get("peso_netto"))

    return {
        "match_values": {
            field_name: _string_or_none(field_payload.get("value"))
            for field_name, field_payload in core_fields.items()
        },
        "supplier_fields": {
            "ordine_cliente": _extract_token_from_value_or_evidence(
                _string_or_none(core_payload.get("ordine_cliente")),
                _string_or_none(core_payload.get("ordine_cliente")),
                r"\b\d{1,3}/\d{2}\b",
            ),
            "commessa_root": _normalize_commessa_root(commessa_raw),
            "product_description_raw": product_description_raw,
            "diameter": _normalize_metalba_diameter_from_text(diameter_context),
            "net_weight": _normalize_weight_value(weight_raw),
        },
        "core_fields": core_fields,
        "chemistry": chemistry_matches,
        "properties": property_matches,
        "notes": note_matches,
        "debug_raw_output": json.dumps(raw_payload, ensure_ascii=False),
    }


def _sanitize_metalba_vision_certificate_fields(
    core_payload: dict[str, object],
    source_crop: str | None,
) -> dict[str, dict[str, str | None]]:
    certificate_raw = _string_or_none(core_payload.get("numero_certificato"))
    order_raw = _string_or_none(core_payload.get("ordine_cliente"))
    article_raw = _string_or_none(core_payload.get("articolo"))
    product_description_raw = _string_or_none(core_payload.get("product_description_raw"))
    alloy_raw = _string_or_none(core_payload.get("lega")) or product_description_raw
    cast_raw = _string_or_none(core_payload.get("colata"))
    weight_raw = _string_or_none(core_payload.get("peso_netto"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw"))
    diameter_context = " ".join(
        part for part in (product_description_raw, diameter_raw) if _string_or_none(part) is not None
    ) or product_description_raw or diameter_raw

    def _payload(value: str | None) -> dict[str, str | None]:
        return {"value": value, "evidence": value, "source_crop": source_crop}

    return {
        "numero_certificato_certificato": _payload(
            _extract_token_from_value_or_evidence(
                certificate_raw,
                certificate_raw,
                r"\b\d{2}-\d{4,5}\b",
                disallow={"10204"},
            )
        ),
        "articolo_certificato": _payload(_string_or_none(article_raw)),
        "codice_cliente_certificato": _payload(None),
        "ordine_cliente_certificato": _payload(
            _extract_token_from_value_or_evidence(order_raw, order_raw, r"\b\d{1,3}/\d{2}\b")
        ),
        "lega_certificato": _payload(_normalize_metalba_alloy_from_text(alloy_raw)),
        "diametro_certificato": _payload(_normalize_metalba_diameter_from_text(diameter_context)),
        "colata_certificato": _payload(
            _extract_token_from_value_or_evidence(cast_raw, cast_raw, r"\b\d{5}[A-Z]\b", disallow={"10204"})
        ),
        "peso_certificato": _payload(_normalize_weight_value(weight_raw)),
    }


def extract_ddt_fields_with_vision(
    db: Session,
    row: AcquisitionRow,
    *,
    actor_id: int,
    openai_api_key: str,
) -> AcquisitionRowDetailResponse:
    _reopen_row_if_validated(db, row, actor_id=actor_id, reason="ddt_vision")
    ddt_document = get_document(db, row.document_ddt_id)
    if not ddt_document.pages:
        ddt_document = _index_document_from_path(db, ddt_document)
    ddt_document = _ensure_document_page_images(db, ddt_document)

    image_pages = [page for page in ddt_document.pages if page.immagine_pagina_storage_key]
    if not image_pages:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="DDT has no image pages available for vision")

    supplier_key = _resolve_row_supplier_key(row)
    if supplier_key in {"aluminium_bozen", "impol", "metalba", "leichtmetall", "neuman", "aww", "zalco"}:
        sibling_rows = (
            db.query(AcquisitionRow)
            .filter(AcquisitionRow.document_ddt_id == ddt_document.id)
            .order_by(AcquisitionRow.id.asc())
            .all()
        )
        ai_candidates = _extract_supplier_ddt_row_groups_with_vision(
            db=db,
            supplier_key=supplier_key,
            ddt_document=ddt_document,
            openai_api_key=openai_api_key,
        )
        if supplier_key == "aluminium_bozen":
            _apply_aluminium_bozen_ai_row_groups_to_rows(
                db=db,
                ddt_document=ddt_document,
                rows=sibling_rows,
                ai_candidates=ai_candidates,
                actor_id=actor_id,
            )
        elif supplier_key == "aww":
            _apply_aww_ai_row_groups_to_rows(
                db=db,
                ddt_document=ddt_document,
                rows=sibling_rows,
                ai_candidates=ai_candidates,
                actor_id=actor_id,
            )
        elif supplier_key == "metalba":
            _apply_metalba_ai_row_groups_to_rows(
                db=db,
                ddt_document=ddt_document,
                rows=sibling_rows,
                ai_candidates=ai_candidates,
                actor_id=actor_id,
            )
        elif supplier_key == "leichtmetall":
            _apply_leichtmetall_ai_row_groups_to_rows(
                db=db,
                ddt_document=ddt_document,
                rows=sibling_rows,
                ai_candidates=ai_candidates,
                actor_id=actor_id,
            )
        elif supplier_key == "neuman":
            _apply_neuman_ai_row_groups_to_rows(
                db=db,
                ddt_document=ddt_document,
                rows=sibling_rows,
                ai_candidates=ai_candidates,
                actor_id=actor_id,
            )
        elif supplier_key == "zalco":
            _apply_zalco_ai_row_groups_to_rows(
                db=db,
                ddt_document=ddt_document,
                rows=sibling_rows,
                ai_candidates=ai_candidates,
                actor_id=actor_id,
            )
        else:
            _apply_impol_ai_row_groups_to_rows(
                db=db,
                ddt_document=ddt_document,
                rows=sibling_rows,
                ai_candidates=ai_candidates,
                actor_id=actor_id,
            )
        return serialize_acquisition_row_detail(get_acquisition_row(db, row.id))

    ddt_values = {
        value.campo: _final_value_for_row(value)
        for value in (
            db.query(ReadValue)
            .filter(ReadValue.acquisition_row_id == row.id, ReadValue.blocco == "ddt")
            .all()
        )
    }

    crop_definitions = _build_ddt_safe_crops(
        image_pages,
        row=row,
        supplier_key=supplier_key,
        ddt_values=ddt_values,
    )
    if not crop_definitions:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Unable to prepare DDT image crops for vision")

    extracted = _sanitize_vision_ddt_fields(_extract_ddt_fields_from_openai(crop_definitions, openai_api_key=openai_api_key))
    extracted_count = 0

    for field_name, payload in extracted.items():
        field_value = _string_or_none(payload.get("value"))
        if field_value is None:
            if _is_revisable_chatgpt_ddt_value(row, field_name):
                _upsert_read_value_model(
                    db=db,
                    acquisition_row_id=row.id,
                    blocco="ddt",
                    campo=field_name,
                    valore_grezzo=None,
                    valore_standardizzato=None,
                    valore_finale=None,
                    stato="proposto",
                    document_evidence_id=None,
                    metodo_lettura="chatgpt",
                    fonte_documentale="ddt",
                    confidenza=None,
                    actor_id=actor_id,
                )
            continue
        if _has_stable_value_protected_from_ai(row, "ddt", field_name):
            continue
        source_crop = payload.get("source_crop")
        evidence_text = _string_or_none(payload.get("evidence")) or field_value
        crop_definition = crop_definitions.get(source_crop) if source_crop else None

        evidence = DocumentEvidence(
            document_id=ddt_document.id,
            document_page_id=crop_definition["page_id"] if crop_definition else None,
            acquisition_row_id=row.id,
            blocco="ddt",
            tipo_evidenza="crop",
            bbox=crop_definition["bbox"] if crop_definition else None,
            testo_grezzo=evidence_text,
            storage_key_derivato=crop_definition["storage_key"] if crop_definition else None,
            metodo_estrazione="chatgpt",
            mascherato=True,
            confidenza=0.72,
            utente_creazione_id=actor_id,
        )
        db.add(evidence)
        db.flush()

        _upsert_read_value_model(
            db=db,
            acquisition_row_id=row.id,
            blocco="ddt",
            campo=field_name,
            valore_grezzo=evidence_text,
            valore_standardizzato=field_value,
            valore_finale=field_value,
            stato="proposto",
            document_evidence_id=evidence.id,
            metodo_lettura="chatgpt",
            fonte_documentale="ddt",
            confidenza=0.72,
            actor_id=actor_id,
        )
        extracted_count += 1

    _sync_row_from_ddt_values(db, row)

    _sync_row_statuses(db, row)
    db.add(row)
    _record_history_event(
        db=db,
        acquisition_row_id=row.id,
        blocco="ddt",
        azione="campi_core_vision_rilevati" if extracted_count else "campi_core_vision_non_rilevati",
        user_id=actor_id,
        nota_breve=str(extracted_count) if extracted_count else None,
    )
    db.commit()
    return serialize_acquisition_row_detail(get_acquisition_row(db, row.id))


def run_ai_intervention(
    db: Session,
    row: AcquisitionRow,
    *,
    actor_id: int,
    openai_api_key: str,
) -> AcquisitionRowDetailResponse:
    supplier_key = _resolve_row_supplier_key(row)
    if not _supplier_supports_ai_vision_pipeline(supplier_key):
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Intervento AI disponibile solo per i fornitori con pipeline AI attiva in questa fase",
        )
    if row.document_ddt_id is None and row.document_certificato_id is None:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Acquisition row has no DDT or certificate document",
        )

    extract_core_fields(db=db, row=row, actor_id=actor_id)
    refreshed_row = get_acquisition_row(db, row.id)

    if refreshed_row.document_ddt_id is not None:
        extract_ddt_fields_with_vision(
            db=db,
            row=refreshed_row,
            actor_id=actor_id,
            openai_api_key=openai_api_key,
        )
        refreshed_row = get_acquisition_row(db, row.id)

    if refreshed_row.document_certificato_id is not None:
        _extract_certificate_core_fields_with_vision(
            db=db,
            row=refreshed_row,
            actor_id=actor_id,
            openai_api_key=openai_api_key,
        )
        refreshed_row = get_acquisition_row(db, row.id)
        detect_chemistry(
            db=db,
            row=refreshed_row,
            actor_id=actor_id,
            openai_api_key=openai_api_key,
        )
        refreshed_row = get_acquisition_row(db, row.id)
        detect_properties(
            db=db,
            row=refreshed_row,
            actor_id=actor_id,
            openai_api_key=openai_api_key,
        )
        refreshed_row = get_acquisition_row(db, row.id)
        detect_standard_notes(db=db, row=refreshed_row, actor_id=actor_id, openai_api_key=openai_api_key)
        refreshed_row = get_acquisition_row(db, row.id)

    _record_history_event(
        db=db,
        acquisition_row_id=refreshed_row.id,
        blocco="workflow",
        azione="intervento_ai_eseguito",
        user_id=actor_id,
    )
    db.commit()
    return serialize_acquisition_row_detail(get_acquisition_row(db, row.id))


def _resolve_row_supplier_key(row: AcquisitionRow) -> str | None:
    template = resolve_supplier_template(
        row.supplier.ragione_sociale if row.supplier is not None else None,
        row.fornitore_raw,
        row.ddt_document.supplier.ragione_sociale if row.ddt_document and row.ddt_document.supplier else None,
        row.certificate_document.supplier.ragione_sociale if row.certificate_document and row.certificate_document.supplier else None,
    )
    return template.supplier_key if template is not None else None


def _process_certificate_side_blocks(
    db: Session,
    *,
    row: AcquisitionRow,
    actor_id: int,
    openai_api_key: str | None,
    use_ai_intervention: bool,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> AcquisitionRow:
    current_row = get_acquisition_row(db, row.id)
    if current_row.document_certificato_id is None:
        return current_row

    supplier_key = _resolve_row_supplier_key(current_row)
    if use_ai_intervention and openai_api_key and _supplier_supports_ai_vision_pipeline(supplier_key):
        payload = _get_supplier_certificate_ai_payload(
            db=db,
            supplier_key=supplier_key,
            certificate_document=get_document(db, current_row.document_certificato_id),
            openai_api_key=openai_api_key,
            certificate_ai_cache=certificate_ai_cache,
        )
        _apply_supplier_certificate_ai_payload(
            db=db,
            row=current_row,
            payload=payload,
            actor_id=actor_id,
        )
        current_row = get_acquisition_row(db, current_row.id)
        if current_row.certificate_document is not None:
            _sync_row_cdq_from_certificate_document(db, current_row, current_row.certificate_document)
        return current_row

    if not _block_has_confirmed_values(db, current_row.id, "chimica"):
        detect_chemistry(db=db, row=current_row, actor_id=actor_id, openai_api_key=openai_api_key)
        current_row = get_acquisition_row(db, row.id)

    if not _block_has_confirmed_values(db, current_row.id, "proprieta"):
        detect_properties(db=db, row=current_row, actor_id=actor_id, openai_api_key=openai_api_key)
        current_row = get_acquisition_row(db, row.id)

    if not _block_has_confirmed_values(db, current_row.id, "note"):
        detect_standard_notes(db=db, row=current_row, actor_id=actor_id, openai_api_key=openai_api_key)
        current_row = get_acquisition_row(db, row.id)

    if current_row.certificate_document is not None:
        _sync_row_cdq_from_certificate_document(db, current_row, current_row.certificate_document)
    return current_row


def _extract_certificate_core_fields_with_vision(
    db: Session,
    row: AcquisitionRow,
    *,
    actor_id: int,
    openai_api_key: str,
) -> AcquisitionRowDetailResponse:
    certificate_document_id = row.document_certificato_id
    if certificate_document_id is None:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Acquisition row has no certificate document")

    _reopen_row_if_validated(db, row, actor_id=actor_id, reason="certificato_vision")
    certificate_document = get_document(db, certificate_document_id)
    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)

    image_pages = [page for page in certificate_document.pages if page.immagine_pagina_storage_key]
    if not image_pages:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Certificate has no image pages available for vision",
        )

    supplier_key = _resolve_row_supplier_key(row)
    field_names = [
        "numero_certificato_certificato",
        "articolo_certificato",
        "codice_cliente_certificato",
        "ordine_cliente_certificato",
        "lega_certificato",
        "diametro_certificato",
        "colata_certificato",
        "peso_certificato",
    ]
    crop_definitions: dict[str, dict[str, str | int]]
    if _supplier_supports_ai_vision_pipeline(supplier_key):
        crop_definitions = _build_certificate_safe_crops(image_pages, supplier_key=supplier_key)
        payload = _get_supplier_certificate_ai_payload(
            db=db,
            supplier_key=supplier_key,
            certificate_document=certificate_document,
            openai_api_key=openai_api_key,
            certificate_ai_cache=None,
        )
        extracted = cast(dict[str, dict[str, str | None]], payload.get("core_fields") or {})
    else:
        crop_definitions = _build_certificate_safe_crops(image_pages, supplier_key=supplier_key)
        if not crop_definitions:
            raise HTTPException(
                status_code=status.HTTP_400_BAD_REQUEST,
                detail="Unable to prepare certificate image crops for vision",
            )
        extracted = _extract_certificate_fields_from_openai(
            crop_definitions,
            openai_api_key=openai_api_key,
            field_names=field_names,
            instruction=(
                "Leggi i ritagli del blocco identita e dei blocchi tecnici vicini di un certificato materiale. "
                "Estrai solo i campi core chiaramente leggibili senza inventare. "
                "I codici articolo possono apparire come 14BT..., i codici cliente come token tecnici che iniziano con A, "
                "l'ordine cliente puo apparire come numero con data o data con numero."
            ),
        )
    extracted_count = 0

    for field_name, payload in extracted.items():
        field_value = _string_or_none(payload.get("value"))
        if field_value is None:
            if _is_revisable_chatgpt_match_value(row, field_name):
                _upsert_read_value_model(
                    db=db,
                    acquisition_row_id=row.id,
                    blocco="match",
                    campo=field_name,
                    valore_grezzo=None,
                    valore_standardizzato=None,
                    valore_finale=None,
                    stato="proposto",
                    document_evidence_id=None,
                    metodo_lettura="chatgpt",
                    fonte_documentale="certificato",
                    confidenza=None,
                    actor_id=actor_id,
                )
            continue
        if _has_stable_value_protected_from_ai(row, "match", field_name):
            continue
        source_crop = payload.get("source_crop")
        evidence_text = _string_or_none(payload.get("evidence")) or field_value
        crop_definition = crop_definitions.get(source_crop) if source_crop else None

        evidence = DocumentEvidence(
            document_id=certificate_document.id,
            document_page_id=crop_definition["page_id"] if crop_definition else None,
            acquisition_row_id=row.id,
            blocco="match",
            tipo_evidenza="crop",
            bbox=crop_definition["bbox"] if crop_definition else None,
            testo_grezzo=evidence_text,
            storage_key_derivato=crop_definition["storage_key"] if crop_definition else None,
            metodo_estrazione="chatgpt",
            mascherato=True,
            confidenza=0.72,
            utente_creazione_id=actor_id,
        )
        db.add(evidence)
        db.flush()

        _upsert_read_value_model(
            db=db,
            acquisition_row_id=row.id,
            blocco="match",
            campo=field_name,
            valore_grezzo=evidence_text,
            valore_standardizzato=field_value,
            valore_finale=field_value,
            stato="proposto",
            document_evidence_id=evidence.id,
            metodo_lettura="chatgpt",
            fonte_documentale="certificato",
            confidenza=0.72,
            actor_id=actor_id,
        )
        extracted_count += 1

    _sync_row_from_match_values(db, row)
    _sync_row_statuses(db, row)
    db.add(row)
    _record_history_event(
        db=db,
        acquisition_row_id=row.id,
        blocco="match",
        azione="campi_core_certificato_vision_rilevati" if extracted_count else "campi_core_certificato_vision_non_rilevati",
        user_id=actor_id,
        nota_breve=str(extracted_count) if extracted_count else None,
    )
    db.commit()
    return serialize_acquisition_row_detail(get_acquisition_row(db, row.id))


def _get_supplier(db: Session, supplier_id: int) -> Supplier:
    supplier = db.get(Supplier, supplier_id)
    if supplier is None:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="Supplier not found")
    return supplier


def _get_document_of_type(db: Session, document_id: int, expected_type: str) -> Document:
    document = get_document(db, document_id)
    if document.tipo_documento != expected_type:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail=f"Document {document_id} is not of type {expected_type}",
        )
    return document


def _resolve_supplier_id(
    db: Session,
    explicit_supplier_id: int | None,
    ddt_document: Document | None,
    certificate_document: Document | None,
) -> int | None:
    supplier_ids = {
        supplier_id
        for supplier_id in {
            explicit_supplier_id,
            ddt_document.fornitore_id if ddt_document is not None else None,
            certificate_document.fornitore_id if certificate_document else None,
        }
        if supplier_id is not None
    }
    if explicit_supplier_id is not None:
        _get_supplier(db, explicit_supplier_id)
    if len(supplier_ids) > 1:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Supplier mismatch across row documents")
    return next(iter(supplier_ids), None)


def _normalize_upload_batch_id(value: str | None) -> str | None:
    normalized = _string_or_none(value)
    if normalized is None:
        return None
    return normalized[:64]


def _find_temporary_duplicate_document_for_user(db: Session, *, actor_id: int, file_hash: str) -> Document | None:
    if not file_hash:
        return None
    return (
        db.query(Document)
        .options(joinedload(Document.supplier))
        .filter(
            Document.utente_upload_id == actor_id,
            Document.stato_upload == "temporaneo",
            Document.hash_file == file_hash,
        )
        .order_by(Document.data_upload.desc(), Document.id.desc())
        .first()
    )


def _find_persistent_duplicate_document(db: Session, *, file_hash: str) -> Document | None:
    if not file_hash:
        return None
    return (
        db.query(Document)
        .options(joinedload(Document.supplier))
        .filter(
            Document.stato_upload == "persistente",
            Document.hash_file == file_hash,
        )
        .order_by(Document.data_upload.desc(), Document.id.desc())
        .first()
    )


def _get_latest_temporary_upload_batch_id(db: Session, *, actor_id: int) -> str | None:
    document = (
        db.query(Document)
        .filter(
            Document.utente_upload_id == actor_id,
            Document.stato_upload == "temporaneo",
            Document.upload_batch_id.isnot(None),
        )
        .order_by(Document.data_upload.desc(), Document.id.desc())
        .first()
    )
    if document is None:
        return None
    return _normalize_upload_batch_id(document.upload_batch_id)


def _delete_storage_key_if_present(storage_key: str | None) -> None:
    resolved_key = _string_or_none(storage_key)
    if resolved_key is None:
        return
    path = _resolve_storage_path(resolved_key)
    if path.exists():
        path.unlink()


def _delete_temporary_upload_batch(db: Session, *, actor_id: int, upload_batch_id: str) -> None:
    documents = (
        db.query(Document)
        .options(joinedload(Document.pages), joinedload(Document.evidences))
        .filter(
            Document.utente_upload_id == actor_id,
            Document.stato_upload == "temporaneo",
            Document.upload_batch_id == upload_batch_id,
        )
        .all()
    )
    if not documents:
        return

    for document in documents:
        if document.rows_as_ddt or document.rows_as_certificate or document.matches or document.match_candidates:
            raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Cannot discard a batch that is already in use")
        page_ids = [page.id for page in document.pages]
        for evidence in document.evidences:
            _delete_storage_key_if_present(evidence.storage_key_derivato)
            db.delete(evidence)
        if page_ids:
            page_evidences = db.query(DocumentEvidence).filter(DocumentEvidence.document_page_id.in_(page_ids)).all()
            for evidence in page_evidences:
                _delete_storage_key_if_present(evidence.storage_key_derivato)
                db.delete(evidence)
        for page in document.pages:
            _delete_storage_key_if_present(page.immagine_pagina_storage_key)
            db.delete(page)
        _delete_storage_key_if_present(document.storage_key)
        db.delete(document)

    db.commit()


def _delete_temporary_documents_by_ids(db: Session, *, actor_id: int, document_ids: list[int]) -> None:
    normalized_ids = _normalize_document_id_list(document_ids)
    if not normalized_ids:
        return
    documents = (
        db.query(Document)
        .options(joinedload(Document.pages), joinedload(Document.evidences))
        .filter(
            Document.utente_upload_id == actor_id,
            Document.stato_upload == "temporaneo",
            Document.id.in_(normalized_ids),
        )
        .all()
    )
    if not documents:
        return

    for document in documents:
        if document.rows_as_ddt or document.rows_as_certificate or document.matches or document.match_candidates:
            continue
        page_ids = [page.id for page in document.pages]
        for evidence in document.evidences:
            _delete_storage_key_if_present(evidence.storage_key_derivato)
            db.delete(evidence)
        if page_ids:
            page_evidences = db.query(DocumentEvidence).filter(DocumentEvidence.document_page_id.in_(page_ids)).all()
            for evidence in page_evidences:
                _delete_storage_key_if_present(evidence.storage_key_derivato)
                db.delete(evidence)
        for page in document.pages:
            _delete_storage_key_if_present(page.immagine_pagina_storage_key)
            db.delete(page)
        _delete_storage_key_if_present(document.storage_key)
        db.delete(document)

    db.commit()


def _set_documents_processing_state(db: Session, document_ids: list[int], *, stato_elaborazione: str) -> None:
    normalized_ids = _normalize_document_id_list(document_ids)
    if not normalized_ids:
        return
    documents = db.query(Document).filter(Document.id.in_(normalized_ids)).all()
    changed = False
    for document in documents:
        if document.stato_elaborazione == stato_elaborazione:
            continue
        document.stato_elaborazione = stato_elaborazione
        db.add(document)
        changed = True
    if changed:
        db.commit()


def _promote_documents_to_persistent(db: Session, document_ids: list[int]) -> None:
    normalized_ids = _normalize_document_id_list(document_ids)
    if not normalized_ids:
        return
    documents = db.query(Document).filter(Document.id.in_(normalized_ids)).all()
    changed = False
    for document in documents:
        if document.stato_upload == "persistente" and document.upload_batch_id is None and document.scadenza_batch is None:
            continue
        document.stato_upload = "persistente"
        document.upload_batch_id = None
        document.scadenza_batch = None
        db.add(document)
        changed = True
    if changed:
        db.commit()


def _save_run(
    db: Session,
    run: AutonomousProcessingRun,
    **updates: object,
) -> AutonomousProcessingRun:
    for field_name, value in updates.items():
        setattr(run, field_name, value)
    db.add(run)
    db.commit()
    db.refresh(run)
    return run


def _normalize_document_id_list(document_ids: list[int]) -> list[int]:
    seen: set[int] = set()
    normalized: list[int] = []
    for document_id in document_ids:
        if document_id in seen:
            continue
        seen.add(document_id)
        normalized.append(document_id)
    return normalized


def _ensure_documents_type(db: Session, document_ids: list[int], expected_type: str) -> None:
    for document_id in document_ids:
        _get_document_of_type(db, document_id, expected_type)


def _resolve_certificate_documents_for_automation(
    db: Session,
    *,
    ddt_documents: list[Document],
    explicit_certificate_document_ids: list[int],
) -> list[Document]:
    documents_by_id: dict[int, Document] = {}

    for document_id in explicit_certificate_document_ids:
        document = _get_document_of_type(db, document_id, "certificato")
        documents_by_id[document.id] = document

    if not ddt_documents and explicit_certificate_document_ids:
        return list(documents_by_id.values())

    supplier_ids = {document.fornitore_id for document in ddt_documents if document.fornitore_id is not None}
    acquisition_query = (
        db.query(AcquisitionRow.document_certificato_id)
        .filter(AcquisitionRow.document_certificato_id.is_not(None))
    )
    if supplier_ids:
        acquisition_query = acquisition_query.filter(AcquisitionRow.fornitore_id.in_(supplier_ids))

    acquisition_certificate_ids = sorted(
        {
            int(document_id)
            for (document_id,) in acquisition_query.distinct().all()
            if document_id is not None
        }
    )
    for document_id in acquisition_certificate_ids:
        document = _get_document_of_type(db, document_id, "certificato")
        documents_by_id.setdefault(document.id, document)

    return list(documents_by_id.values())


def _ensure_autonomous_rows(
    db: Session,
    *,
    ddt_document: Document,
    actor_id: int,
    actor_email: str,
) -> tuple[list[AcquisitionRow], int]:
    existing_rows = (
        db.query(AcquisitionRow)
        .filter(AcquisitionRow.document_ddt_id == ddt_document.id)
        .order_by(AcquisitionRow.id.asc())
        .all()
    )
    if existing_rows:
        return [get_acquisition_row(db, row.id) for row in existing_rows], 0

    document = prepare_document_for_reader(db, ddt_document)
    plan = build_document_row_split_plan(document)
    if plan.row_split_candidates:
        split_result = create_rows_from_document_split_plan(
            db=db,
            document=document,
            actor_id=actor_id,
            actor_email=actor_email,
        )
        return [get_acquisition_row(db, item.id) for item in split_result.created_rows], split_result.created_count

    supplier_name = ddt_document.supplier.ragione_sociale if ddt_document.supplier is not None else None
    created = create_acquisition_row(
        db=db,
        payload=AcquisitionRowCreateRequest(
            document_ddt_id=ddt_document.id,
            fornitore_id=ddt_document.fornitore_id,
            fornitore_raw=supplier_name,
        ),
        actor_id=actor_id,
        actor_email=actor_email,
    )
    return [get_acquisition_row(db, created.id)], 1


def _ensure_autonomous_rows_with_ai(
    db: Session,
    *,
    ddt_document: Document,
    actor_id: int,
    actor_email: str,
    openai_api_key: str,
) -> tuple[list[AcquisitionRow], int]:
    existing_rows = (
        db.query(AcquisitionRow)
        .filter(AcquisitionRow.document_ddt_id == ddt_document.id)
        .order_by(AcquisitionRow.id.asc())
        .all()
    )
    if existing_rows:
        return [get_acquisition_row(db, row.id) for row in existing_rows], 0

    template = resolve_supplier_template(
        ddt_document.supplier.ragione_sociale if ddt_document.supplier is not None else None,
        ddt_document.nome_file_originale,
    )
    supplier_key = template.supplier_key if template is not None else None
    if not _supplier_supports_ai_vision_pipeline(supplier_key):
        return _ensure_autonomous_rows(
            db=db,
            ddt_document=ddt_document,
            actor_id=actor_id,
            actor_email=actor_email,
        )

    ddt_document = _ensure_document_page_images(db, _index_document_from_path(db, ddt_document) if not ddt_document.pages else ddt_document)
    ai_candidates = _extract_supplier_ddt_row_groups_with_vision(
        db=db,
        supplier_key=supplier_key,
        ddt_document=ddt_document,
        openai_api_key=openai_api_key,
    )
    if not ai_candidates:
        return [], 0

    existing_rows_all = (
        db.query(AcquisitionRow)
        .filter(AcquisitionRow.fornitore_id == ddt_document.fornitore_id)
        .order_by(AcquisitionRow.id.asc())
        .all()
    )
    existing_signatures = {
        _split_candidate_signature_from_row(row): row
        for row in existing_rows_all
        if row.document_ddt_id is not None
    }

    created_rows: list[AcquisitionRow] = []
    fallback_ddt = next((candidate.ddt_number for candidate in ai_candidates if _string_or_none(candidate.ddt_number)), None)
    for candidate in ai_candidates:
        candidate_signature = _split_candidate_signature_from_candidate(
            document=ddt_document,
            candidate=candidate,
            fallback_ddt=fallback_ddt,
        )
        existing_row = existing_signatures.get(candidate_signature)
        if existing_row is not None:
            continue

        certificate_first_candidates = _candidate_rows_for_incoming_ddt_link(
            rows=existing_rows_all,
            supplier_id=ddt_document.fornitore_id,
        )
        certificate_first_row = _find_existing_certificate_first_row_for_split_candidate(
            db=db,
            rows=certificate_first_candidates,
            document=ddt_document,
            candidate=candidate,
            fallback_ddt=fallback_ddt,
            supplier_key=supplier_key,
        )
        if certificate_first_row is not None:
            certificate_first_row.document_ddt_id = ddt_document.id
            certificate_first_row.fornitore_id = ddt_document.fornitore_id
            certificate_first_row.fornitore_raw = ddt_document.supplier.ragione_sociale if ddt_document.supplier is not None else None
            certificate_first_row.ddt = candidate.ddt_number or fallback_ddt
            certificate_first_row.ordine = candidate.customer_order_no
            certificate_first_row.lega_base = candidate.lega or certificate_first_row.lega_base
            certificate_first_row.diametro = candidate.diametro or certificate_first_row.diametro
            certificate_first_row.colata = candidate.colata or certificate_first_row.colata
            certificate_first_row.peso = candidate.peso_netto or certificate_first_row.peso
            if candidate.cdq:
                certificate_first_row.cdq = candidate.cdq
            db.add(certificate_first_row)
            db.commit()
            db.refresh(certificate_first_row)
            _persist_split_candidate_values(db=db, row=certificate_first_row, candidate=candidate, actor_id=actor_id)
            _apply_supplier_ai_candidate_to_row(
                db=db,
                row=certificate_first_row,
                ai_candidate=candidate,
                actor_id=actor_id,
                document_id=ddt_document.id,
            )
            db.commit()
            refreshed = get_acquisition_row(db, certificate_first_row.id)
            existing_signatures[candidate_signature] = refreshed
            existing_rows_all.append(refreshed)
            created_rows.append(refreshed)
            continue

        created_row = create_acquisition_row(
            db=db,
            payload=AcquisitionRowCreateRequest(
                document_ddt_id=ddt_document.id,
                fornitore_id=ddt_document.fornitore_id,
                fornitore_raw=ddt_document.supplier.ragione_sociale if ddt_document.supplier is not None else None,
                cdq=candidate.cdq,
                lega_base=candidate.lega,
                diametro=candidate.diametro,
                colata=candidate.colata,
                ddt=candidate.ddt_number or fallback_ddt,
                peso=candidate.peso_netto,
                ordine=candidate.customer_order_no,
                stato_tecnico="rosso",
                stato_workflow="nuova",
                priorita_operativa="media",
            ),
            actor_id=actor_id,
            actor_email=actor_email,
        )
        row = get_acquisition_row(db, created_row.id)
        _persist_split_candidate_values(db=db, row=row, candidate=candidate, actor_id=actor_id)
        _apply_supplier_ai_candidate_to_row(
            db=db,
            row=row,
            ai_candidate=candidate,
            actor_id=actor_id,
            document_id=ddt_document.id,
        )
        db.commit()
        refreshed = get_acquisition_row(db, row.id)
        existing_signatures[candidate_signature] = refreshed
        existing_rows_all.append(refreshed)
        created_rows.append(refreshed)

    log_service.record(
        "acquisition",
        f"AI rows created from document {ddt_document.id}: {len(created_rows)}",
        actor_email,
    )
    return created_rows, len(created_rows)


def _ensure_certificate_first_rows(
    db: Session,
    *,
    certificate_documents: list[Document],
    actor_id: int,
    actor_email: str,
    openai_api_key: str | None,
    use_ai_intervention: bool,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> tuple[int, int]:
    created_count = 0
    linked_match_count = 0
    for certificate_document in certificate_documents:
        existing_for_document = (
            db.query(AcquisitionRow)
            .filter(AcquisitionRow.document_certificato_id == certificate_document.id)
            .first()
        )
        if existing_for_document is not None:
            continue

        certificate_document = prepare_document_for_reader(db, certificate_document)
        template = resolve_supplier_template(
            certificate_document.supplier.ragione_sociale if certificate_document.supplier is not None else None,
            certificate_document.nome_file_originale,
        )
        supplier_key = template.supplier_key if template is not None else None
        if not _supplier_supports_certificate_first(supplier_key):
            continue

        if use_ai_intervention and openai_api_key:
            payload = _get_supplier_certificate_ai_payload(
                db=db,
                supplier_key=supplier_key,
                certificate_document=certificate_document,
                openai_api_key=openai_api_key,
                certificate_ai_cache=certificate_ai_cache,
            )
            ai_match_values = cast(dict[str, str | None], payload.get("match_values") or {})
            ai_supplier_fields = cast(dict[str, str | None], payload.get("supplier_fields") or {})
            certificate_number = _string_or_none(ai_match_values.get("numero_certificato_certificato"))
            certificate_alloy = _string_or_none(ai_match_values.get("lega_certificato"))
            certificate_diameter = _string_or_none(ai_match_values.get("diametro_certificato"))
            certificate_cast = _string_or_none(ai_match_values.get("colata_certificato"))
            certificate_weight = _string_or_none(ai_match_values.get("peso_certificato"))
            certificate_article = (
                _string_or_none(ai_supplier_fields.get("article"))
                or _string_or_none(ai_supplier_fields.get("product_code"))
                or _string_or_none(ai_supplier_fields.get("arconic_item_number"))
                or _string_or_none(ai_supplier_fields.get("code_art"))
                or _string_or_none(ai_match_values.get("articolo_certificato"))
            )
            certificate_profile_code = (
                _string_or_none(ai_supplier_fields.get("profile_code"))
                or _string_or_none(ai_supplier_fields.get("customer_code"))
                or _string_or_none(ai_supplier_fields.get("customer_item_number"))
                or _string_or_none(ai_supplier_fields.get("symbol"))
                or _string_or_none(ai_match_values.get("codice_cliente_certificato"))
            )
            certificate_customer_order = (
                _string_or_none(ai_supplier_fields.get("customer_order_normalized"))
                or _string_or_none(ai_supplier_fields.get("customer_order_no"))
                or _string_or_none(ai_supplier_fields.get("customer_po"))
                or _string_or_none(ai_supplier_fields.get("order_no"))
                or (_string_or_none(ai_supplier_fields.get("customer_order_number")) if supplier_key == "neuman" else None)
                or (_string_or_none(ai_supplier_fields.get("ordine_cliente")) if supplier_key == "metalba" else None)
                or _string_or_none(ai_match_values.get("ordine_cliente_certificato"))
            )
            certificate_delivery_note = (
                _string_or_none(ai_supplier_fields.get("delivery_note_no"))
                or _string_or_none(ai_supplier_fields.get("tally_sheet_no"))
                or _string_or_none(ai_match_values.get("ddt_certificato"))
            )
            certificate_packing_list = (
                _string_or_none(ai_supplier_fields.get("packing_list_no"))
                or _string_or_none(ai_supplier_fields.get("packing_slip_no"))
            )
            certificate_supplier_order = (
                _string_or_none(ai_supplier_fields.get("supplier_order_no"))
                or _string_or_none(ai_supplier_fields.get("sales_order_number"))
                or (_string_or_none(ai_supplier_fields.get("auftragsbestaetigung_root")) if supplier_key == "aww" else None)
            )
        else:
            certificate_matches = reader_detect_certificate_core_matches(
                certificate_document.pages,
                supplier_key=supplier_key,
            )
            supplier_fields = reader_extract_supplier_match_fields(
                certificate_document.pages,
                supplier_key,
                "certificato",
            )
            certificate_number = _string_or_none(cast(dict[str, object], certificate_matches.get("numero_certificato_certificato") or {}).get("final"))
            certificate_alloy = _string_or_none(cast(dict[str, object], certificate_matches.get("lega_certificato") or {}).get("final"))
            certificate_diameter = _string_or_none(cast(dict[str, object], certificate_matches.get("diametro_certificato") or {}).get("final"))
            certificate_cast = _string_or_none(cast(dict[str, object], certificate_matches.get("colata_certificato") or {}).get("final"))
            certificate_weight = _string_or_none(cast(dict[str, object], certificate_matches.get("peso_certificato") or {}).get("final"))
            certificate_article = (
                _string_or_none(supplier_fields.get("article"))
                or _string_or_none(supplier_fields.get("product_code"))
                or _string_or_none(supplier_fields.get("customer_material_number"))
                or _string_or_none(supplier_fields.get("arconic_item_number"))
                or _string_or_none(supplier_fields.get("code_art"))
                or (_string_or_none(supplier_fields.get("kunden_teile_nr")) if supplier_key == "aww" else None)
            )
            certificate_profile_code = (
                _string_or_none(supplier_fields.get("profile_code"))
                or _string_or_none(supplier_fields.get("customer_code"))
                or _string_or_none(supplier_fields.get("customer_item_number"))
                or _string_or_none(supplier_fields.get("symbol"))
                or (_string_or_none(supplier_fields.get("artikel_nr")) if supplier_key == "aww" else None)
            )
            certificate_customer_order = (
                _string_or_none(supplier_fields.get("customer_order_normalized"))
                or _string_or_none(supplier_fields.get("customer_order_no"))
                or _string_or_none(supplier_fields.get("customer_po"))
                or _string_or_none(supplier_fields.get("order_no"))
                or (_string_or_none(supplier_fields.get("customer_order_number")) if supplier_key == "neuman" else None)
                or (_string_or_none(supplier_fields.get("ordine_cliente")) if supplier_key == "metalba" else None)
                or _string_or_none(supplier_fields.get("po_no"))
            )
            certificate_delivery_note = (
                _string_or_none(supplier_fields.get("delivery_note_no"))
                or _string_or_none(supplier_fields.get("tally_sheet_no"))
                or _string_or_none(cast(dict[str, object], certificate_matches.get("ddt_certificato") or {}).get("final"))
            )
            if supplier_key == "impol":
                certificate_diameter = certificate_diameter or _string_or_none(supplier_fields.get("diameter"))
                certificate_cast = certificate_cast or _string_or_none(supplier_fields.get("charge"))
                certificate_weight = certificate_weight or _string_or_none(supplier_fields.get("net_weight"))
            elif supplier_key == "metalba":
                certificate_alloy = certificate_alloy or _normalize_metalba_alloy_from_text(
                    _string_or_none(supplier_fields.get("product_description_raw")) or _string_or_none(supplier_fields.get("alloy"))
                )
                certificate_diameter = certificate_diameter or _string_or_none(supplier_fields.get("diameter"))
                certificate_weight = certificate_weight or _string_or_none(supplier_fields.get("net_weight"))
            elif supplier_key == "neuman":
                certificate_number = certificate_number or _string_or_none(supplier_fields.get("lot_number"))
                certificate_cast = certificate_cast or _string_or_none(supplier_fields.get("lot_number"))
                certificate_alloy = certificate_alloy or _string_or_none(supplier_fields.get("alloy"))
                certificate_diameter = certificate_diameter or _string_or_none(supplier_fields.get("diameter"))
                certificate_weight = certificate_weight or _string_or_none(supplier_fields.get("weight"))
            elif supplier_key == "aww":
                certificate_alloy = certificate_alloy or _string_or_none(supplier_fields.get("alloy"))
                certificate_diameter = certificate_diameter or _string_or_none(supplier_fields.get("diameter"))
                certificate_weight = certificate_weight or _string_or_none(supplier_fields.get("weight"))
            certificate_packing_list = (
                _string_or_none(supplier_fields.get("packing_list_no"))
                or _string_or_none(supplier_fields.get("packing_slip_no"))
            )
            certificate_supplier_order = (
                _string_or_none(supplier_fields.get("supplier_order_no"))
                or _string_or_none(supplier_fields.get("sales_order_number"))
                or (_string_or_none(supplier_fields.get("auftragsbestaetigung_root")) if supplier_key == "aww" else None)
            )

        if not any((certificate_number, certificate_article, certificate_customer_order, certificate_cast, certificate_packing_list, certificate_supplier_order)):
            continue
        certificate_cdq = certificate_number if supplier_key != "aww" else None
        certificate_signature = _certificate_first_signature(
            fornitore_id=certificate_document.fornitore_id,
            cdq=certificate_cdq,
            ordine=certificate_customer_order,
            article=certificate_article,
            profile_code=certificate_profile_code,
            lega=certificate_alloy,
            diametro=certificate_diameter,
            colata=certificate_cast,
            peso=certificate_weight,
        )
        linked_row = _find_existing_row_for_certificate(
            db=db,
            supplier_key=supplier_key,
            supplier_id=certificate_document.fornitore_id,
            certificate_number=certificate_number,
            article=certificate_article,
            profile_code=certificate_profile_code,
            customer_order=certificate_customer_order,
            alloy=certificate_alloy,
            diameter=certificate_diameter,
            cast=certificate_cast,
            weight=certificate_weight,
            packing_list=certificate_packing_list,
            supplier_order=certificate_supplier_order,
        )
        if linked_row is not None:
            if linked_row.document_certificato_id is None:
                upsert_match(
                    db=db,
                    row=linked_row,
                    payload=MatchUpsertRequest(
                        document_certificato_id=certificate_document.id,
                        stato="proposto",
                        motivo_breve="Collegato automaticamente da certificate-first",
                        fonte_proposta="sistema",
                        candidates=[
                            MatchCandidateRequest(
                                document_certificato_id=certificate_document.id,
                                rank=1,
                                motivo_breve="Collegato automaticamente da certificate-first",
                                fonte_proposta="sistema",
                                stato="scelto",
                            )
                        ],
                    ),
                    actor_id=actor_id,
                )
                if not (use_ai_intervention and openai_api_key):
                    extract_core_fields(db=db, row=get_acquisition_row(db, linked_row.id), actor_id=actor_id)
                linked_row = _process_certificate_side_blocks(
                    db=db,
                    row=get_acquisition_row(db, linked_row.id),
                    actor_id=actor_id,
                    openai_api_key=openai_api_key,
                    use_ai_intervention=use_ai_intervention,
                    certificate_ai_cache=certificate_ai_cache,
                )
                linked_match_count += 1
            continue
        duplicate_row = next(
            (
                row
                for row in db.query(AcquisitionRow)
                .filter(
                    AcquisitionRow.document_ddt_id.is_(None),
                    AcquisitionRow.fornitore_id == certificate_document.fornitore_id,
                )
                .all()
                if _certificate_first_signature_from_row(row) == certificate_signature
            ),
            None,
        )
        if duplicate_row is not None:
            if duplicate_row.document_certificato_id is None:
                upsert_match(
                    db=db,
                    row=duplicate_row,
                    payload=MatchUpsertRequest(
                        document_certificato_id=certificate_document.id,
                        stato="proposto",
                        motivo_breve="Collegato automaticamente da certificate-first",
                        fonte_proposta="sistema",
                        candidates=[
                            MatchCandidateRequest(
                                document_certificato_id=certificate_document.id,
                                rank=1,
                                motivo_breve="Collegato automaticamente da certificate-first",
                                fonte_proposta="sistema",
                                stato="scelto",
                            )
                        ],
                    ),
                    actor_id=actor_id,
                )
                if not (use_ai_intervention and openai_api_key):
                    extract_core_fields(db=db, row=get_acquisition_row(db, duplicate_row.id), actor_id=actor_id)
                duplicate_row = _process_certificate_side_blocks(
                    db=db,
                    row=get_acquisition_row(db, duplicate_row.id),
                    actor_id=actor_id,
                    openai_api_key=openai_api_key,
                    use_ai_intervention=use_ai_intervention,
                    certificate_ai_cache=certificate_ai_cache,
                )
            continue

        created_row = create_acquisition_row(
            db=db,
            payload=AcquisitionRowCreateRequest(
                document_ddt_id=None,
                document_certificato_id=certificate_document.id,
                fornitore_id=certificate_document.fornitore_id,
                fornitore_raw=certificate_document.supplier.ragione_sociale if certificate_document.supplier is not None else None,
                cdq=certificate_cdq,
                lega_base=certificate_alloy,
                diametro=certificate_diameter,
                colata=certificate_cast,
                ddt=certificate_delivery_note,
                peso=certificate_weight,
                ordine=certificate_customer_order if _supplier_certificate_first_keeps_row_order(supplier_key) else None,
                note_documento="Certificato caricato in attesa del DDT",
                stato_tecnico="rosso",
                stato_workflow="nuova",
                priorita_operativa="media",
            ),
            actor_id=actor_id,
            actor_email=actor_email,
        )
        created_row_model = get_acquisition_row(db, created_row.id)
        if not (use_ai_intervention and openai_api_key):
            extract_core_fields(db=db, row=created_row_model, actor_id=actor_id)
        created_row_model = _process_certificate_side_blocks(
            db=db,
            row=get_acquisition_row(db, created_row.id),
            actor_id=actor_id,
            openai_api_key=openai_api_key,
            use_ai_intervention=use_ai_intervention,
            certificate_ai_cache=certificate_ai_cache,
        )
        created_count += 1

    return created_count, linked_match_count


def _find_existing_aluminium_bozen_row_for_certificate(
    *,
    rows: list[AcquisitionRow],
    certificate_number: str | None,
    article: str | None,
    profile_code: str | None,
    customer_order: str | None,
    alloy: str | None,
    diameter: str | None,
    cast: str | None,
    weight: str | None,
) -> AcquisitionRow | None:
    if not rows:
        return None

    normalized_cdq = reader_normalize_match_token(certificate_number)
    normalized_article = reader_normalize_match_token(article)
    normalized_profile_code = reader_normalize_match_token(profile_code)
    normalized_customer_order = reader_normalize_match_token(customer_order)
    normalized_cast = reader_normalize_match_token(cast)
    normalized_alloy = reader_normalize_match_token(alloy)
    normalized_diameter = reader_normalize_match_token(diameter)
    normalized_weight = reader_normalize_match_token(weight)

    def score(row: AcquisitionRow) -> int:
        total = 0
        row_identity_fields = _certificate_first_row_identity_fields(row)
        row_cdq = reader_normalize_match_token(row.cdq)
        row_article = reader_normalize_match_token(row_identity_fields.get("article"))
        row_profile_code = reader_normalize_match_token(
            row_identity_fields.get("profile_code") or row_identity_fields.get("customer_code")
        )
        row_customer_order = reader_normalize_match_token(row_identity_fields.get("customer_order"))
        row_cast = reader_normalize_match_token(row.colata)
        row_alloy = reader_normalize_match_token(row.lega_base)
        row_diameter = reader_normalize_match_token(row.diametro)
        row_weight = reader_normalize_match_token(row.peso)

        if normalized_cdq:
            if row_cdq and row_cdq != normalized_cdq:
                return -1
            if row_cdq == normalized_cdq:
                total += 200
        if normalized_article and row_article:
            if row_article != normalized_article:
                return -1
            total += 80
        if normalized_profile_code and row_profile_code:
            if row_profile_code != normalized_profile_code:
                return -1
            total += 60
        if normalized_customer_order and row_customer_order:
            if row_customer_order != normalized_customer_order:
                return -1
            total += 60
        if normalized_cast and row_cast:
            if row_cast != normalized_cast:
                return -1
            total += 80
        if normalized_alloy and row_alloy:
            if row_alloy != normalized_alloy:
                return -1
            total += 40
        if normalized_diameter and row_diameter:
            if row_diameter != normalized_diameter:
                return -1
            total += 40
        if normalized_weight and row_weight:
            if row_weight != normalized_weight:
                return -1
            total += 20
        return total

    scored = [(score(row), row) for row in rows]
    scored = [item for item in scored if item[0] >= 180]
    if not scored:
        return None
    scored.sort(key=lambda item: (-item[0], item[1].id))
    return scored[0][1]


def _find_existing_impol_row_for_certificate(
    *,
    rows: list[AcquisitionRow],
    customer_order: str | None,
    alloy: str | None,
    diameter: str | None,
    cast: str | None,
    weight: str | None,
    packing_list: str | None,
    supplier_order: str | None,
    product_code: str | None,
) -> AcquisitionRow | None:
    if not rows:
        return None

    normalized_customer_order = reader_normalize_match_token(customer_order)

    normalized_alloy = reader_normalize_match_token(alloy)
    normalized_diameter = reader_normalize_match_token(diameter)
    normalized_cast = reader_normalize_match_token(cast)
    normalized_packing_list = reader_normalize_match_token(normalize_impol_packing_list_root(packing_list))
    normalized_supplier_order = reader_normalize_match_token(supplier_order)
    normalized_product_code = reader_normalize_match_token(product_code)

    best_row: AcquisitionRow | None = None
    best_score = 0

    for row in rows:
        if row.document_ddt_id is None:
            continue

        ddt_values = {
            value.campo: _final_value_for_row(value)
            for value in row.values
            if value.blocco == "ddt"
        }
        supplier_fields = reader_extract_row_supplier_match_fields(
            row=row,
            ddt_values=ddt_values,
            supplier_key="impol",
        )

        row_customer_order = reader_normalize_match_token(
            supplier_fields.get("customer_order_no") or row.ordine
        )
        if row_customer_order != normalized_customer_order:
            continue

        score = 160
        row_alloy = reader_normalize_match_token(row.lega_base)
        row_diameter = reader_normalize_match_token(row.diametro)
        row_cast = reader_normalize_match_token(row.colata)
        row_weight_raw = _string_or_none(row.peso)

        material_match_count = 0
        available_material_signals = 0

        if normalized_alloy:
            available_material_signals += 1
            if row_alloy:
                if row_alloy != normalized_alloy:
                    continue
                score += 80
                material_match_count += 1

        if normalized_diameter:
            available_material_signals += 1
            if row_diameter:
                if row_diameter != normalized_diameter:
                    continue
                score += 80
                material_match_count += 1

        if normalized_cast:
            available_material_signals += 1
            if row_cast:
                if row_cast != normalized_cast:
                    continue
                score += 110
                material_match_count += 1

        if _string_or_none(weight):
            available_material_signals += 1
            if row_weight_raw:
                if not reader_weights_are_compatible(row_weight_raw, weight):
                    continue
                score += 70
                material_match_count += 1

        row_packing = reader_normalize_match_token(supplier_fields.get("packing_list_no"))
        row_supplier_order = reader_normalize_match_token(supplier_fields.get("supplier_order_no"))
        row_product_code = reader_normalize_match_token(supplier_fields.get("product_code"))

        if normalized_packing_list and row_packing == normalized_packing_list:
            score += 35
        if normalized_supplier_order and row_supplier_order == normalized_supplier_order:
            score += 30
        if normalized_product_code and row_product_code == normalized_product_code:
            score += 30

        required_material_matches = min(3, available_material_signals)
        if material_match_count < required_material_matches:
            continue

        if score > best_score:
            best_score = score
            best_row = row

    if best_score >= 260:
        return best_row
    return None


def _find_existing_metalba_row_for_certificate(
    *,
    rows: list[AcquisitionRow],
    customer_order: str | None,
    alloy: str | None,
    diameter: str | None,
    weight: str | None,
) -> AcquisitionRow | None:
    if not rows:
        return None

    normalized_customer_order = reader_normalize_match_token(customer_order)
    if not normalized_customer_order:
        return None

    normalized_alloy = reader_normalize_match_token(alloy)
    normalized_diameter = reader_normalize_match_token(diameter)

    best_row: AcquisitionRow | None = None
    best_score = 0

    for row in rows:
        if row.document_ddt_id is None:
            continue

        ddt_values = {
            value.campo: _final_value_for_row(value)
            for value in row.values
            if value.blocco == "ddt"
        }
        supplier_fields = reader_extract_row_supplier_match_fields(
            row=row,
            ddt_values=ddt_values,
            supplier_key="metalba",
        )

        row_vs_rif = reader_normalize_match_token(
            supplier_fields.get("vs_rif") or row.ordine
        )
        if row_vs_rif != normalized_customer_order:
            continue

        score = 160
        material_match_count = 0
        available_material_signals = 0

        row_diameter = reader_normalize_match_token(row.diametro)
        if normalized_diameter:
            available_material_signals += 1
            if row_diameter:
                if row_diameter != normalized_diameter:
                    continue
                score += 55
                material_match_count += 1

        row_alloy = reader_normalize_match_token(row.lega_base)
        if normalized_alloy:
            available_material_signals += 1
            if row_alloy:
                if row_alloy != normalized_alloy:
                    continue
                score += 45
                material_match_count += 1

        row_weight_raw = _string_or_none(row.peso)
        if _string_or_none(weight):
            available_material_signals += 1
            if row_weight_raw:
                if not reader_weights_are_compatible(row_weight_raw, weight):
                    continue
                score += 35
                material_match_count += 1

        required_material_matches = min(2, available_material_signals)
        if material_match_count < required_material_matches:
            continue

        if score > best_score:
            best_score = score
            best_row = row

    if best_score >= 230:
        return best_row
    return None


def _find_existing_neuman_row_for_certificate(
    *,
    rows: list[AcquisitionRow],
    article: str | None,
    customer_order: str | None,
    alloy: str | None,
    diameter: str | None,
    cast: str | None,
    weight: str | None,
) -> AcquisitionRow | None:
    if not rows:
        return None

    normalized_article = reader_normalize_match_token(article)
    normalized_customer_order = reader_normalize_match_token(customer_order)
    normalized_alloy = reader_normalize_match_token(alloy)
    normalized_diameter = reader_normalize_match_token(diameter)
    normalized_cast = reader_normalize_match_token(cast)

    best_row: AcquisitionRow | None = None
    best_score = 0

    for row in rows:
        if row.document_ddt_id is None:
            continue

        ddt_values = {
            value.campo: _final_value_for_row(value)
            for value in row.values
            if value.blocco == "ddt"
        }
        supplier_fields = reader_extract_row_supplier_match_fields(
            row=row,
            ddt_values=ddt_values,
            supplier_key="neuman",
        )

        material_match_count = 0
        available_material_signals = 0
        score = 0

        row_article = reader_normalize_match_token(
            supplier_fields.get("customer_material_number")
            or _certificate_first_row_identity_fields(row).get("article")
        )
        if normalized_article:
            available_material_signals += 1
            if row_article:
                if row_article != normalized_article:
                    continue
                score += 120
                material_match_count += 1

        row_cast = reader_normalize_match_token(supplier_fields.get("lot_number") or row.colata or row.cdq)
        if normalized_cast:
            available_material_signals += 1
            if row_cast:
                if row_cast != normalized_cast:
                    continue
                score += 120
                material_match_count += 1

        row_alloy = reader_normalize_match_token(row.lega_base or supplier_fields.get("alloy"))
        if normalized_alloy:
            available_material_signals += 1
            if row_alloy:
                if row_alloy != normalized_alloy:
                    continue
                score += 70
                material_match_count += 1

        row_diameter = _string_or_none(row.diametro or supplier_fields.get("diameter"))
        if normalized_diameter:
            available_material_signals += 1
            if row_diameter:
                if not _supplier_decimal_tokens_match(row_diameter, diameter):
                    continue
                score += 70
                material_match_count += 1

        row_weight_raw = _string_or_none(row.peso or supplier_fields.get("weight"))
        if _string_or_none(weight):
            available_material_signals += 1
            if row_weight_raw:
                if not reader_neuman_weights_are_compatible(row_weight_raw, weight):
                    continue
                score += 55
                material_match_count += 1

        row_customer_order = reader_normalize_match_token(
            supplier_fields.get("customer_order_number") or row.ordine
        )
        if normalized_customer_order and row_customer_order:
            if row_customer_order != normalized_customer_order:
                continue
            score += 30

        required_material_matches = min(4, available_material_signals)
        if material_match_count < required_material_matches:
            continue

        if score > best_score:
            best_score = score
            best_row = row

    if best_score >= 300:
        return best_row
    return None


def _find_existing_aww_row_for_certificate(
    *,
    rows: list[AcquisitionRow],
    article: str | None,
    profile_code: str | None,
    customer_order: str | None,
    alloy: str | None,
    diameter: str | None,
    weight: str | None,
    supplier_order: str | None,
) -> AcquisitionRow | None:
    if not rows:
        return None

    normalized_article = reader_normalize_match_token(article)
    normalized_profile_code = reader_normalize_match_token(profile_code)
    normalized_customer_order = reader_normalize_match_token(customer_order)
    normalized_alloy = reader_normalize_match_token(alloy)
    normalized_diameter = reader_normalize_match_token(diameter)
    normalized_supplier_order = reader_normalize_match_token(supplier_order)

    best_row: AcquisitionRow | None = None
    best_score = 0

    for row in rows:
        if row.document_ddt_id is None:
            continue

        ddt_values = {
            value.campo: _final_value_for_row(value)
            for value in row.values
            if value.blocco == "ddt"
        }
        supplier_fields = reader_extract_row_supplier_match_fields(
            row=row,
            ddt_values=ddt_values,
            supplier_key="aww",
        )

        score = 0
        anchor_match_count = 0
        available_anchor_signals = 0

        row_article = reader_normalize_match_token(supplier_fields.get("your_part_number"))
        if normalized_article:
            available_anchor_signals += 1
            if row_article:
                if row_article != normalized_article:
                    continue
                score += 120
                anchor_match_count += 1

        row_profile_code = reader_normalize_match_token(supplier_fields.get("part_number"))
        if normalized_profile_code:
            available_anchor_signals += 1
            if row_profile_code:
                if row_profile_code != normalized_profile_code:
                    continue
                score += 110
                anchor_match_count += 1

        row_supplier_order = reader_normalize_match_token(supplier_fields.get("order_confirmation_root"))
        if normalized_supplier_order:
            available_anchor_signals += 1
            if row_supplier_order:
                if row_supplier_order != normalized_supplier_order:
                    continue
                score += 95
                anchor_match_count += 1

        support_match_count = 0
        available_support_signals = 0

        row_alloy = reader_normalize_match_token(row.lega_base or supplier_fields.get("alloy"))
        if normalized_alloy:
            available_support_signals += 1
            if row_alloy:
                if row_alloy != normalized_alloy:
                    continue
                score += 55
                support_match_count += 1

        row_diameter = _string_or_none(row.diametro or supplier_fields.get("diameter"))
        if normalized_diameter:
            available_support_signals += 1
            if row_diameter:
                if not _supplier_decimal_tokens_match(row_diameter, diameter):
                    continue
                score += 45
                support_match_count += 1

        row_weight_raw = _string_or_none(row.peso or supplier_fields.get("weight"))
        if _string_or_none(weight):
            available_support_signals += 1
            if row_weight_raw:
                if not reader_weights_are_compatible(row_weight_raw, weight):
                    continue
                score += 25
                support_match_count += 1

        row_customer_order = reader_normalize_match_token(
            _string_or_none(row.ordine) or supplier_fields.get("customer_order_no")
        )
        if normalized_customer_order and row_customer_order and row_customer_order == normalized_customer_order:
            score += 20

        required_anchor_matches = min(2, available_anchor_signals)
        if required_anchor_matches == 0 or anchor_match_count < required_anchor_matches:
            continue

        required_support_matches = min(2, available_support_signals)
        if available_support_signals and support_match_count < required_support_matches:
            continue

        if score > best_score:
            best_score = score
            best_row = row

    if best_score >= 230:
        return best_row
    return None


def _find_existing_leichtmetall_row_for_certificate(
    *,
    rows: list[AcquisitionRow],
    customer_order: str | None,
    alloy: str | None,
    diameter: str | None,
    cast: str | None,
    weight: str | None,
) -> AcquisitionRow | None:
    if not rows:
        return None

    normalized_customer_order = reader_normalize_match_token(customer_order)
    if not normalized_customer_order:
        return None

    normalized_alloy = reader_normalize_match_token(alloy)
    normalized_diameter = reader_normalize_match_token(diameter)
    normalized_cast = reader_normalize_match_token(cast)

    best_row: AcquisitionRow | None = None
    best_score = 0

    for row in rows:
        if row.document_ddt_id is None:
            continue

        ddt_values = {
            value.campo: _final_value_for_row(value)
            for value in row.values
            if value.blocco == "ddt"
        }
        supplier_fields = reader_extract_row_supplier_match_fields(
            row=row,
            ddt_values=ddt_values,
            supplier_key="leichtmetall",
        )

        row_customer_order = reader_normalize_match_token(
            supplier_fields.get("po_no") or supplier_fields.get("customer_order_no") or row.ordine
        )
        if normalized_customer_order and row_customer_order and row_customer_order != normalized_customer_order:
            continue

        score = 160 if normalized_customer_order and row_customer_order else 0
        material_match_count = 0
        available_material_signals = 0

        if normalized_alloy:
            available_material_signals += 1
            row_alloy = reader_normalize_match_token(row.lega_base)
            if row_alloy:
                if row_alloy != normalized_alloy:
                    continue
                score += 70
                material_match_count += 1

        if normalized_diameter:
            available_material_signals += 1
            row_diameter = _string_or_none(row.diametro)
            if row_diameter:
                if not _supplier_decimal_tokens_match(row_diameter, diameter):
                    continue
                score += 70
                material_match_count += 1

        if normalized_cast:
            available_material_signals += 1
            row_cast = reader_normalize_match_token(
                supplier_fields.get("charge_cast_no") or row.colata or row.cdq
            )
            if row_cast:
                if row_cast != normalized_cast:
                    continue
                score += 120
                material_match_count += 1

        if _string_or_none(weight):
            available_material_signals += 1
            if row.peso:
                if not reader_weights_are_compatible(row.peso, weight):
                    continue
                score += 65
                material_match_count += 1

        required_material_matches = min(4 if not (normalized_customer_order and row_customer_order) else 3, available_material_signals)
        if material_match_count < required_material_matches:
            continue

        if score > best_score:
            best_score = score
            best_row = row

    if best_score >= (260 if normalized_customer_order else 280):
        return best_row
    return None


def _find_existing_row_for_certificate(
    db: Session,
    *,
    supplier_key: str | None,
    supplier_id: int | None,
    certificate_number: str | None,
    article: str | None,
    profile_code: str | None,
    customer_order: str | None,
    alloy: str | None,
    diameter: str | None,
    cast: str | None,
    weight: str | None,
    packing_list: str | None,
    supplier_order: str | None,
) -> AcquisitionRow | None:
    candidate_rows = _candidate_rows_for_incoming_certificate_link(
        db,
        supplier_id=supplier_id,
    )
    if supplier_key == "aluminium_bozen":
        return _find_existing_aluminium_bozen_row_for_certificate(
            rows=candidate_rows,
            certificate_number=certificate_number,
            article=article,
            profile_code=profile_code,
            customer_order=customer_order,
            alloy=alloy,
            diameter=diameter,
            cast=cast,
            weight=weight,
        )
    if supplier_key == "impol":
        return _find_existing_impol_row_for_certificate(
            rows=candidate_rows,
            customer_order=customer_order,
            alloy=alloy,
            diameter=diameter,
            cast=cast,
            weight=weight,
            packing_list=packing_list,
            supplier_order=supplier_order,
            product_code=article,
        )
    if supplier_key == "leichtmetall":
        return _find_existing_leichtmetall_row_for_certificate(
            rows=candidate_rows,
            customer_order=customer_order,
            alloy=alloy,
            diameter=diameter,
            cast=cast,
            weight=weight,
        )
    if supplier_key == "metalba":
        return _find_existing_metalba_row_for_certificate(
            rows=candidate_rows,
            customer_order=customer_order,
            alloy=alloy,
            diameter=diameter,
            weight=weight,
        )
    if supplier_key == "neuman":
        return _find_existing_neuman_row_for_certificate(
            rows=candidate_rows,
            article=article,
            customer_order=customer_order,
            alloy=alloy,
            diameter=diameter,
            cast=cast,
            weight=weight,
        )
    if supplier_key == "aww":
        return _find_existing_aww_row_for_certificate(
            rows=candidate_rows,
            article=article,
            profile_code=profile_code,
            customer_order=customer_order,
            alloy=alloy,
            diameter=diameter,
            weight=weight,
            supplier_order=supplier_order,
        )
    return None


def _certificate_first_signature(
    *,
    fornitore_id: int | None,
    cdq: str | None,
    ordine: str | None,
    article: str | None,
    profile_code: str | None,
    lega: str | None,
    diametro: str | None,
    colata: str | None,
    peso: str | None,
) -> tuple[str | int | None, ...]:
    return (
        fornitore_id,
        reader_normalize_match_token(cdq),
        reader_normalize_match_token(ordine),
        reader_normalize_match_token(article),
        reader_normalize_match_token(profile_code),
        reader_normalize_match_token(lega),
        reader_normalize_match_token(diametro),
        reader_normalize_match_token(colata),
        reader_normalize_match_token(peso),
    )


def _certificate_first_signature_from_row(row: AcquisitionRow) -> tuple[str | int | None, ...]:
    identity_fields = _certificate_first_row_identity_fields(row)
    return _certificate_first_signature(
        fornitore_id=row.fornitore_id,
        cdq=row.cdq,
        ordine=identity_fields.get("customer_order"),
        article=identity_fields.get("article"),
        profile_code=identity_fields.get("profile_code") or identity_fields.get("customer_code"),
        lega=row.lega_base or row.lega_designazione or row.variante_lega,
        diametro=row.diametro,
        colata=row.colata,
        peso=row.peso,
    )


def _certificate_first_row_identity_fields(row: AcquisitionRow) -> dict[str, str | None]:
    ddt_values = {
        value.campo: _final_value_for_row(value)
        for value in row.values
        if value.blocco == "ddt"
    }
    match_values = {
        value.campo: _final_value_for_row(value)
        for value in row.values
        if value.blocco == "match"
    }
    return {
        "article": _string_or_none(ddt_values.get("article_code")) or _string_or_none(match_values.get("articolo_certificato")),
        "profile_code": _string_or_none(ddt_values.get("profile_code"))
        or _string_or_none(ddt_values.get("customer_code"))
        or _string_or_none(match_values.get("codice_cliente_certificato")),
        "customer_order": _string_or_none(ddt_values.get("customer_order_no"))
        or _string_or_none(match_values.get("ordine_cliente_certificato"))
        or _string_or_none(row.ordine),
    }


def _certificate_match_values_map(row: AcquisitionRow) -> dict[str, str | None]:
    return {
        value.campo: _final_value_for_row(value)
        for value in row.values
        if value.blocco == "match"
    }


def _certificate_link_payload_from_row(
    row: AcquisitionRow,
    *,
    supplier_key: str | None,
) -> dict[str, str | None]:
    identity_fields = _certificate_first_row_identity_fields(row)
    match_values = _certificate_match_values_map(row)
    profile_code = (
        _string_or_none(match_values.get("profile_code_certificato"))
        or _string_or_none(match_values.get("codice_cliente_certificato"))
        or identity_fields.get("profile_code")
    )
    supplier_order = _string_or_none(match_values.get("supplier_order_no_certificato"))
    certificate_number = _string_or_none(row.cdq)
    packing_list = normalize_impol_packing_list_root(certificate_number) if supplier_key == "impol" else None
    return {
        "certificate_number": certificate_number,
        "article": identity_fields.get("article"),
        "profile_code": profile_code,
        "customer_order": identity_fields.get("customer_order"),
        "alloy": _row_high_alloy_value(row),
        "diameter": _string_or_none(row.diametro),
        "cast": _string_or_none(row.colata),
        "weight": _string_or_none(row.peso),
        "packing_list": packing_list,
        "supplier_order": supplier_order,
    }


def _certificate_supplier_fields_from_row(
    row: AcquisitionRow,
    *,
    supplier_key: str | None,
) -> dict[str, str | None]:
    match_values = _certificate_match_values_map(row)
    payload = _certificate_link_payload_from_row(row, supplier_key=supplier_key)
    if supplier_key == "metalba":
        return {
            "ordine_cliente": payload["customer_order"],
        }
    if supplier_key == "leichtmetall":
        return {
            "po_no": payload["customer_order"],
            "customer_order_no": payload["customer_order"],
            "charge_cast_no": payload["cast"] or payload["certificate_number"],
            "alloy": payload["alloy"],
            "diameter": payload["diameter"],
            "weight": payload["weight"],
        }
    if supplier_key == "aww":
        return {
            "kunden_teile_nr": payload["article"],
            "artikel_nr": payload["profile_code"],
            "auftragsbestaetigung_root": payload["supplier_order"],
            "customer_order_no": payload["customer_order"],
            "alloy": payload["alloy"],
            "diameter": payload["diameter"],
            "weight": payload["weight"],
        }
    if supplier_key == "aluminium_bozen":
        return {
            "article": payload["article"],
            "profile_code": payload["profile_code"],
            "customer_order_normalized": payload["customer_order"],
        }
    if supplier_key == "neuman":
        return {
            "delivery_note_no": _string_or_none(row.ddt),
            "lot_number": payload["cast"] or payload["certificate_number"],
            "customer_material_number": payload["article"],
            "customer_order_number": payload["customer_order"],
            "alloy": payload["alloy"],
            "diameter": payload["diameter"],
            "weight": payload["weight"],
        }
    if supplier_key == "impol":
        return {
            "packing_list_no": payload["packing_list"],
            "customer_order_no": payload["customer_order"],
            "supplier_order_no": payload["supplier_order"],
            "product_code": payload["article"],
            "charge": payload["cast"],
            "diameter": payload["diameter"],
            "net_weight": payload["weight"],
        }
    return {
        "numero_certificato_certificato": payload["certificate_number"],
        "ordine_cliente_certificato": payload["customer_order"],
        "lega_certificato": payload["alloy"],
        "diametro_certificato": payload["diameter"],
        "colata_certificato": payload["cast"],
        "peso_certificato": payload["weight"],
        "profile_code_certificato": _string_or_none(match_values.get("profile_code_certificato")),
        "supplier_order_no_certificato": _string_or_none(match_values.get("supplier_order_no_certificato")),
    }


def _candidate_row_matches_certificate_row(
    *,
    candidate_row: AcquisitionRow,
    supplier_key: str | None,
    certificate_payload: dict[str, str | None],
) -> bool:
    rows = [candidate_row]
