def _mask_words_before_anchor(
    image: Image.Image,
    words: list[dict[str, int | str | tuple[int, int, int]]],
    *,
    anchor_terms: tuple[str, ...],
    top_extra: int = 0,
    bottom_extra: int = 0,
) -> bool:
    texts = [str(word["text"]).upper() for word in words]
    anchor_index = next(
        (
            index
            for index, text in enumerate(texts)
            if any(term in text for term in anchor_terms)
        ),
        None,
    )
    if anchor_index is None or anchor_index <= 0:
        return False
    _mask_word_group(
        image,
        words[:anchor_index],
        top_extra=top_extra,
        bottom_extra=bottom_extra,
    )
    return True


def _mask_words_from_anchor(
    image: Image.Image,
    words: list[dict[str, int | str | tuple[int, int, int]]],
    *,
    anchor_terms: tuple[str, ...],
    top_extra: int = 0,
    bottom_extra: int = 0,
) -> bool:
    texts = [str(word["text"]).upper() for word in words]
    anchor_index = next(
        (
            index
            for index, text in enumerate(texts)
            if any(term in text for term in anchor_terms)
        ),
        None,
    )
    if anchor_index is None:
        return False
    _mask_word_group(
        image,
        words[anchor_index:],
        top_extra=top_extra,
        bottom_extra=bottom_extra,
    )
    return True


def _mask_words_after_anchor(
    image: Image.Image,
    words: list[dict[str, int | str | tuple[int, int, int]]],
    *,
    anchor_terms: tuple[str, ...],
    top_extra: int = 0,
    bottom_extra: int = 0,
    max_gap: int | None = None,
) -> bool:
    texts = [str(word["text"]).upper() for word in words]
    anchor_index = next(
        (
            index
            for index, text in enumerate(texts)
            if any(term in text for term in anchor_terms)
        ),
        None,
    )
    if anchor_index is None or anchor_index + 1 >= len(words):
        return False
    tail_words = words[anchor_index + 1 :]
    while tail_words and str(tail_words[0]["text"]).strip() in {":", "-", ".", "/"}:
        tail_words = tail_words[1:]
    if not tail_words:
        return False
    if max_gap is None:
        max_gap = max(18, image.width // 35)
    contiguous_words = [tail_words[0]]
    previous_right = int(tail_words[0]["right"])
    for word in tail_words[1:]:
        gap = int(word["left"]) - previous_right
        if gap > max_gap:
            break
        contiguous_words.append(word)
        previous_right = int(word["right"])
    _mask_word_group(
        image,
        contiguous_words,
        top_extra=top_extra,
        bottom_extra=bottom_extra,
    )
    return True


def _mask_words_between_anchors(
    image: Image.Image,
    words: list[dict[str, int | str | tuple[int, int, int]]],
    *,
    start_terms: tuple[str, ...],
    stop_terms: tuple[str, ...],
    top_extra: int = 0,
    bottom_extra: int = 0,
) -> bool:
    texts = [str(word["text"]).upper() for word in words]
    start_index = next(
        (
            index
            for index, text in enumerate(texts)
            if any(term in text for term in start_terms)
        ),
        None,
    )
    if start_index is None:
        return False
    stop_index = next(
        (
            index
            for index, text in enumerate(texts[start_index + 1 :], start=start_index + 1)
            if any(term in text for term in stop_terms)
        ),
        None,
    )
    if stop_index is None or stop_index <= start_index:
        return False
    _mask_word_group(
        image,
        words[start_index:stop_index],
        top_extra=top_extra,
        bottom_extra=bottom_extra,
    )
    return True


def _mask_contiguous_words_from_anchor(
    image: Image.Image,
    words: list[dict[str, int | str | tuple[int, int, int]]],
    *,
    anchor_terms: tuple[str, ...],
    stop_terms: tuple[str, ...] = (),
    top_extra: int = 0,
    bottom_extra: int = 0,
    max_gap: int | None = None,
) -> bool:
    texts = [str(word["text"]).upper() for word in words]
    start_index = next(
        (
            index
            for index, text in enumerate(texts)
            if any(term in text for term in anchor_terms)
        ),
        None,
    )
    if start_index is None:
        return False
    if max_gap is None:
        max_gap = max(14, image.width // 45)
    end_index = start_index
    previous_right = int(words[start_index]["right"])
    for index in range(start_index + 1, len(words)):
        text = texts[index]
        if any(term in text for term in stop_terms):
            break
        gap = int(words[index]["left"]) - previous_right
        if gap > max_gap:
            break
        end_index = index
        previous_right = int(words[index]["right"])
    _mask_word_group(
        image,
        words[start_index : end_index + 1],
        top_extra=top_extra,
        bottom_extra=bottom_extra,
    )
    return True


