def _mask_neuman_customer_occurrence_blocks(
    image: Image.Image,
    lines: list[dict[str, int | str]],
) -> None:
    words = _extract_ocr_word_blocks(image)
    if not words:
        return
    is_certificate_page = any("INSPECTION CERTIFICATE" in str(line["text"]).upper() for line in lines)
    line_map = _group_ocr_words_by_line(words)
    stop_terms = (
        "DELIVERY NOTE",
        "LOAD",
        "CUSTOMER ORDER NUMBER",
        "CONTRACT",
        "ART-NR",
        "PRODUCT:",
        "CUSTOMER MATERIAL NUMBER",
        "LOT NUMBER",
        "NET WEIGHT",
        "CHEMICAL",
    )
    customer_tokens = ("FORGIALLUMINIO", "ORGIALLUMINIO", "RGIALLUMINIO")
    address_tokens = ("ENRICO", "FERMI", "PEDAVENA", "32034", "ITALY", "WALTER")
    top_pad = max(3, image.height // 220)
    bottom_pad = max(5, image.height // 170)

    for line_words in line_map.values():
        line_text = " ".join(str(word["text"]).upper() for word in line_words)
        if any(term in line_text for term in stop_terms):
            continue

        top = int(line_words[0]["top"])
        if (
            not is_certificate_page
            and top <= int(image.height * 0.30)
            and "CUSTOMER" in line_text
            and "CUSTOMER ORDER NUMBER" not in line_text
        ):
            if _mask_words_after_anchor(
                image,
                line_words,
                anchor_terms=("CUSTOMER",),
                top_extra=top_pad,
                bottom_extra=bottom_pad,
            ):
                continue

        _mask_words_matching_terms(
            image,
            line_words,
            customer_tokens + address_tokens,
            top_extra=top_pad,
            bottom_extra=bottom_pad,
            left_extra=max(6, image.width // 320),
            right_extra=max(8, image.width // 280),
        )

    if not is_certificate_page:
        _mask_visual_content_in_relative_box(
            image,
            (0.78, 0.60, 0.98, 0.79),
            padding=max(6, image.width // 260),
            min_pixels=10,
            dilation_size=17,
        )


def _mask_neuman_supplier_occurrence_blocks(
    image: Image.Image,
    lines: list[dict[str, int | str]],
) -> None:
    words = _extract_ocr_word_blocks(image)
    if not words:
        return
    is_certificate_page = any("INSPECTION CERTIFICATE" in str(line["text"]).upper() for line in lines)
    line_map = _group_ocr_words_by_line(words)
    stop_terms = (
        "DELIVERY NOTE",
        "LOAD",
        "CUSTOMER ORDER NUMBER",
        "CONTRACT",
        "ART-NR",
        "PRODUCT:",
        "LOT NUMBER",
        "NET WEIGHT",
        "CHEMICAL",
    )
    supplier_tokens = ("NEUMAN", "ALUMINIUM", "AUSTRIA", "CASTING", "WERKSTRASSE", "MARKTL", "@NEUMAN", "WWW.NEUMAN.AT")
    top_pad = max(3, image.height // 220)
    bottom_pad = max(5, image.height // 170)

    for line_words in line_map.values():
        line_text = " ".join(str(word["text"]).upper() for word in line_words)
        if any(term in line_text for term in stop_terms):
            continue

        sensitive_words = [
            word
            for word in line_words
            if any(token in str(word["text"]).upper() for token in supplier_tokens)
        ]
        if not sensitive_words:
            continue

        top = min(int(word["top"]) for word in sensitive_words)
        right = max(int(word["right"]) for word in sensitive_words)

        if top <= int(image.height * 0.22) and right >= int(image.width * 0.55):
            _mask_word_group(
                image,
                sensitive_words,
                left_extra=max(6, image.width // 320),
                right_extra=max(10, image.width // 220),
                top_extra=max(top_pad, image.height // 220),
                bottom_extra=max(bottom_pad, image.height // 200),
            )
            continue

        _mask_word_group(
            image,
            sensitive_words,
            top_extra=top_pad,
            bottom_extra=bottom_pad,
            left_extra=max(6, image.width // 320),
            right_extra=max(10, image.width // 220),
        )

    _mask_neuman_visual_logo_regions(image, is_certificate_page=is_certificate_page)


def _collect_occurrence_cluster(
    image: Image.Image,
    lines: list[dict[str, int | str]],
    start_line: dict[str, int | str],
    *,
    stop_terms: tuple[str, ...],
    stop_on_label: bool,
    max_preceding_lines: int,
    max_following_lines: int,
    left_limit: int,
    right_limit: int,
    max_vertical_gap: int | None = None,
) -> list[dict[str, int | str]]:
    start_index = next((index for index, line in enumerate(lines) if line is start_line), None)
    if start_index is None:
        return []
    cluster = [start_line]
    vertical_gap_limit = max_vertical_gap or max(18, image.height // 35)
    previous_top = int(start_line["top"])
    for line in reversed(lines[max(0, start_index - max_preceding_lines) : start_index]):
        text = str(line["text"]).upper()
        if any(term in text for term in stop_terms):
            break
        if stop_on_label and ":" in text:
            break
        if previous_top - int(line["bottom"]) > vertical_gap_limit:
            break
        if int(line["left"]) > right_limit or int(line["right"]) < left_limit:
            continue
        cluster.insert(0, line)
        previous_top = int(line["top"])
    previous_bottom = int(start_line["bottom"])
    for line in lines[start_index + 1 : start_index + 1 + max_following_lines]:
        text = str(line["text"]).upper()
        if any(term in text for term in stop_terms):
            break
        if stop_on_label and ":" in text:
            break
        if int(line["top"]) - previous_bottom > vertical_gap_limit:
            break
        if int(line["left"]) > right_limit or int(line["right"]) < left_limit:
            continue
        cluster.append(line)
        previous_bottom = int(line["bottom"])
    return cluster


def _mask_line_cluster(
    image: Image.Image,
    cluster: list[dict[str, int | str]],
    *,
    left_limit: int | None = None,
    right_limit: int | None = None,
    top_extra: int = 0,
    left_extra: int = 0,
    right_extra: int = 0,
    bottom_extra: int = 0,
) -> None:
    if not cluster:
        return
    left = max(0, min(int(line["left"]) for line in cluster) - max(10, image.width // 250) - left_extra)
    top = max(0, min(int(line["top"]) for line in cluster) - max(6, image.height // 300) - top_extra)
    right = max(int(line["right"]) for line in cluster) + max(12, image.width // 220) + right_extra
    bottom = min(
        image.height - 1,
        max(int(line["bottom"]) for line in cluster) + max(8, image.height // 260) + bottom_extra,
    )
    if left_limit is not None:
        left = max(left, left_limit)
    if right_limit is not None:
        right = min(right, right_limit)
    if right <= left or bottom <= top:
        return
    draw = ImageDraw.Draw(image)
    draw.rectangle((left, top, right, bottom), fill="black")


def _find_table_header_bottom(
    lines: list[dict[str, int | str]],
    *,
    required_terms: tuple[str, ...],
) -> int | None:
    normalized_required = tuple(term.upper() for term in required_terms)
    for line in lines:
        text = str(line["text"]).upper()
        if all(term in text for term in normalized_required):
            return int(line["bottom"])
    matched_bottoms: list[int] = []
    matched_terms: set[str] = set()
    for line in lines:
        text = str(line["text"]).upper()
        line_matches = [term for term in normalized_required if term in text]
        if not line_matches:
            continue
        matched_terms.update(line_matches)
        matched_bottoms.append(int(line["bottom"]))
    if all(term in matched_terms for term in normalized_required) and matched_bottoms:
        return max(matched_bottoms)
    return None


def _extract_primary_anchor_term(text: str) -> str | None:
    for token in re.findall(r"[A-Z0-9]{5,}", text.upper()):
        if token not in {"ITALY", "SLOVENIA", "ADDRESS", "CUSTOMER"}:
            return token
    return None

