def _sanitize_leichtmetall_ai_row_groups(
    *,
    ddt_number_raw: str | None,
    raw_rows: list[dict[str, object]],
    ai_document_payload_raw: str | None = None,
) -> list[ReaderRowSplitCandidateResponse]:
    sanitized_rows: list[ReaderRowSplitCandidateResponse] = []
    normalized_ddt = _sanitize_leichtmetall_ddt_number_candidate(ddt_number_raw)

    for index, raw_row in enumerate(raw_rows, start=1):
        purchase_number_raw = _string_or_none(raw_row.get("purchase_number_raw"))
        order_confirmation_raw = _string_or_none(raw_row.get("order_confirmation_raw"))
        alloy_raw = _string_or_none(raw_row.get("alloy_raw"))
        diameter_raw = _string_or_none(raw_row.get("diameter_raw"))
        batch_raw = _string_or_none(raw_row.get("batch_raw"))
        net_weight_raw = _string_or_none(raw_row.get("net_weight_raw"))
        source_crops = cast(list[str], raw_row.get("source_crops") or [])

        order_value = _normalize_leichtmetall_order_token(purchase_number_raw)
        batch_value = _normalize_leichtmetall_batch_token(batch_raw)
        alloy_value = _normalize_leichtmetall_alloy_from_text(alloy_raw)
        diameter_value = _normalize_leichtmetall_diameter_from_text(diameter_raw)
        weight_value = _normalize_value_for_field("ddt", "peso", net_weight_raw)

        raw_payload = dict(raw_row)
        raw_payload["purchase_number_raw"] = purchase_number_raw
        raw_payload["order_confirmation_raw"] = order_confirmation_raw

        candidate = ReaderRowSplitCandidateResponse(
            candidate_index=index,
            supplier_key="leichtmetall",
            ddt_number=normalized_ddt,
            cdq=batch_value,
            customer_order_no=order_value,
            supplier_order_no=_string_or_none(order_confirmation_raw),
            lega=alloy_value,
            diametro=diameter_value,
            peso_netto=weight_value,
            colata=batch_value,
            lot_batch_no=batch_value,
            snippets=source_crops[:6],
            ai_row_payload_raw=json.dumps(raw_payload, ensure_ascii=False),
            ai_document_payload_raw=ai_document_payload_raw,
        )

        if any(
            getattr(candidate, field_name) is not None
            for field_name in (
                "ddt_number",
                "customer_order_no",
                "cdq",
                "lega",
                "diametro",
                "peso_netto",
                "colata",
            )
        ):
            sanitized_rows.append(candidate)

    return sanitized_rows


def _reconcile_leichtmetall_ai_candidates_with_document(
    *,
    ddt_document: Document,
    ai_candidates: list[ReaderRowSplitCandidateResponse],
) -> list[ReaderRowSplitCandidateResponse]:
    if not ai_candidates:
        return []

    batch_groups = _extract_leichtmetall_batch_groups(ddt_document)
    if batch_groups:
        first_page = next((page for page in ddt_document.pages if page.numero_pagina == 1), ddt_document.pages[0])
        first_page_lines = [reader_normalize_line(line) for line in reader_page_lines(first_page)]
        header_weight = _extract_leichtmetall_header_weight(first_page_lines)
        header_total = _parse_leichtmetall_weight_token(header_weight)
        if header_total is not None:
            if len(batch_groups) == 1:
                only_batch_payload = next(iter(batch_groups.values()))
                only_batch_payload["weight_total"] = header_total
            else:
                grouped_total = sum(int(payload.get("weight_total", 0)) for payload in batch_groups.values())
                if 0 < grouped_total < header_total:
                    dominant_batch_payload = max(
                        batch_groups.values(),
                        key=lambda payload: (
                            int(payload.get("weight_total", 0)),
                            len(list(payload.get("snippets", []))),
                        ),
                    )
                    dominant_batch_payload["weight_total"] = int(dominant_batch_payload.get("weight_total", 0)) + (
                        header_total - grouped_total
                    )

    merged: dict[tuple[str | None, str | None, str | None, str | None, str | None], ReaderRowSplitCandidateResponse] = {}
    merged_raw_payloads: dict[tuple[str | None, str | None, str | None, str | None, str | None], list[object]] = {}

    for candidate in ai_candidates:
        batch_key = _string_or_none(candidate.colata or candidate.cdq or candidate.lot_batch_no)
        order_key = _string_or_none(candidate.customer_order_no)
        alloy_key = _string_or_none(candidate.lega)
        diameter_key = _string_or_none(candidate.diametro)
        ddt_key = _string_or_none(candidate.ddt_number)
        key = (ddt_key, order_key, batch_key, alloy_key, diameter_key)

        reconciled_weight = None
        if batch_key and batch_key in batch_groups:
            weight_total = int(batch_groups[batch_key].get("weight_total", 0))
            if weight_total > 0:
                reconciled_weight = _format_leichtmetall_weight(weight_total)

        existing = merged.get(key)
        if existing is None:
            if reconciled_weight is not None:
                candidate.peso_netto = reconciled_weight
            merged[key] = candidate
            raw_payloads: list[object] = []
            if candidate.ai_row_payload_raw:
                try:
                    raw_payloads.append(json.loads(candidate.ai_row_payload_raw))
                except json.JSONDecodeError:
                    raw_payloads.append(candidate.ai_row_payload_raw)
            merged_raw_payloads[key] = raw_payloads
            continue

        existing.snippets = _merge_snippets(existing.snippets, candidate.snippets)
        if reconciled_weight is not None:
            existing.peso_netto = reconciled_weight
        elif existing.peso_netto is None and candidate.peso_netto is not None:
            existing.peso_netto = candidate.peso_netto

        if candidate.ai_row_payload_raw:
            try:
                merged_raw_payloads[key].append(json.loads(candidate.ai_row_payload_raw))
            except json.JSONDecodeError:
                merged_raw_payloads[key].append(candidate.ai_row_payload_raw)

    reconciled_candidates = list(merged.values())
    for index, candidate in enumerate(reconciled_candidates, start=1):
        candidate.candidate_index = index
        key = (
            _string_or_none(candidate.ddt_number),
            _string_or_none(candidate.customer_order_no),
            _string_or_none(candidate.colata or candidate.cdq or candidate.lot_batch_no),
            _string_or_none(candidate.lega),
            _string_or_none(candidate.diametro),
        )
        raw_payloads = merged_raw_payloads.get(key, [])
        if len(raw_payloads) > 1:
            candidate.ai_row_payload_raw = json.dumps(raw_payloads, ensure_ascii=False)
        elif len(raw_payloads) == 1:
            single_payload = raw_payloads[0]
            candidate.ai_row_payload_raw = (
                json.dumps(single_payload, ensure_ascii=False)
                if not isinstance(single_payload, str)
                else single_payload
            )
    return reconciled_candidates


def _extract_aww_ddt_row_groups_with_vision(
    db: Session,
    *,
    ddt_document: Document,
    openai_api_key: str,
) -> list[ReaderRowSplitCandidateResponse]:
    if not ddt_document.pages:
        ddt_document = _index_document_from_path(db, ddt_document)
    ddt_document = _ensure_document_page_images(db, ddt_document)

    image_pages = [page for page in ddt_document.pages if page.immagine_pagina_storage_key]
    if not image_pages:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="DDT has no image pages available for AI")

    crop_definitions = _build_aww_ddt_group_crops(image_pages)
    if not crop_definitions:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Unable to prepare AWW DDT pages for AI",
        )

    local_matches = reader_detect_ddt_core_matches(ddt_document.pages, supplier_key="aww")
    fallback_ddt = _string_or_none(cast(dict[str, object], local_matches.get("ddt") or {}).get("final"))

    ddt_number_raw, raw_rows, ai_document_payload_raw = _extract_aww_ddt_row_groups_from_openai(
        crop_definitions,
        openai_api_key=openai_api_key,
    )
    candidates = _sanitize_aww_ai_row_groups(
        ddt_number_raw=ddt_number_raw or fallback_ddt,
        raw_rows=raw_rows,
        ai_document_payload_raw=ai_document_payload_raw,
    )
    return _enrich_aww_ai_row_groups_from_pages(candidates, ddt_document.pages)


def _build_aww_ddt_group_crops(
    pages: list[DocumentPage],
) -> dict[str, dict[str, str | int]]:
    crops: dict[str, dict[str, str | int]] = {}
    image_pages = [page for page in sorted(pages, key=lambda item: item.numero_pagina) if page.immagine_pagina_storage_key]
    if not image_pages:
        return crops

    for index, page in enumerate(image_pages):
        image_path = get_document_page_image_path(page)
        with Image.open(image_path) as image:
            masked_page = _build_aww_ddt_masked_page(image)
            storage_key = _save_ddt_crop(page, masked_page, f"aww_masked_page_{page.numero_pagina}")
            width, height = masked_page.size
            role_specs = [("row_groups_page", "row_groups_page")]
            if index == 0:
                role_specs.insert(0, ("header_page", "header_page"))
            else:
                role_specs.insert(0, ("continuation_page", "continuation_page"))
            for suffix, role in role_specs:
                label = f"page{page.numero_pagina}_{suffix}"
                crops[label] = {
                    "label": label,
                    "role": role,
                    "page_id": page.id,
                    "page_number": page.numero_pagina,
                    "storage_key": storage_key,
                    "bbox": f"0,0,{width},{height}",
                }
    return crops


def _build_aww_ddt_masked_page(image: Image.Image) -> Image.Image:
    masked = image.convert("RGB")
    lines = _extract_ocr_line_blocks(masked)
    _mask_aww_visual_logo_regions(masked, is_certificate_page=False)
    _mask_aww_customer_occurrence_blocks(masked, lines)
    _mask_aww_supplier_occurrence_blocks(masked, lines)
    _mask_aww_ddt_contact_values(masked)
    return masked


def _mask_aww_ddt_supplier_logo(image: Image.Image) -> None:
    _mask_aww_visual_logo_regions(image, is_certificate_page=False)


def _mask_aww_ddt_contact_values(image: Image.Image) -> None:
    words = _extract_ocr_word_blocks(image)
    if not words:
        return
    line_map = _group_ocr_words_by_line(words)
    anchor_groups = (
        ("CONTACT",),
        ("EMAIL",),
        ("SALES REPRESENTATIVE",),
    )
    for line_words in line_map.values():
        for anchors in anchor_groups:
            _mask_words_after_anchor(image, line_words, anchor_terms=anchors)


def _mask_aww_certificate_contact_values(image: Image.Image) -> None:
    words = _extract_ocr_word_blocks(image)
    if not words:
        return
    line_map = _group_ocr_words_by_line(words)
    anchor_groups = (
        ("ABNAHMEBEAUFTRAGTER",),
        ("PROD.WORKER/PERSONNE",),
        ("TEL.",),
    )
    for line_words in line_map.values():
        for anchors in anchor_groups:
            _mask_words_after_anchor(image, line_words, anchor_terms=anchors)


def _extract_aww_ddt_row_groups_from_openai(
    crops: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> tuple[str | None, list[dict[str, object]], str]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi queste pagine di un Delivery Note AWW e ricostruisci tutte le righe logiche materiale presenti. "
                "Il documento puo avere piu pagine e piu posizioni materiale. "
                "Una riga logica coincide con una singola posizione materiale del DDT. "
                "La posizione puo avere piu packaging IDs o piu righe HU: net_weight_raw deve essere il netto totale della posizione materiale, non il peso del singolo collo. "
                "Delivery Note e il numero DDT. "
                "customer_order_raw deve essere il Customer Order Number o Your purchase order della stessa posizione, quando visibile. "
                "part_number_raw deve essere il Part number della stessa posizione. "
                "your_part_number_raw deve essere lo Your part number della stessa posizione. "
                "order_confirmation_raw deve essere il valore di Order confirmation o il root del Batch number (OC) della stessa posizione. "
                "batch_number_oc_raw deve essere il Batch number (OC) completo della stessa posizione. "
                "alloy_temper_raw deve essere il valore di Legierung/Zustand o alloy code AWW della stessa posizione. "
                "alloy_temper_raw deve contenere solo la lega/stato metallurgico, ad esempio EN AW-6082A/535/T1. "
                "Non usare codici articolo, Your part number, Part number o Profilzeichnung come alloy_temper_raw. "
                "Se vedi una riga come Your part number o Profilzeichnung, non prenderla come lega. "
                "Cerca invece alloy code AWW, Legierung/Zustand o una dicitura materiale equivalente. "
                "Se trovi solo T1/T6 senza una lega tipo 6082, 6082A, EN AW o AlSi, restituisci null. "
                "Se il documento mostra EN AW-6082A/535/T1, restituisci proprio quel raw completo. "
                "diameter_raw deve essere il diametro preso dal simbolo Ø o da outer Ø della stessa posizione, senza dipendere dalla parola barra. "
                "length_raw deve essere la lunghezza raw della stessa posizione, quando visibile. "
                "Non fare il match con alcun certificato e non normalizzare i valori. "
                "Usa solo testo realmente visibile. Non inventare, non inferire e non usare nome file o conoscenza esterna. "
                "Se un campo non e chiaramente leggibile, restituisci null. "
                "Restituisci solo JSON con questa struttura: "
                "{\"ddt_number_raw\":\"string|null\",\"rows\":[{\"row_index\":1,"
                "\"customer_order_raw\":\"string|null\",\"part_number_raw\":\"string|null\","
                "\"your_part_number_raw\":\"string|null\",\"order_confirmation_raw\":\"string|null\","
                "\"batch_number_oc_raw\":\"string|null\",\"alloy_temper_raw\":\"string|null\","
                "\"diameter_raw\":\"string|null\",\"length_raw\":\"string|null\",\"net_weight_raw\":\"string|null\","
                "\"source_crops\":[\"label\"]}]}"
            ),
        }
    ]

    for crop_label, crop in crops.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": (
                    f"Page label: {crop_label}; "
                    f"role: {crop.get('role') or 'unknown'}; "
                    f"page_number: {crop.get('page_number') or 'unknown'}"
                ),
            }
        )
        content.append(
            {
                "type": "input_image",
                "image_url": f"data:image/png;base64,{encoded}",
                "detail": "high",
            }
        )

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="AWW DDT row-group AI request failed") from exc

    return (*_parse_openai_json_payload_for_aww_row_groups(response.output_text), response.output_text)


def _parse_openai_json_payload_for_aww_row_groups(
    payload: str,
) -> tuple[str | None, list[dict[str, object]]]:
    text = payload.strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text)
        text = re.sub(r"\s*```$", "", text)
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, re.DOTALL)
        if not match:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from AWW DDT row-group AI")
        try:
            data = json.loads(match.group(0))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from AWW DDT row-group AI") from exc

    if not isinstance(data, dict):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Unexpected AWW DDT row-group AI payload")

    rows_payload = data.get("rows")
    if not isinstance(rows_payload, list):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Missing rows in AWW DDT row-group AI payload")

    normalized_rows: list[dict[str, object]] = []
    for index, raw_row in enumerate(rows_payload, start=1):
        if not isinstance(raw_row, dict):
            continue
        raw_row_index = raw_row.get("row_index")
        try:
            normalized_row_index = int(raw_row_index) if raw_row_index is not None else index
        except (TypeError, ValueError):
            normalized_row_index = index
        source_crops = raw_row.get("source_crops")
        normalized_sources = [
            item
            for item in (
                _string_or_none(source_crop) for source_crop in (source_crops if isinstance(source_crops, list) else [])
            )
            if item is not None
        ]
        normalized_rows.append(
            {
                "row_index": normalized_row_index,
                "customer_order_raw": _string_or_none(raw_row.get("customer_order_raw")),
                "part_number_raw": _string_or_none(raw_row.get("part_number_raw")),
                "your_part_number_raw": _string_or_none(raw_row.get("your_part_number_raw")),
                "order_confirmation_raw": _string_or_none(raw_row.get("order_confirmation_raw")),
                "batch_number_oc_raw": _string_or_none(raw_row.get("batch_number_oc_raw")),
                "alloy_temper_raw": _string_or_none(raw_row.get("alloy_temper_raw")),
                "diameter_raw": _string_or_none(raw_row.get("diameter_raw")),
                "length_raw": _string_or_none(raw_row.get("length_raw")),
                "net_weight_raw": _string_or_none(raw_row.get("net_weight_raw")),
                "source_crops": normalized_sources,
            }
        )

    return _string_or_none(data.get("ddt_number_raw")), normalized_rows


def _sanitize_aww_ai_row_groups(
    *,
    ddt_number_raw: str | None,
    raw_rows: list[dict[str, object]],
    ai_document_payload_raw: str,
) -> list[ReaderRowSplitCandidateResponse]:
    sanitized_rows: list[ReaderRowSplitCandidateResponse] = []
    normalized_ddt = _sanitize_aww_ddt_number_candidate(ddt_number_raw)

    for index, raw_row in enumerate(raw_rows, start=1):
        customer_order_raw = _string_or_none(raw_row.get("customer_order_raw"))
        part_number_raw = _string_or_none(raw_row.get("part_number_raw"))
        your_part_number_raw = _string_or_none(raw_row.get("your_part_number_raw"))
        order_confirmation_raw = _string_or_none(raw_row.get("order_confirmation_raw"))
        batch_number_oc_raw = _string_or_none(raw_row.get("batch_number_oc_raw"))
        alloy_temper_raw = _string_or_none(raw_row.get("alloy_temper_raw"))
        diameter_raw = _string_or_none(raw_row.get("diameter_raw"))
        length_raw = _string_or_none(raw_row.get("length_raw"))
        net_weight_raw = _string_or_none(raw_row.get("net_weight_raw"))
        source_crops = cast(list[str], raw_row.get("source_crops") or [])

        order_value = _normalize_aww_customer_order_token(customer_order_raw)
        part_number = _normalize_aww_part_number_from_text(part_number_raw)
        your_part_number = _normalize_aww_customer_material_from_text(your_part_number_raw)
        order_confirmation_root = _normalize_aww_order_confirmation_root(
            batch_number_oc_raw or order_confirmation_raw
        )
        alloy_value = _normalize_aww_alloy_from_text(alloy_temper_raw)
        diameter_value = _normalize_aww_diameter_from_text(diameter_raw)
        weight_value = _normalize_value_for_field("ddt", "peso", net_weight_raw)

        raw_payload = dict(raw_row)
        raw_payload["customer_order_raw"] = customer_order_raw
        raw_payload["part_number_raw"] = part_number_raw
        raw_payload["your_part_number_raw"] = your_part_number_raw
        raw_payload["order_confirmation_raw"] = order_confirmation_raw
        raw_payload["batch_number_oc_raw"] = batch_number_oc_raw
        raw_payload["alloy_temper_raw"] = alloy_temper_raw
        raw_payload["diameter_raw"] = diameter_raw
        raw_payload["length_raw"] = length_raw
        raw_payload["net_weight_raw"] = net_weight_raw

        candidate = ReaderRowSplitCandidateResponse(
            candidate_index=index,
            supplier_key="aww",
            ddt_number=normalized_ddt,
            profile_code=part_number,
            article_code=your_part_number,
            lega=alloy_value,
            diametro=diameter_value,
            peso_netto=weight_value,
            customer_order_no=order_value,
            supplier_order_no=order_confirmation_root,
            snippets=source_crops[:6],
            ai_row_payload_raw=json.dumps(raw_payload, ensure_ascii=False),
            ai_document_payload_raw=ai_document_payload_raw,
        )

        if any(
            getattr(candidate, field_name) is not None
            for field_name in ("ddt_number", "profile_code", "article_code", "lega", "diametro", "peso_netto", "supplier_order_no")
        ):
            sanitized_rows.append(candidate)

    return sanitized_rows


def _enrich_aww_ai_row_groups_from_pages(
    candidates: list[ReaderRowSplitCandidateResponse],
    pages: list[DocumentPage],
) -> list[ReaderRowSplitCandidateResponse]:
    if not candidates or not pages:
        return candidates
    page_texts = _document_page_text_map(pages)
    for candidate in candidates:
        if _is_valid_aww_alloy_value(candidate.lega):
            continue
        raw_payload = _load_json_dict(candidate.ai_row_payload_raw)
        source_pages = _source_crop_page_numbers(cast(list[str], raw_payload.get("source_crops") or []))
        fallback_text = _collect_page_text_subset(page_texts, source_pages)
        alloy_raw = _extract_aww_alloy_from_document_text(fallback_text)
        alloy_value = _normalize_aww_alloy_from_text(alloy_raw)
        if alloy_value is None:
            continue
        candidate.lega = alloy_value
        raw_payload["alloy_temper_raw"] = alloy_raw
        candidate.ai_row_payload_raw = json.dumps(raw_payload, ensure_ascii=False)
    return candidates


def _sanitize_aww_ddt_number_candidate(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(\d{7,9})\b", cleaned)
    if match is not None:
        return match.group(1)
    return _sanitize_ddt_number_candidate(value, None)


def _normalize_aww_order_confirmation_root(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(\d{6,10})\b", cleaned)
    return match.group(1) if match is not None else None


def _normalize_aww_customer_material_from_text(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\bA[0-9A-Z]{6,}\b")


def _normalize_aww_part_number_from_text(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\bP3-\d{5}-\d{4}\b")


def _normalize_aww_customer_order_token(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b([0-9]{1,6})\b", cleaned)
    return match.group(1) if match is not None else cleaned


def _normalize_aww_alloy_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = re.sub(r"\s+", " ", cleaned.upper()).strip()
    base: str | None = None
    if "6082A" in normalized or "ALSI1MGMN(A)" in normalized:
        base = "6082A"
    elif "6082" in normalized or "ALSI1MGMN" in normalized:
        base = "6082"
    temper_match = re.search(r"\bT\d+[A-Z0-9/-]*\b", normalized)
    temper = temper_match.group(0) if temper_match is not None else None
    if base and temper:
        return f"{base} {temper}"
    return base


def _is_valid_aww_alloy_value(value: str | None) -> bool:
    return _normalize_aww_alloy_from_text(value) is not None


def _normalize_aww_diameter_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = re.sub(r"\s+", " ", cleaned.upper()).strip()
    match = re.search(r"[ØO]\s*([0-9]+(?:[.,][0-9]+)?)\s*MM\b", normalized)
    if match is not None:
        return _normalize_diameter_value(match.group(1))
    match = re.search(r"\b([0-9]{2,3}(?:[.,][0-9]+)?)\s*MM\b", normalized)
    if match is not None:
        return _normalize_diameter_value(match.group(1))
    direct = re.fullmatch(r"\s*([0-9]{2,3}(?:[.,][0-9]+)?)\s*", normalized)
    if direct is not None:
        return _normalize_diameter_value(direct.group(1))
    return None


def _document_page_text_map(pages: list[DocumentPage]) -> dict[int, str]:
    page_texts: dict[int, str] = {}
    for page in pages:
        text = _string_or_none(page.ocr_text) or _string_or_none(page.testo_estratto)
        if text is None:
            continue
        page_texts[int(page.numero_pagina)] = text
    return page_texts


def _source_crop_page_numbers(source_crops: list[str]) -> list[int]:
    page_numbers: list[int] = []
    for label in source_crops:
        cleaned = _string_or_none(label)
        if cleaned is None:
            continue
        match = re.search(r"page[_-]?(\d+)", cleaned, re.IGNORECASE)
        if match is None:
            continue
        page_number = int(match.group(1))
        if page_number not in page_numbers:
            page_numbers.append(page_number)
    return page_numbers


def _collect_page_text_subset(page_texts: dict[int, str], page_numbers: list[int]) -> str:
    if page_numbers:
        texts = [page_texts[number] for number in page_numbers if number in page_texts]
        if texts:
            return "\n".join(texts)
    return "\n".join(page_texts[number] for number in sorted(page_texts))


def _load_json_dict(raw_payload: str | None) -> dict[str, object]:
    cleaned = _string_or_none(raw_payload)
    if cleaned is None:
        return {}
    try:
        parsed = json.loads(cleaned)
    except (TypeError, ValueError):
        return {}
    return parsed if isinstance(parsed, dict) else {}


def _extract_aww_alloy_from_document_text(text: str | None) -> str | None:
    cleaned = _string_or_none(text)
    if cleaned is None:
        return None
    match = re.search(r"alloy\s+code\s+aww\s*:\s*([^\n\r]+)", cleaned, re.IGNORECASE)
    if match is None:
        return None
    return _string_or_none(match.group(1))


def _extract_aww_dimension_context_from_document_text(text: str | None) -> str | None:
    cleaned = _string_or_none(text)
    if cleaned is None:
        return None
    match = re.search(
        r"((?:rundstange|round\s*bar)\s*[0-9]{2,3}(?:[.,][0-9]+)?)",
        cleaned,
        re.IGNORECASE,
    )
    if match is not None:
        return _string_or_none(match.group(1))
    return None


def _extract_neuman_ddt_row_groups_with_vision(
    db: Session,
    *,
    ddt_document: Document,
    openai_api_key: str,
) -> list[ReaderRowSplitCandidateResponse]:
    if not ddt_document.pages:
        ddt_document = _index_document_from_path(db, ddt_document)
    ddt_document = _ensure_document_page_images(db, ddt_document)

    image_pages = [page for page in ddt_document.pages if page.immagine_pagina_storage_key]
    if not image_pages:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="DDT has no image pages available for AI")

    crop_definitions = _build_neuman_ddt_group_crops(image_pages)
    if not crop_definitions:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Unable to prepare Neuman DDT row-group crops for AI",
        )

    local_plan = build_document_row_split_plan(prepare_document_for_reader(db, ddt_document))
    fallback_ddt = next(
        (_string_or_none(candidate.ddt_number) for candidate in local_plan.row_split_candidates if candidate.ddt_number),
        None,
    )

    ddt_number_raw, raw_rows, ai_document_payload_raw = _extract_neuman_ddt_row_groups_from_openai(
        crop_definitions,
        openai_api_key=openai_api_key,
    )
    return _sanitize_neuman_ai_row_groups(
        ddt_number_raw=ddt_number_raw or fallback_ddt,
        raw_rows=raw_rows,
        ai_document_payload_raw=ai_document_payload_raw,
    )


def _build_neuman_ddt_group_crops(
    pages: list[DocumentPage],
) -> dict[str, dict[str, str | int]]:
    crops: dict[str, dict[str, str | int]] = {}
    image_pages = [page for page in sorted(pages, key=lambda item: item.numero_pagina) if page.immagine_pagina_storage_key]
    if not image_pages:
        return crops

    for index, page in enumerate(image_pages):
        image_path = get_document_page_image_path(page)
        with Image.open(image_path) as image:
            masked_page = _build_neuman_ddt_masked_page(image)
            storage_key = _save_ddt_crop(page, masked_page, f"neuman_masked_page_{page.numero_pagina}")
            width, height = masked_page.size
            role_specs = [("row_groups_page", "row_groups_page")]
            if index == 0:
                role_specs.insert(0, ("header_page", "header_page"))
            else:
                role_specs.insert(0, ("continuation_page", "continuation_page"))
            for suffix, role in role_specs:
                label = f"page{page.numero_pagina}_{suffix}"
                crops[label] = {
                    "label": label,
                    "role": role,
                    "page_id": page.id,
                    "page_number": page.numero_pagina,
                    "storage_key": storage_key,
                    "bbox": f"0,0,{width},{height}",
                }
    return crops


def _build_neuman_ddt_masked_page(image: Image.Image) -> Image.Image:
    masked = image.convert("RGB")
    lines = _extract_ocr_line_blocks(masked)
    _mask_neuman_visual_logo_regions(masked, is_certificate_page=False)
    _mask_neuman_customer_occurrence_blocks(masked, lines)
    _mask_neuman_supplier_occurrence_blocks(masked, lines)
    return masked


def _extract_neuman_ddt_row_groups_from_openai(
    crops: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> tuple[str | None, list[dict[str, object]], str]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi queste immagini di un Delivery Note Neuman e ricostruisci tutte le righe logiche materiale presenti. "
                "Il documento puo avere piu pagine e piu gruppi prodotto/lotto. "
                "Una riga logica coincide con un gruppo coerente prodotto + Lot. "
                "I colli HU dello stesso Lot vanno sommati e net_weight_raw deve essere il netto totale del gruppo Lot, non il peso di un singolo collo. "
                "Delivery Note e il numero DDT. Load non e il numero DDT. "
                "Art-Nr. e il codice materiale del DDT. Werkstoff e il materiale/lega. "
                "diameter_raw deve venire dal simbolo Ø o dal testo prodotto che contiene il diametro, senza dipendere dalla parola barra. "
                "customer_order_raw deve essere il valore del campo Customer Order Number, quando visibile. "
                "lot_raw deve essere il Lot della stessa riga logica. "
                "Non fare il match con alcun certificato e non normalizzare i valori. "
                "Usa solo testo realmente visibile. Non inventare, non inferire e non usare nome file o conoscenza esterna. "
                "Se un campo non e chiaramente leggibile, restituisci null. "
                "Restituisci solo JSON con questa struttura: "
                "{\"ddt_number_raw\":\"string|null\",\"rows\":[{\"row_index\":1,"
                "\"customer_order_raw\":\"string|null\",\"article_number_raw\":\"string|null\","
                "\"material_raw\":\"string|null\",\"diameter_raw\":\"string|null\",\"lot_raw\":\"string|null\","
                "\"net_weight_raw\":\"string|null\",\"source_crops\":[\"label\"]}]}"
            ),
        }
    ]

    for crop_label, crop in crops.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": (
                    f"Page label: {crop_label}; "
                    f"role: {crop.get('role') or 'unknown'}; "
                    f"page_number: {crop.get('page_number') or 'unknown'}"
                ),
            }
        )
        content.append(
            {
                "type": "input_image",
                "image_url": f"data:image/png;base64,{encoded}",
                "detail": "high",
            }
        )

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Neuman DDT row-group AI request failed") from exc

    return (*_parse_openai_json_payload_for_neuman_row_groups(response.output_text), response.output_text)


def _parse_openai_json_payload_for_neuman_row_groups(
    payload: str,
) -> tuple[str | None, list[dict[str, object]]]:
    text = payload.strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text)
        text = re.sub(r"\s*```$", "", text)
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, re.DOTALL)
        if not match:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Neuman DDT row-group AI")
        try:
            data = json.loads(match.group(0))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Neuman DDT row-group AI") from exc

    if not isinstance(data, dict):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Unexpected Neuman DDT row-group AI payload")

    rows_payload = data.get("rows")
    if not isinstance(rows_payload, list):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Missing rows in Neuman DDT row-group AI payload")

    normalized_rows: list[dict[str, object]] = []
    for index, raw_row in enumerate(rows_payload, start=1):
        if not isinstance(raw_row, dict):
            continue
        raw_row_index = raw_row.get("row_index")
        try:
            normalized_row_index = int(raw_row_index) if raw_row_index is not None else index
        except (TypeError, ValueError):
            normalized_row_index = index
        source_crops = raw_row.get("source_crops")
        normalized_sources = [
            item
            for item in (
                _string_or_none(source_crop) for source_crop in (source_crops if isinstance(source_crops, list) else [])
            )
            if item is not None
        ]
        normalized_rows.append(
            {
                "row_index": normalized_row_index,
                "customer_order_raw": _string_or_none(raw_row.get("customer_order_raw")),
                "article_number_raw": _string_or_none(raw_row.get("article_number_raw")),
                "material_raw": _string_or_none(raw_row.get("material_raw")),
                "diameter_raw": _string_or_none(raw_row.get("diameter_raw")),
                "lot_raw": _string_or_none(raw_row.get("lot_raw")),
                "net_weight_raw": _string_or_none(raw_row.get("net_weight_raw")),
                "source_crops": normalized_sources,
            }
        )

    return _string_or_none(data.get("ddt_number_raw")), normalized_rows


def _sanitize_neuman_ai_row_groups(
    *,
    ddt_number_raw: str | None,
    raw_rows: list[dict[str, object]],
    ai_document_payload_raw: str,
) -> list[ReaderRowSplitCandidateResponse]:
    sanitized_rows: list[ReaderRowSplitCandidateResponse] = []
    normalized_ddt = _sanitize_neuman_ddt_number_candidate(ddt_number_raw)

    for index, raw_row in enumerate(raw_rows, start=1):
        customer_order_raw = _string_or_none(raw_row.get("customer_order_raw"))
        article_number_raw = _string_or_none(raw_row.get("article_number_raw"))
        material_raw = _string_or_none(raw_row.get("material_raw"))
        diameter_raw = _string_or_none(raw_row.get("diameter_raw"))
        lot_raw = _string_or_none(raw_row.get("lot_raw"))
        net_weight_raw = _string_or_none(raw_row.get("net_weight_raw"))
        source_crops = cast(list[str], raw_row.get("source_crops") or [])

        order_value = _normalize_neuman_customer_order_token(customer_order_raw)
        article_value = _normalize_neuman_article_from_text(article_number_raw)
        alloy_value = _normalize_neuman_alloy_from_text(material_raw)
        diameter_value = _normalize_neuman_diameter_from_text(diameter_raw)
        lot_value = _normalize_neuman_lot_token(lot_raw)
        weight_value = reader_normalize_neuman_weight_result(net_weight_raw)

        raw_payload = dict(raw_row)
        raw_payload["customer_order_raw"] = customer_order_raw
        raw_payload["article_number_raw"] = article_number_raw
        raw_payload["material_raw"] = material_raw
        raw_payload["diameter_raw"] = diameter_raw
        raw_payload["lot_raw"] = lot_raw
        raw_payload["net_weight_raw"] = net_weight_raw

        candidate = ReaderRowSplitCandidateResponse(
            candidate_index=index,
            supplier_key="neuman",
            ddt_number=normalized_ddt,
            cdq=lot_value,
            article_code=article_value,
            lega=alloy_value,
            diametro=diameter_value,
            peso_netto=weight_value,
            colata=lot_value,
            lot_batch_no=lot_value,
            customer_order_no=order_value,
            snippets=source_crops[:6],
            ai_row_payload_raw=json.dumps(raw_payload, ensure_ascii=False),
            ai_document_payload_raw=ai_document_payload_raw,
        )

        if any(
            getattr(candidate, field_name) is not None
            for field_name in ("ddt_number", "cdq", "article_code", "lega", "diametro", "peso_netto", "customer_order_no")
        ):
            sanitized_rows.append(candidate)

    return sanitized_rows


def _sanitize_neuman_ddt_number_candidate(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(\d{6,9})\b", cleaned)
    if match is not None:
        return match.group(1)
    return _sanitize_ddt_number_candidate(value, None)


def _normalize_neuman_lot_token(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\b\d{5}\b")


def _normalize_neuman_article_from_text(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\bA\d[0-9A-Z]{4,}\b")


def _normalize_neuman_customer_order_token(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    explicit = re.search(r"\b([0-9]{1,6})\s+OF\s+\d{2}\.\d{2}\.\d{4}\b", cleaned.upper())
    if explicit is not None:
        return explicit.group(1)
    direct = re.search(r"\b([0-9]{1,6})\b", cleaned)
    if direct is not None:
        return direct.group(1)
    return cleaned


def _normalize_neuman_alloy_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = re.sub(r"\s+", " ", cleaned.upper()).strip()
    match = re.search(r"\bEN\s+AW[-\s]*([0-9]{4}[A-Z]{0,3})\b", normalized)
    if match is not None:
        return match.group(1)
    fallback = re.search(r"\b([1-9][0-9]{3}[A-Z]{0,3})\b", normalized)
    if fallback is not None:
        return fallback.group(1)
    return None


def _normalize_neuman_diameter_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = re.sub(r"\s+", " ", cleaned.upper()).strip()
    match = re.search(r"[Ø@]\s*([0-9]+(?:[.,][0-9]+)?)\s*MM\b", normalized)
    if match is not None:
        return _normalize_numeric_value(match.group(1))
    match = re.search(r"[Ø@]\s*([0-9]+(?:[.,][0-9]+)?)\b", normalized)
    if match is not None:
        return _normalize_numeric_value(match.group(1))
    direct = re.fullmatch(r"\s*([0-9]{2,3}(?:[.,][0-9]+)?)\s*(?:MM)?\s*", normalized)
    if direct is not None:
        return _normalize_numeric_value(direct.group(1))
    return None


def _sanitize_leichtmetall_ddt_number_candidate(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(\d{7,9})\b", cleaned)
    if match is not None:
        return match.group(1)
    return _sanitize_ddt_number_candidate(value, None)


def _sanitize_metalba_ddt_number_candidate(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(?:DDT\s*)?(\d{2}[-/]\d{5})\b", cleaned.upper())
    if match is None:
        return None
    return match.group(1).replace("/", "-")


def _normalize_metalba_alloy_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = re.sub(r"\s+", " ", cleaned.upper())
    match = re.search(r"\b([1-9][0-9]{3}[A-Z]?)\s+(F|T\d+[A-Z0-9/-]*)\b", normalized)
    if match is None:
        return None
    return f"{match.group(1)} {match.group(2)}"


def _normalize_metalba_diameter_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\bBARRA\s+TONDA\s+DIAM\s*([0-9]+(?:[.,][0-9]+)?)\s*MM\b", cleaned.upper())
    if match is None:
        return None
    return _normalize_numeric_value(match.group(1))


def _normalize_leichtmetall_alloy_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = re.sub(r"\s+", " ", cleaned.upper()).strip()
    match = re.search(r"\b([1-9][0-9]{3}[A-Z]?)\b", normalized)
    if match is None:
        return None
    alloy = match.group(1)
    return "7075" if alloy == "7175" else alloy


def _normalize_leichtmetall_diameter_from_text(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(?:DIA(?:METER)?|Ø)\s*([0-9]+(?:[.,][0-9]+)?)\b", cleaned.upper())
    if match is not None:
        return _normalize_numeric_value(match.group(1))
    direct_match = re.fullmatch(r"\s*([0-9]{2,3}(?:[.,][0-9]+)?)\s*(?:MM)?\s*", cleaned.upper())
    if direct_match is None:
        return None
    return _normalize_numeric_value(direct_match.group(1))


def _normalize_leichtmetall_order_token(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    parts = [part.strip() for part in re.split(r"\s*\+\s*", cleaned) if part.strip()]
    return " + ".join(parts) if parts else None


def _normalize_leichtmetall_batch_token(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(
        value,
        value,
        r"\b\d{5,6}\b",
        disallow={"10204"},
    )


def _normalize_aluminium_bozen_measured_rows_payload(
    measured_rows_payload: list[object],
    *,
    page_id: int,
) -> dict[str, dict[str, str | int]]:
    candidates: dict[str, list[tuple[float, str]]] = {}
    snippets: dict[str, str] = {}
    for raw_row in measured_rows_payload:
        if not isinstance(raw_row, dict):
            continue
        snippet_parts: list[str] = []
        for field_name in ("Rm", "Rp0.2", "A%", "HB", "IACS%", "Rp0.2/Rm"):
            raw_value = _string_or_none(raw_row.get(field_name))
            if raw_value is None:
                continue
            standardized = _normalize_numeric_value(raw_value)
            if standardized is None:
                continue
            try:
                numeric_value = float(standardized)
            except ValueError:
                continue
            candidates.setdefault(field_name, []).append((numeric_value, standardized))
            snippet_parts.append(f"{field_name}={raw_value}")
        if snippet_parts:
            snippet = " ".join(snippet_parts)
            for field_name in ("Rm", "Rp0.2", "A%", "HB", "IACS%", "Rp0.2/Rm"):
                if _string_or_none(raw_row.get(field_name)) is not None:
                    snippets.setdefault(field_name, snippet)

    normalized: dict[str, dict[str, str | int]] = {}
    for field_name, values in candidates.items():
        values.sort(key=lambda item: item[0])
        _, chosen = values[0]
        normalized[field_name] = {
            "page_id": page_id,
            "snippet": snippets.get(field_name, chosen),
            "raw": chosen,
            "standardized": chosen,
            "final": chosen,
            "method": "chatgpt",
        }
    return normalized


def _get_leichtmetall_certificate_ai_payload(
    db: Session,
    *,
    certificate_document: Document,
    openai_api_key: str,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> dict[str, object]:
    cached = certificate_ai_cache.get(certificate_document.id) if certificate_ai_cache is not None else None
    if cached is not None:
        return cached

    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)
    if not _document_has_image_pages(certificate_document):
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    crops = _build_certificate_safe_crops(certificate_document.pages, supplier_key="leichtmetall")
    page_images = _select_leichtmetall_certificate_document_images(crops)
    if not page_images:
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    raw_payload = _extract_leichtmetall_certificate_payload_from_openai(
        page_images,
        openai_api_key=openai_api_key,
    )
    payload = _normalize_leichtmetall_certificate_ai_payload(page_images, raw_payload)
    if certificate_ai_cache is not None:
        certificate_ai_cache[certificate_document.id] = payload
    return payload


def _select_leichtmetall_certificate_document_images(
    crops: dict[str, dict[str, str | int]],
) -> dict[str, dict[str, str | int]]:
    return _select_impol_certificate_document_images(crops)


def _extract_leichtmetall_certificate_payload_from_openai(
    page_images: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> dict[str, object]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi questo certificato materiale Leichtmetall. "
                "Scopo: estrarre i dati identificativi e tecnici del certificato, leggere composizione chimica, proprieta meccaniche e note tecniche rilevanti. "
                "Presta particolare attenzione a PO-No., Charge / Cast No, alloy, diameter e weight. "
                "Per questo fornitore la Charge / Cast No del certificato puo essere trattata anche come cdq. "
                "Usa solo testo realmente visibile nel documento. Non inventare, non inferire, non normalizzare. "
                "Se un campo non e chiaramente leggibile, restituisci null. "
                "Campi core da estrarre. "
                "numero_certificato: per questo fornitore usa il valore di Charge / Cast No, che puo essere trattato anche come cdq. "
                "ordine_cliente: estrai il valore del campo PO-No. "
                "articolo: usa null se non esiste un vero codice articolo distinto. "
                "lega: estrai la lega materiale. "
                "descrizione_profilo_cliente: usa null se non esiste un campo separato equivalente. "
                "colata: estrai il valore del campo Charge / Cast No. "
                "peso_netto: estrai il weight netto della riga materiale. "
                "Campi runtime di supporto da estrarre inoltre. "
                "po_no: estrai il valore raw del campo PO-No. "
                "charge_cast_no: estrai il valore raw del campo Charge / Cast No. "
                "alloy_raw: estrai il valore raw della lega. "
                "diameter_raw: estrai il diametro raw del materiale. "
                "weight_raw: estrai il peso raw del materiale. "
                "Chimica: usa solo Si, Fe, Cu, Mn, Mg, Cr, Ni, Zn, Ti, Cd, Hg, Pb, V, Bi, Sn, Zr, Be, Zr+Ti, Mn+Cr, Bi+Pb; restituisci solo i valori misurati veri e ignora Min e Max. "
                "Proprieta meccaniche: considera Rm, Rp0.2, A%, HB, IACS%, Rp0.2/Rm; non usare Min o Max; se ci sono piu righe misurate vere, restituisci tutte le righe misurate raw. "
                "Note: verifica nota_us_control_class_a, nota_us_control_class_b, nota_rohs, nota_radioactive_free; se compaiono sia Class A sia Class B restituisci entrambe. "
                "Restituisci solo JSON con questa struttura: "
                "{\"core\":{\"numero_certificato\":\"string|null\",\"ordine_cliente\":\"string|null\",\"articolo\":\"string|null\","
                "\"lega\":\"string|null\",\"descrizione_profilo_cliente\":\"string|null\",\"colata\":\"string|null\",\"peso_netto\":\"string|null\","
                "\"po_no\":\"string|null\",\"charge_cast_no\":\"string|null\",\"alloy_raw\":\"string|null\",\"diameter_raw\":\"string|null\",\"weight_raw\":\"string|null\"},"
                "\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\",\"Mn\":\"string|null\",\"Mg\":\"string|null\","
                "\"Cr\":\"string|null\",\"Ni\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\",\"Cd\":\"string|null\",\"Hg\":\"string|null\","
                "\"Pb\":\"string|null\",\"V\":\"string|null\",\"Bi\":\"string|null\",\"Sn\":\"string|null\",\"Zr\":\"string|null\",\"Be\":\"string|null\",\"Zr+Ti\":\"string|null\",\"Mn+Cr\":\"string|null\","
                "\"Bi+Pb\":\"string|null\"},"
                "\"mechanical_raw\":{\"measured_rows\":[{\"Rm\":\"string|null\",\"Rp0.2\":\"string|null\",\"A%\":\"string|null\",\"HB\":\"string|null\","
                "\"IACS%\":\"string|null\",\"Rp0.2/Rm\":\"string|null\"}]},"
                "\"notes_raw\":{\"nota_us_control_class_a_raw\":\"string|null\",\"nota_us_control_class_b_raw\":\"string|null\","
                "\"nota_rohs_raw\":\"string|null\",\"nota_radioactive_free_raw\":\"string|null\"}}"
            ),
        }
    ]

    for image_label, crop in page_images.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": (
                    f"Image label: {image_label}; "
                    f"page_number: {crop.get('page_number') or 'unknown'}"
                ),
            }
        )
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Leichtmetall certificate AI extraction request failed") from exc

    return _parse_openai_json_payload_for_certificate_bundle(response.output_text)


def _normalize_leichtmetall_certificate_ai_payload(
    page_images: dict[str, dict[str, str | int]],
    raw_payload: dict[str, object],
) -> dict[str, object]:
    first_page_crop = next(iter(page_images.values()), None)
    first_page_id = int(first_page_crop.get("page_id")) if first_page_crop and first_page_crop.get("page_id") else 0
    last_page_crop = next(reversed(page_images.values()), None) if page_images else None
    last_page_id = int(last_page_crop.get("page_id")) if last_page_crop and last_page_crop.get("page_id") else first_page_id

    core_payload = cast(dict[str, object], raw_payload.get("core") or {})
    core_fields = _sanitize_leichtmetall_vision_certificate_fields(core_payload, next(iter(page_images.keys()), None))

    chemistry_payload = cast(dict[str, object], raw_payload.get("chemistry_raw") or {})
    chemistry_matches = _normalize_vision_numeric_matches(
        {
            field_name: {
                "value": _string_or_none(chemistry_payload.get(field_name)),
                "evidence": _string_or_none(chemistry_payload.get(field_name)),
                "source_crop": next(iter(page_images.keys()), None),
            }
            for field_name in ("Si", "Fe", "Cu", "Mn", "Mg", "Cr", "Ni", "Zn", "Ti", "Cd", "Hg", "Pb", "V", "Bi", "Sn", "Zr", "Be", "Zr+Ti", "Mn+Cr", "Bi+Pb")
        },
        {
            next(iter(page_images.keys()), "page1"): {
                "page_id": first_page_id,
                "page_number": first_page_crop.get("page_number") if first_page_crop else 1,
            }
        },
    )

    measured_rows_payload = cast(dict[str, object], raw_payload.get("mechanical_raw") or {}).get("measured_rows") or []
    property_matches = _normalize_aluminium_bozen_measured_rows_payload(
        measured_rows_payload if isinstance(measured_rows_payload, list) else [],
        page_id=first_page_id,
    )

    notes_payload = cast(dict[str, object], raw_payload.get("notes_raw") or {})
    note_matches = _normalize_vision_note_matches(
        _build_vision_note_extracted_payload(notes_payload, next(reversed(page_images.keys()), None) if page_images else None),
        {
            next(reversed(page_images.keys()), "page1"): {
                "page_id": last_page_id,
                "page_number": last_page_crop.get("page_number") if last_page_crop else (first_page_crop.get("page_number") if first_page_crop else 1),
            }
        },
    )

    po_no_raw = _string_or_none(core_payload.get("po_no")) or _string_or_none(core_payload.get("ordine_cliente"))
    charge_cast_raw = _string_or_none(core_payload.get("charge_cast_no")) or _string_or_none(core_payload.get("colata"))
    alloy_raw = _string_or_none(core_payload.get("alloy_raw")) or _string_or_none(core_payload.get("lega"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw"))
    weight_raw = _string_or_none(core_payload.get("weight_raw")) or _string_or_none(core_payload.get("peso_netto"))

    return {
        "match_values": {
            field_name: _string_or_none(field_payload.get("value"))
            for field_name, field_payload in core_fields.items()
        },
        "supplier_fields": {
            "po_no": _normalize_leichtmetall_order_token(po_no_raw),
            "customer_order_no": _normalize_leichtmetall_order_token(po_no_raw),
            "charge_cast_no": _normalize_leichtmetall_batch_token(charge_cast_raw),
            "alloy": _normalize_leichtmetall_alloy_from_text(alloy_raw),
            "diameter": _normalize_leichtmetall_diameter_from_text(diameter_raw),
            "weight": reader_normalize_neuman_weight_result(weight_raw),
        },
        "core_fields": core_fields,
        "chemistry": chemistry_matches,
        "properties": property_matches,
        "notes": note_matches,
        "debug_raw_output": json.dumps(raw_payload, ensure_ascii=False),
    }


def _sanitize_leichtmetall_vision_certificate_fields(
    core_payload: dict[str, object],
    source_crop: str | None,
) -> dict[str, dict[str, str | None]]:
    order_raw = _string_or_none(core_payload.get("po_no")) or _string_or_none(core_payload.get("ordine_cliente"))
    cast_raw = _string_or_none(core_payload.get("charge_cast_no")) or _string_or_none(core_payload.get("colata"))
    alloy_raw = _string_or_none(core_payload.get("alloy_raw")) or _string_or_none(core_payload.get("lega"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw"))
    weight_raw = _string_or_none(core_payload.get("weight_raw")) or _string_or_none(core_payload.get("peso_netto"))

    def _payload(value: str | None) -> dict[str, str | None]:
        return {"value": value, "evidence": value, "source_crop": source_crop}

    normalized_order = _normalize_leichtmetall_order_token(order_raw)
    normalized_cast = _normalize_leichtmetall_batch_token(cast_raw)
    normalized_alloy = _normalize_leichtmetall_alloy_from_text(alloy_raw)
    normalized_diameter = _normalize_leichtmetall_diameter_from_text(diameter_raw)
    normalized_weight = reader_normalize_neuman_weight_result(weight_raw)

    return {
        "numero_certificato_certificato": _payload(normalized_cast),
        "ordine_cliente_certificato": _payload(normalized_order),
        "articolo_certificato": _payload(None),
        "codice_cliente_certificato": _payload(None),
        "lega_certificato": _payload(normalized_alloy),
        "descrizione_profilo_cliente_certificato": _payload(None),
        "colata_certificato": _payload(normalized_cast),
        "peso_certificato": _payload(normalized_weight),
        "diametro_certificato": _payload(normalized_diameter),
    }


def _get_aww_certificate_ai_payload(
    db: Session,
    *,
    certificate_document: Document,
    openai_api_key: str,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> dict[str, object]:
    cached = certificate_ai_cache.get(certificate_document.id) if certificate_ai_cache is not None else None
    if cached is not None:
        return cached

    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)
    if not _document_has_image_pages(certificate_document):
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    crops = _build_certificate_safe_crops(certificate_document.pages, supplier_key="aww")
    page_images = _select_aww_certificate_document_images(crops)
    if not page_images:
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    raw_payload = _extract_aww_certificate_payload_from_openai(
        page_images,
        openai_api_key=openai_api_key,
    )
    payload = _normalize_aww_certificate_ai_payload(page_images, raw_payload)
    payload = _enrich_aww_certificate_ai_payload_from_pages(payload, certificate_document.pages)
    if certificate_ai_cache is not None:
        certificate_ai_cache[certificate_document.id] = payload
    return payload


def _select_aww_certificate_document_images(
    crops: dict[str, dict[str, str | int]],
) -> dict[str, dict[str, str | int]]:
    return _select_impol_certificate_document_images(crops)


def _extract_aww_certificate_payload_from_openai(
    page_images: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> dict[str, object]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi questo certificato materiale AWW. "
                "Scopo: estrarre i dati identificativi e tecnici del certificato, leggere composizione chimica, proprieta meccaniche e note tecniche rilevanti. "
                "Per il match con il DDT i campi forti sono Kunden-Teile-Nr., Artikel-Nr. e Auftragsbestätigung. "
                "Kunden-Teile-Nr. corrisponde al customer material number. Artikel-Nr. corrisponde al part number. "
                "Auftragsbestätigung deve essere letto dal campo Auftragsbestätigung e restituito anche come root numerico. "
                "La lega deve essere costruita leggendo Werkstoff/Material e Zustand/Temper insieme, senza inventare. "
                "product_raw deve essere il raw del blocco prodotto o della riga Abmessung/dimension, quando li compare il diametro del materiale. "
                "diameter_raw deve venire dal simbolo Ø o dal campo Abmessung/dimension o Product, senza dipendere dalla parola barra. "
                "Nei certificati AWW piu vecchi il diametro puo comparire solo come 'Rundstange 40,00' dentro Abmessung/dimension: in quel caso restituisci quel raw in product_raw e il numero in diameter_raw. "
                "weight_raw deve essere il peso netto / delivery quantity del materiale, non altri numeri tabellari. "
                "Se il certificato indica 'siehe Lieferschein' o 'see delivery note', restituisci quel raw in weight_raw invece di inventare un numero. "
                "Charge No. della tabella chimica e la riga misurata vera. Ignora Soll min e Set value max. "
                "Le proprieta meccaniche hanno due blocchi distinti: blocco standard e blocco simulated heat treatment. "
                "Non fonderli mai. Se il blocco standard ha una vera riga misurata di Charge No., estraila in standard_measured_row. "
                "Se il blocco standard non ha una vera riga misurata, lascia standard_measured_row null. "
                "Per il blocco simulated heat treatment, estrai simulated_measured_row solo se esiste una vera riga misurata di Charge No.. "
                "Usa solo testo realmente visibile nel documento. Non inventare, non inferire e non normalizzare. "
                "Se un campo non e chiaramente leggibile, restituisci null. "
                "Restituisci solo JSON con questa struttura: "
                "{\"core\":{\"numero_certificato\":\"string|null\",\"ordine_cliente\":\"string|null\",\"articolo\":\"string|null\","
                "\"profile_code\":\"string|null\",\"lega\":\"string|null\",\"descrizione_profilo_cliente\":\"string|null\","
                "\"colata\":\"string|null\",\"peso_netto\":\"string|null\",\"customer_material_number_raw\":\"string|null\","
                "\"article_number_raw\":\"string|null\",\"order_confirmation_raw\":\"string|null\",\"customer_order_raw\":\"string|null\","
                "\"material_raw\":\"string|null\",\"temper_raw\":\"string|null\",\"product_raw\":\"string|null\","
                "\"diameter_raw\":\"string|null\",\"weight_raw\":\"string|null\",\"charge_number_raw\":\"string|null\"},"
                "\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\",\"Mn\":\"string|null\",\"Mg\":\"string|null\","
                "\"Cr\":\"string|null\",\"Ni\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\",\"Cd\":\"string|null\",\"Hg\":\"string|null\","
                "\"Pb\":\"string|null\",\"V\":\"string|null\",\"Bi\":\"string|null\",\"Sn\":\"string|null\",\"Zr\":\"string|null\",\"Be\":\"string|null\",\"Zr+Ti\":\"string|null\",\"Mn+Cr\":\"string|null\","
                "\"Bi+Pb\":\"string|null\"},"
                "\"mechanical_raw\":{\"standard_measured_row\":{\"Rm\":\"string|null\",\"Rp0.2\":\"string|null\",\"A%\":\"string|null\",\"HB\":\"string|null\",\"IACS%\":\"string|null\",\"Rp0.2/Rm\":\"string|null\"},"
                "\"simulated_measured_row\":{\"Rm\":\"string|null\",\"Rp0.2\":\"string|null\",\"A%\":\"string|null\",\"HB\":\"string|null\",\"IACS%\":\"string|null\",\"Rp0.2/Rm\":\"string|null\"}},"
                "\"notes_raw\":{\"nota_us_control_class_a_raw\":\"string|null\",\"nota_us_control_class_b_raw\":\"string|null\","
                "\"nota_rohs_raw\":\"string|null\",\"nota_radioactive_free_raw\":\"string|null\"}}"
            ),
        }
    ]

    for image_label, crop in page_images.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": (
                    f"Image label: {image_label}; "
                    f"page_number: {crop.get('page_number') or 'unknown'}"
                ),
            }
        )
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="AWW certificate AI extraction request failed") from exc

    return _parse_openai_json_payload_for_certificate_bundle(response.output_text)


def _normalize_aww_certificate_ai_payload(
    page_images: dict[str, dict[str, str | int]],
    raw_payload: dict[str, object],
) -> dict[str, object]:
    first_page_crop = next(iter(page_images.values()), None)
    first_page_id = int(first_page_crop.get("page_id")) if first_page_crop and first_page_crop.get("page_id") else 0
    last_page_crop = next(reversed(page_images.values()), None) if page_images else None
    last_page_id = int(last_page_crop.get("page_id")) if last_page_crop and last_page_crop.get("page_id") else first_page_id

    core_payload = cast(dict[str, object], raw_payload.get("core") or {})
    core_fields = _sanitize_aww_vision_certificate_fields(core_payload, next(iter(page_images.keys()), None))

    chemistry_payload = cast(dict[str, object], raw_payload.get("chemistry_raw") or {})
    chemistry_matches = _normalize_vision_numeric_matches(
        {
            field_name: {
                "value": _string_or_none(chemistry_payload.get(field_name)),
                "evidence": _string_or_none(chemistry_payload.get(field_name)),
                "source_crop": next(iter(page_images.keys()), None),
            }
            for field_name in ("Si", "Fe", "Cu", "Mn", "Mg", "Cr", "Ni", "Zn", "Ti", "Cd", "Hg", "Pb", "V", "Bi", "Sn", "Zr", "Be", "Zr+Ti", "Mn+Cr", "Bi+Pb")
        },
        {
            next(iter(page_images.keys()), "page1"): {
                "page_id": first_page_id,
                "page_number": first_page_crop.get("page_number") if first_page_crop else 1,
            }
        },
    )

    mechanical_payload = cast(dict[str, object], raw_payload.get("mechanical_raw") or {})
    property_matches = _normalize_aww_measured_rows_payload(
        mechanical_payload,
        page_id=first_page_id,
    )

    notes_payload = cast(dict[str, object], raw_payload.get("notes_raw") or {})
    note_matches = _normalize_vision_note_matches(
        _build_vision_note_extracted_payload(notes_payload, next(reversed(page_images.keys()), None) if page_images else None),
        {
            next(reversed(page_images.keys()), "page1"): {
                "page_id": last_page_id,
                "page_number": last_page_crop.get("page_number") if last_page_crop else (first_page_crop.get("page_number") if first_page_crop else 1),
            }
        },
    )

    customer_material_raw = _string_or_none(core_payload.get("customer_material_number_raw")) or _string_or_none(core_payload.get("articolo"))
    part_number_raw = _string_or_none(core_payload.get("article_number_raw")) or _string_or_none(core_payload.get("profile_code"))
    order_confirmation_raw = _string_or_none(core_payload.get("order_confirmation_raw"))
    customer_order_raw = _string_or_none(core_payload.get("customer_order_raw")) or _string_or_none(core_payload.get("ordine_cliente"))
    material_raw = _string_or_none(core_payload.get("material_raw"))
    temper_raw = _string_or_none(core_payload.get("temper_raw"))
    product_raw = _string_or_none(core_payload.get("product_raw"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw")) or product_raw
    weight_raw = _string_or_none(core_payload.get("weight_raw")) or _string_or_none(core_payload.get("peso_netto"))

    return {
        "match_values": {
            field_name: _string_or_none(field_payload.get("value"))
            for field_name, field_payload in core_fields.items()
        },
        "supplier_fields": {
            "article": _normalize_aww_customer_material_from_text(customer_material_raw),
            "profile_code": _normalize_aww_part_number_from_text(part_number_raw),
            "supplier_order_no": _normalize_aww_order_confirmation_root(order_confirmation_raw),
            "customer_order_no": _normalize_aww_customer_order_token(customer_order_raw),
            "alloy": _normalize_aww_alloy_from_text(" ".join(item for item in (material_raw, temper_raw) if item)),
            "diameter": _normalize_aww_diameter_from_text(diameter_raw),
            "weight": reader_normalize_aww_weight_result(weight_raw),
        },
        "core_fields": core_fields,
        "chemistry": chemistry_matches,
        "properties": property_matches,
        "notes": note_matches,
        "debug_raw_output": json.dumps(raw_payload, ensure_ascii=False),
    }


def _enrich_aww_certificate_ai_payload_from_pages(
    payload: dict[str, object],
    pages: list[DocumentPage],
) -> dict[str, object]:
    if not pages:
        return payload
    supplier_fields = cast(dict[str, object], payload.get("supplier_fields") or {})
    if _string_or_none(cast(str | None, supplier_fields.get("diameter"))) is not None:
        return payload

    fallback_text = _collect_page_text_subset(_document_page_text_map(pages), [])
    dimension_context = _extract_aww_dimension_context_from_document_text(fallback_text)
    normalized_diameter = _normalize_aww_diameter_from_text(dimension_context)
    if normalized_diameter is None:
        return payload

    supplier_fields["diameter"] = normalized_diameter
    payload["supplier_fields"] = supplier_fields

    core_fields = cast(dict[str, dict[str, str | None]], payload.get("core_fields") or {})
    core_fields["diametro_certificato"] = {
        "value": normalized_diameter,
        "evidence": dimension_context,
        "source_crop": next(iter(core_fields.values()), {}).get("source_crop") if core_fields else None,
    }
    payload["core_fields"] = core_fields

    match_values = cast(dict[str, str | None], payload.get("match_values") or {})
    match_values["diametro_certificato"] = normalized_diameter
    payload["match_values"] = match_values
    return payload


def _sanitize_aww_vision_certificate_fields(
    core_payload: dict[str, object],
    source_crop: str | None,
) -> dict[str, dict[str, str | None]]:
    customer_material_raw = _string_or_none(core_payload.get("customer_material_number_raw")) or _string_or_none(core_payload.get("articolo"))
    part_number_raw = _string_or_none(core_payload.get("article_number_raw")) or _string_or_none(core_payload.get("profile_code"))
    order_confirmation_raw = _string_or_none(core_payload.get("order_confirmation_raw"))
    customer_order_raw = _string_or_none(core_payload.get("customer_order_raw")) or _string_or_none(core_payload.get("ordine_cliente"))
    material_raw = _string_or_none(core_payload.get("material_raw"))
    temper_raw = _string_or_none(core_payload.get("temper_raw"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw")) or _string_or_none(core_payload.get("product_raw"))
    weight_raw = _string_or_none(core_payload.get("weight_raw")) or _string_or_none(core_payload.get("peso_netto"))
    charge_raw = _string_or_none(core_payload.get("charge_number_raw")) or _string_or_none(core_payload.get("colata"))
    certificate_number_raw = _string_or_none(core_payload.get("numero_certificato"))

    def _payload(value: str | None) -> dict[str, str | None]:
        return {"value": value, "evidence": value, "source_crop": source_crop}

    normalized_article = _normalize_aww_customer_material_from_text(customer_material_raw)
    normalized_profile = _normalize_aww_part_number_from_text(part_number_raw)
    normalized_order = _normalize_aww_customer_order_token(customer_order_raw)
    normalized_alloy = _normalize_aww_alloy_from_text(" ".join(item for item in (material_raw, temper_raw) if item))
    normalized_diameter = _normalize_aww_diameter_from_text(diameter_raw)
    normalized_weight = reader_normalize_aww_weight_result(weight_raw)
    normalized_charge = _normalize_aww_charge_from_text(charge_raw)

    return {
        "numero_certificato_certificato": _payload(certificate_number_raw),
        "ordine_cliente_certificato": _payload(normalized_order),
        "articolo_certificato": _payload(normalized_article),
        "profile_code_certificato": _payload(normalized_profile),
        "supplier_order_no_certificato": _payload(_normalize_aww_order_confirmation_root(order_confirmation_raw)),
        "codice_cliente_certificato": _payload(None),
        "lega_certificato": _payload(normalized_alloy),
        "descrizione_profilo_cliente_certificato": _payload(None),
        "colata_certificato": _payload(normalized_charge),
        "peso_certificato": _payload(normalized_weight),
        "diametro_certificato": _payload(normalized_diameter),
    }


def _normalize_aww_measured_rows_payload(
    measured_payload: dict[str, object],
    *,
    page_id: int,
) -> dict[str, dict[str, str | int]]:
    standard_row = cast(dict[str, object], measured_payload.get("standard_measured_row") or {})
    simulated_row = cast(dict[str, object], measured_payload.get("simulated_measured_row") or {})

    def _normalized_row(raw_row: dict[str, object]) -> tuple[dict[str, dict[str, str | int]], int]:
        normalized: dict[str, dict[str, str | int]] = {}
        count = 0
        for field_name in ("Rm", "Rp0.2", "A%", "HB", "IACS%", "Rp0.2/Rm"):
            raw_value = _string_or_none(raw_row.get(field_name))
            standardized = _normalize_numeric_value(raw_value)
            if standardized is None:
                continue
            normalized[field_name] = {
                "page_id": page_id,
                "snippet": f"{field_name}={raw_value}",
                "raw": standardized,
                "standardized": standardized,
                "final": standardized,
                "method": "chatgpt",
            }
            count += 1
        return normalized, count

    standard_matches, standard_count = _normalized_row(standard_row)
    simulated_matches, simulated_count = _normalized_row(simulated_row)

    core_fields = {"Rm", "Rp0.2", "A%", "HB"}
    standard_core_count = sum(1 for field_name in core_fields if field_name in standard_matches)
    simulated_core_count = sum(1 for field_name in core_fields if field_name in simulated_matches)

    # AWW certificates can expose a partial standard block (for example only HB)
    # above a complete simulated-heat-treatment measured row. In those cases
    # prefer the richer row instead of accepting the first non-empty block.
    if simulated_core_count >= 3 and simulated_core_count > standard_core_count:
        return simulated_matches
    if standard_core_count >= 3:
        return standard_matches
    if simulated_count > standard_count:
        return simulated_matches
    if standard_count >= 1:
        return standard_matches
    return simulated_matches


def _normalize_aww_charge_from_text(value: str | None) -> str | None:
    return _extract_token_from_value_or_evidence(value, value, r"\b\d{5,7}\b")


def _get_neuman_certificate_ai_payload(
    db: Session,
    *,
    certificate_document: Document,
    openai_api_key: str,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> dict[str, object]:
    cached = certificate_ai_cache.get(certificate_document.id) if certificate_ai_cache is not None else None
    if cached is not None:
        return cached

    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)
    if not _document_has_image_pages(certificate_document):
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    crops = _build_certificate_safe_crops(certificate_document.pages, supplier_key="neuman")
    page_images = _select_neuman_certificate_document_images(crops)
    if not page_images:
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    raw_payload = _extract_neuman_certificate_payload_from_openai(
        page_images,
        openai_api_key=openai_api_key,
    )
    payload = _normalize_neuman_certificate_ai_payload(page_images, raw_payload)
    if certificate_ai_cache is not None:
        certificate_ai_cache[certificate_document.id] = payload
    return payload


def _select_neuman_certificate_document_images(
    crops: dict[str, dict[str, str | int]],
) -> dict[str, dict[str, str | int]]:
    return _select_impol_certificate_document_images(crops)


def _extract_neuman_certificate_payload_from_openai(
    page_images: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> dict[str, object]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi questo certificato materiale Neuman. "
                "Scopo: estrarre i dati identificativi e tecnici del certificato, leggere composizione chimica e note tecniche rilevanti per il match con il DDT. "
                "Per questo fornitore Lot number e il riferimento tecnico forte e puo essere trattato anche come cdq e colata. "
                "Delivery note e il numero DDT. Customer material number e il codice articolo lato certificato. Material identifica la lega. "
                "diameter_raw deve venire dal simbolo Ø o dal Product, senza dipendere dalla parola barra. "
                "net_weight_raw deve essere il Net weight [kg] del materiale, non la Length o altri numeri vicini. "
                "Se il certificato riporta solo limiti richiesti o conferme di compliance meccanica, non inventare valori misurati: mechanical_raw.measured_rows deve essere una lista vuota. "
                "Usa solo testo realmente visibile nel documento. Non inventare, non inferire e non normalizzare. "
                "Se un campo non e chiaramente leggibile, restituisci null. "
                "Campi core da estrarre. "
                "numero_certificato: per questo fornitore usa il valore di Lot number. "
                "ordine_cliente: estrai il Customer order number solo se esiste chiaramente nel certificato, altrimenti null. "
                "articolo: estrai Customer material number. "
                "lega: estrai il materiale dal campo Material. "
                "descrizione_profilo_cliente: usa null se non esiste un campo separato equivalente. "
                "colata: estrai il valore di Lot number. "
                "peso_netto: estrai il valore di Net weight [kg]. "
                "Campi runtime di supporto da estrarre inoltre. "
                "delivery_note_raw: estrai Delivery note. "
                "lot_number_raw: estrai Lot number. "
                "customer_material_number_raw: estrai Customer material number. "
                "customer_order_number_raw: estrai Customer order number se presente. "
                "material_raw: estrai Material. "
                "product_raw: estrai Product. "
                "diameter_raw: estrai il diametro raw dal Product o dal simbolo Ø. "
                "net_weight_raw: estrai il Net weight [kg]. "
                "Chimica: usa solo Si, Fe, Cu, Mn, Mg, Cr, Ni, Zn, Ti, Cd, Hg, Pb, V, Bi, Sn, Zr, Be, Zr+Ti, Mn+Cr, Bi+Pb; restituisci solo i valori misurati veri della riga lotto e ignora Min e Max. "
                "Proprieta meccaniche: se il certificato mostra un vero blocco misurato di Hardness and mechanical properties, "
                "estrai una measured_rows con i valori misurati reali. "
                "Per questo fornitore il blocco misurato puo apparire in forma compatta vicino a 'after simulated heat treatment acc. customer requirements' "
                "e a 'Hardness and mechanical properties', con i quattro valori misurati del lotto per HB, A%, Rp0.2 e Rm. "
                "Usa i label e le unita vicine ([HB], [%], [MPa]) per associare correttamente i valori; "
                "non trattare i limiti min/max come valori misurati. "
                "Se non esiste una vera riga o un vero blocco misurato, restituisci measured_rows vuoto. "
                "Note: verifica nota_us_control_class_a, nota_us_control_class_b, nota_rohs, nota_radioactive_free; se compaiono sia Class A sia Class B restituisci entrambe. "
                "Restituisci solo JSON con questa struttura: "
                "{\"core\":{\"numero_certificato\":\"string|null\",\"ordine_cliente\":\"string|null\",\"articolo\":\"string|null\","
                "\"lega\":\"string|null\",\"descrizione_profilo_cliente\":\"string|null\",\"colata\":\"string|null\",\"peso_netto\":\"string|null\","
                "\"delivery_note_raw\":\"string|null\",\"lot_number_raw\":\"string|null\",\"customer_material_number_raw\":\"string|null\","
                "\"customer_order_number_raw\":\"string|null\",\"material_raw\":\"string|null\",\"product_raw\":\"string|null\","
                "\"diameter_raw\":\"string|null\",\"net_weight_raw\":\"string|null\"},"
                "\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\",\"Mn\":\"string|null\",\"Mg\":\"string|null\","
                "\"Cr\":\"string|null\",\"Ni\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\",\"Cd\":\"string|null\",\"Hg\":\"string|null\","
                "\"Pb\":\"string|null\",\"V\":\"string|null\",\"Bi\":\"string|null\",\"Sn\":\"string|null\",\"Zr\":\"string|null\",\"Be\":\"string|null\",\"Zr+Ti\":\"string|null\",\"Mn+Cr\":\"string|null\","
                "\"Bi+Pb\":\"string|null\"},"
                "\"mechanical_raw\":{\"measured_rows\":[{\"Rm\":\"string|null\",\"Rp0.2\":\"string|null\",\"A%\":\"string|null\",\"HB\":\"string|null\","
                "\"IACS%\":\"string|null\",\"Rp0.2/Rm\":\"string|null\"}]},"
                "\"notes_raw\":{\"nota_us_control_class_a_raw\":\"string|null\",\"nota_us_control_class_b_raw\":\"string|null\","
                "\"nota_rohs_raw\":\"string|null\",\"nota_radioactive_free_raw\":\"string|null\"}}"
            ),
        }
    ]

    for image_label, crop in page_images.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": (
                    f"Image label: {image_label}; "
                    f"page_number: {crop.get('page_number') or 'unknown'}"
                ),
            }
        )
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Neuman certificate AI extraction request failed") from exc

    return _parse_openai_json_payload_for_certificate_bundle(response.output_text)


def _normalize_neuman_certificate_ai_payload(
    page_images: dict[str, dict[str, str | int]],
    raw_payload: dict[str, object],
) -> dict[str, object]:
    first_page_crop = next(iter(page_images.values()), None)
    first_page_id = int(first_page_crop.get("page_id")) if first_page_crop and first_page_crop.get("page_id") else 0
    last_page_crop = next(reversed(page_images.values()), None) if page_images else None
    last_page_id = int(last_page_crop.get("page_id")) if last_page_crop and last_page_crop.get("page_id") else first_page_id

    core_payload = cast(dict[str, object], raw_payload.get("core") or {})
    core_fields = _sanitize_neuman_vision_certificate_fields(core_payload, next(iter(page_images.keys()), None))

    chemistry_payload = cast(dict[str, object], raw_payload.get("chemistry_raw") or {})
    chemistry_matches = _normalize_vision_numeric_matches(
        {
            field_name: {
                "value": _string_or_none(chemistry_payload.get(field_name)),
                "evidence": _string_or_none(chemistry_payload.get(field_name)),
                "source_crop": next(iter(page_images.keys()), None),
            }
            for field_name in ("Si", "Fe", "Cu", "Mn", "Mg", "Cr", "Ni", "Zn", "Ti", "Cd", "Hg", "Pb", "V", "Bi", "Sn", "Zr", "Be", "Zr+Ti", "Mn+Cr", "Bi+Pb")
        },
        {
            next(iter(page_images.keys()), "page1"): {
                "page_id": first_page_id,
                "page_number": first_page_crop.get("page_number") if first_page_crop else 1,
            }
        },
    )

    measured_rows_payload = cast(dict[str, object], raw_payload.get("mechanical_raw") or {}).get("measured_rows") or []
    property_matches = _normalize_aluminium_bozen_measured_rows_payload(
        measured_rows_payload if isinstance(measured_rows_payload, list) else [],
        page_id=first_page_id,
    )

    notes_payload = cast(dict[str, object], raw_payload.get("notes_raw") or {})
    note_matches = _normalize_vision_note_matches(
        _build_vision_note_extracted_payload(notes_payload, next(reversed(page_images.keys()), None) if page_images else None),
        {
            next(reversed(page_images.keys()), "page1"): {
                "page_id": last_page_id,
                "page_number": last_page_crop.get("page_number") if last_page_crop else (first_page_crop.get("page_number") if first_page_crop else 1),
            }
        },
    )

    delivery_note_raw = _string_or_none(core_payload.get("delivery_note_raw"))
    lot_raw = _string_or_none(core_payload.get("lot_number_raw")) or _string_or_none(core_payload.get("colata")) or _string_or_none(core_payload.get("numero_certificato"))
    article_raw = _string_or_none(core_payload.get("customer_material_number_raw")) or _string_or_none(core_payload.get("articolo"))
    customer_order_raw = _string_or_none(core_payload.get("customer_order_number_raw")) or _string_or_none(core_payload.get("ordine_cliente"))
    material_raw = _string_or_none(core_payload.get("material_raw")) or _string_or_none(core_payload.get("lega"))
    product_raw = _string_or_none(core_payload.get("product_raw"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw")) or product_raw
    weight_raw = _string_or_none(core_payload.get("net_weight_raw")) or _string_or_none(core_payload.get("peso_netto"))

    return {
        "match_values": {
            field_name: _string_or_none(field_payload.get("value"))
            for field_name, field_payload in core_fields.items()
        },
        "supplier_fields": {
            "delivery_note_no": _sanitize_neuman_ddt_number_candidate(delivery_note_raw),
            "lot_number": _normalize_neuman_lot_token(lot_raw),
            "customer_material_number": _normalize_neuman_article_from_text(article_raw),
            "customer_order_number": _normalize_neuman_customer_order_token(customer_order_raw),
            "alloy": _normalize_neuman_alloy_from_text(material_raw),
            "diameter": _normalize_neuman_diameter_from_text(diameter_raw),
            "weight": reader_normalize_neuman_weight_result(weight_raw),
            "product_raw": _string_or_none(product_raw),
        },
        "core_fields": core_fields,
        "chemistry": chemistry_matches,
        "properties": property_matches,
        "notes": note_matches,
        "debug_raw_output": json.dumps(raw_payload, ensure_ascii=False),
    }


def _sanitize_neuman_vision_certificate_fields(
    core_payload: dict[str, object],
    source_crop: str | None,
) -> dict[str, dict[str, str | None]]:
    lot_raw = _string_or_none(core_payload.get("lot_number_raw")) or _string_or_none(core_payload.get("colata")) or _string_or_none(core_payload.get("numero_certificato"))
    article_raw = _string_or_none(core_payload.get("customer_material_number_raw")) or _string_or_none(core_payload.get("articolo"))
    order_raw = _string_or_none(core_payload.get("customer_order_number_raw")) or _string_or_none(core_payload.get("ordine_cliente"))
    material_raw = _string_or_none(core_payload.get("material_raw")) or _string_or_none(core_payload.get("lega"))
    diameter_raw = _string_or_none(core_payload.get("diameter_raw")) or _string_or_none(core_payload.get("product_raw"))
    weight_raw = _string_or_none(core_payload.get("net_weight_raw")) or _string_or_none(core_payload.get("peso_netto"))

    def _payload(value: str | None) -> dict[str, str | None]:
        return {"value": value, "evidence": value, "source_crop": source_crop}

    normalized_lot = _normalize_neuman_lot_token(lot_raw)
    normalized_order = _normalize_neuman_customer_order_token(order_raw)
    normalized_article = _normalize_neuman_article_from_text(article_raw)
    normalized_alloy = _normalize_neuman_alloy_from_text(material_raw)
    normalized_diameter = _normalize_neuman_diameter_from_text(diameter_raw)
    normalized_weight = reader_normalize_neuman_weight_result(weight_raw)

    return {
        "numero_certificato_certificato": _payload(normalized_lot),
        "ordine_cliente_certificato": _payload(normalized_order),
        "articolo_certificato": _payload(normalized_article),
        "codice_cliente_certificato": _payload(None),
        "lega_certificato": _payload(normalized_alloy),
        "descrizione_profilo_cliente_certificato": _payload(None),
        "colata_certificato": _payload(normalized_lot),
        "peso_certificato": _payload(normalized_weight),
        "diametro_certificato": _payload(normalized_diameter),
    }


def _apply_aluminium_bozen_certificate_ai_payload(
    db: Session,
    *,
    row: AcquisitionRow,
    payload: dict[str, object],
    actor_id: int,
) -> None:
    certificate_document = get_document(db, row.document_certificato_id)
    raw_payload_text = _string_or_none(cast(dict[str, object], payload).get("debug_raw_output"))
    if raw_payload_text:
        _create_ai_payload_evidence(
            db=db,
            row_id=row.id,
            document_id=certificate_document.id,
            document_page_id=certificate_document.pages[0].id if certificate_document.pages else None,
            blocco="match",
            payload_text=raw_payload_text,
            actor_id=actor_id,
            confidence=0.77,
        )
    core_fields = cast(dict[str, dict[str, str | None]], payload.get("core_fields") or {})
    for field_name, field_payload in core_fields.items():
        field_value = _string_or_none(field_payload.get("value"))
        if field_value is None or _has_stable_value_protected_from_ai(row, "match", field_name):
            continue
        evidence = _string_or_none(field_payload.get("evidence")) or field_value
        evidence_model = _create_text_evidence(
            db=db,
            row_id=row.id,
            document_id=certificate_document.id,
            document_page_id=certificate_document.pages[0].id if certificate_document.pages else None,
            blocco="match",
            snippet=evidence,
            actor_id=actor_id,
            confidence=0.77,
        )
        _upsert_read_value_model(
            db=db,
            acquisition_row_id=row.id,
            blocco="match",
            campo=field_name,
            valore_grezzo=field_value,
            valore_standardizzato=field_value,
            valore_finale=field_value,
            stato="proposto",
            document_evidence_id=evidence_model.id,
            metodo_lettura="chatgpt",
            fonte_documentale="certificato",
            confidenza=0.77,
            actor_id=actor_id,
        )

    for block_name, confidence in (("chemistry", 0.76), ("properties", 0.74), ("notes", 0.74)):
        block_key = {"chemistry": "chimica", "properties": "proprieta", "notes": "note"}[block_name]
        matches = cast(dict[str, dict[str, str | int]], payload.get(block_name) or {})
        if not matches:
            continue
        _prune_unconfirmed_block_values(db=db, row_id=row.id, block=block_key, keep_fields=set(matches.keys()))
        for field_name, match in matches.items():
            snippet = _string_or_none(cast(dict[str, object], match).get("snippet")) or _string_or_none(cast(dict[str, object], match).get("final")) or ""
            page_id = cast(dict[str, object], match).get("page_id")
            evidence = _create_text_evidence(
                db=db,
                row_id=row.id,
                document_id=certificate_document.id,
                document_page_id=int(page_id) if page_id else None,
                blocco=block_key,
                snippet=snippet,
                actor_id=actor_id,
                confidence=confidence,
            )
            _upsert_read_value_model(
                db=db,
                acquisition_row_id=row.id,
                blocco=block_key,
                campo=field_name,
                valore_grezzo=_string_or_none(cast(dict[str, object], match).get("raw")) or _string_or_none(cast(dict[str, object], match).get("final")),
                valore_standardizzato=_string_or_none(cast(dict[str, object], match).get("standardized")) or _string_or_none(cast(dict[str, object], match).get("final")),
                valore_finale=_string_or_none(cast(dict[str, object], match).get("final")),
                stato="proposto",
                document_evidence_id=evidence.id,
                metodo_lettura="chatgpt",
                fonte_documentale="certificato",
                confidenza=confidence,
                actor_id=actor_id,
            )

    _sync_row_from_match_values(db, row)
    _sync_row_statuses(db, row)
    db.add(row)


