def _extract_zalco_ddt_row_groups_with_vision(
    db: Session,
    *,
    ddt_document: Document,
    openai_api_key: str,
) -> list[ReaderRowSplitCandidateResponse]:
    if not ddt_document.pages:
        ddt_document = _index_document_from_path(db, ddt_document)
    ddt_document = _ensure_document_page_images(db, ddt_document)

    image_pages = [page for page in ddt_document.pages if page.immagine_pagina_storage_key]
    if not image_pages:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="DDT has no image pages available for AI")

    crop_definitions = _build_zalco_ddt_group_crops(image_pages)
    if not crop_definitions:
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Unable to prepare Zalco DDT pages for AI")

    local_matches = reader_detect_ddt_core_matches(ddt_document.pages, supplier_key="zalco")
    fallback_ddt = _string_or_none(cast(dict[str, object], local_matches.get("ddt") or {}).get("final"))
    ddt_number_raw, raw_rows, ai_document_payload_raw = _extract_zalco_ddt_row_groups_from_openai(
        crop_definitions,
        openai_api_key=openai_api_key,
    )
    return _sanitize_zalco_ai_row_groups(
        ddt_number_raw=ddt_number_raw or fallback_ddt,
        raw_rows=raw_rows,
        ai_document_payload_raw=ai_document_payload_raw,
    )


def _build_zalco_ddt_group_crops(
    pages: list[DocumentPage],
) -> dict[str, dict[str, str | int]]:
    crops: dict[str, dict[str, str | int]] = {}
    image_pages = [page for page in sorted(pages, key=lambda item: item.numero_pagina) if page.immagine_pagina_storage_key]
    for index, page in enumerate(image_pages):
        image_path = get_document_page_image_path(page)
        with Image.open(image_path) as image:
            masked_page = _build_zalco_masked_page(image)
            storage_key = _save_ddt_crop(page, masked_page, f"zalco_masked_page_{page.numero_pagina}")
            width, height = masked_page.size
            roles = [("row_groups_page", "row_groups_page")]
            if index == 0:
                roles.insert(0, ("header_page", "header_page"))
            else:
                roles.insert(0, ("continuation_page", "continuation_page"))
            for suffix, role in roles:
                label = f"page{page.numero_pagina}_{suffix}"
                crops[label] = {
                    "label": label,
                    "role": role,
                    "page_id": page.id,
                    "page_number": page.numero_pagina,
                    "storage_key": storage_key,
                    "bbox": f"0,0,{width},{height}",
                }
    return crops


def _extract_zalco_ddt_row_groups_from_openai(
    crops: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> tuple[str | None, list[dict[str, object]], str]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi queste immagini di un DDT Zalco / Zeeland Aluminium Company. "
                "Una riga acquisition corrisponde al documento tally/packing utile, non alle singole righe FAR/bundle. "
                "Non usare annotazioni a penna e non usare il nome file. "
                "Se trovi LISTE DE COLISAGE / PACKING LIST WITH ANALYSIS, usa quella pagina come sorgente forte. "
                "Se trovi solo AVIS D'EXPEDITION / TALLY SHEET che rimanda a VOIR LISTE DE COLISAGE, restituisci comunque i campi visibili ma lascia cast_raw nullo se non c'e' la colata reale. "
                "Campi da leggere: tally_sheet_raw e' No. AVIS / TALLY SHEET o il numero finale tipo 000020285; "
                "order_raw e' No. ORDRE / Order Nr. o ordine cliente; symbol_raw e' SYMBOLE/CUSTOMER ALLOY CODE tipo 608213; "
                "code_art_raw e' CODE ART/CODE tipo 0381Z; diameter_raw e' FORMAT o DIAMETER OR SIZES; "
                "weight_raw e' POIDS NET/NET; cast_raw e' No. COULEE/CAST Nr. completo, ad esempio 2023 42669; "
                "alloy_raw e' la lega/stato stampata, ad esempio 6082 HO; chemistry_raw contiene solo valori misurati, non limiti. "
                "Restituisci solo JSON con questa struttura: "
                "{\"ddt_number_raw\":\"string|null\",\"rows\":[{\"row_index\":1,\"tally_sheet_raw\":\"string|null\","
                "\"order_raw\":\"string|null\",\"symbol_raw\":\"string|null\",\"code_art_raw\":\"string|null\","
                "\"diameter_raw\":\"string|null\",\"weight_raw\":\"string|null\",\"cast_raw\":\"string|null\","
                "\"alloy_raw\":\"string|null\",\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\","
                "\"Mn\":\"string|null\",\"Mg\":\"string|null\",\"Cr\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\"},"
                "\"source_crops\":[\"label\"]}]}"
            ),
        }
    ]

    for crop_label, crop in crops.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append(
            {
                "type": "input_text",
                "text": f"Crop label: {crop_label}; role: {crop.get('role') or 'unknown'}; page_number: {crop.get('page_number') or 'unknown'}",
            }
        )
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})

    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Zalco DDT row-group AI request failed") from exc

    return (*_parse_openai_json_payload_for_zalco_row_groups(response.output_text), response.output_text)


def _parse_openai_json_payload_for_zalco_row_groups(payload: str) -> tuple[str | None, list[dict[str, object]]]:
    text = payload.strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text)
        text = re.sub(r"\s*```$", "", text)
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, re.DOTALL)
        if not match:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Zalco DDT row-group AI")
        try:
            data = json.loads(match.group(0))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from Zalco DDT row-group AI") from exc

    if not isinstance(data, dict):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Unexpected Zalco DDT row-group AI payload")
    rows_payload = data.get("rows")
    if not isinstance(rows_payload, list):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Missing rows in Zalco DDT row-group AI payload")

    normalized_rows: list[dict[str, object]] = []
    for index, raw_row in enumerate(rows_payload, start=1):
        if not isinstance(raw_row, dict):
            continue
        source_crops = raw_row.get("source_crops")
        normalized_sources = [
            item
            for item in (_string_or_none(source_crop) for source_crop in (source_crops if isinstance(source_crops, list) else []))
            if item is not None
        ]
        chemistry_raw = raw_row.get("chemistry_raw")
        normalized_rows.append(
            {
                "row_index": index,
                "tally_sheet_raw": _string_or_none(raw_row.get("tally_sheet_raw")),
                "order_raw": _string_or_none(raw_row.get("order_raw")),
                "symbol_raw": _string_or_none(raw_row.get("symbol_raw")),
                "code_art_raw": _string_or_none(raw_row.get("code_art_raw")),
                "diameter_raw": _string_or_none(raw_row.get("diameter_raw")),
                "weight_raw": _string_or_none(raw_row.get("weight_raw")),
                "cast_raw": _string_or_none(raw_row.get("cast_raw")),
                "alloy_raw": _string_or_none(raw_row.get("alloy_raw")),
                "chemistry_raw": chemistry_raw if isinstance(chemistry_raw, dict) else {},
                "source_crops": normalized_sources,
            }
        )
    return _string_or_none(data.get("ddt_number_raw")), normalized_rows


def _sanitize_zalco_ai_row_groups(
    *,
    ddt_number_raw: str | None,
    raw_rows: list[dict[str, object]],
    ai_document_payload_raw: str | None = None,
) -> list[ReaderRowSplitCandidateResponse]:
    candidates: list[ReaderRowSplitCandidateResponse] = []
    fallback_tally = _normalize_zalco_tally_number(ddt_number_raw)

    for index, raw_row in enumerate(raw_rows, start=1):
        tally = _normalize_zalco_tally_number(_string_or_none(raw_row.get("tally_sheet_raw"))) or fallback_tally
        symbol = _normalize_zalco_symbol(_string_or_none(raw_row.get("symbol_raw")))
        code_art = _normalize_zalco_code_art(_string_or_none(raw_row.get("code_art_raw")))
        candidate = ReaderRowSplitCandidateResponse(
            candidate_index=index,
            supplier_key="zalco",
            ddt_number=tally,
            cdq=tally,
            customer_order_no=_normalize_zalco_order(_string_or_none(raw_row.get("order_raw"))),
            customer_code=symbol,
            article_code=code_art,
            product_code=code_art,
            lega=_normalize_zalco_alloy(_string_or_none(raw_row.get("alloy_raw"))),
            diametro=_normalize_zalco_diameter(_string_or_none(raw_row.get("diameter_raw"))),
            peso_netto=_normalize_zalco_weight(_string_or_none(raw_row.get("weight_raw"))),
            colata=_normalize_zalco_cast_number(_string_or_none(raw_row.get("cast_raw"))),
            snippets=cast(list[str], raw_row.get("source_crops") or [])[:6],
            ai_row_payload_raw=json.dumps(raw_row, ensure_ascii=False),
            ai_document_payload_raw=ai_document_payload_raw,
        )
        if any(
            getattr(candidate, field_name) is not None
            for field_name in ("ddt_number", "cdq", "customer_order_no", "customer_code", "article_code", "diametro", "peso_netto", "colata")
        ):
            candidates.append(candidate)
    return candidates


def _apply_zalco_ai_row_groups_to_rows(
    db: Session,
    *,
    ddt_document: Document,
    rows: list[AcquisitionRow],
    ai_candidates: list[ReaderRowSplitCandidateResponse],
    actor_id: int,
) -> None:
    if not rows or not ai_candidates:
        return
    pairs: list[tuple[int, int, int]] = []
    ai_by_index = {candidate.candidate_index: candidate for candidate in ai_candidates}
    row_value_maps = {
        row.id: {
            value.campo: _final_value_for_row(value)
            for value in db.query(ReadValue).filter(ReadValue.acquisition_row_id == row.id, ReadValue.blocco == "ddt").all()
        }
        for row in rows
    }
    for row in rows:
        ddt_values = row_value_maps.get(row.id, {})
        for candidate in ai_candidates:
            score = _score_zalco_ai_candidate_against_row(row=row, ddt_values=ddt_values, ai_candidate=candidate)
            if score > 0:
                pairs.append((score, row.id, candidate.candidate_index))
    if not pairs and len(rows) == 1 and len(ai_candidates) == 1:
        pairs.append((1, rows[0].id, ai_candidates[0].candidate_index))
    pairs.sort(reverse=True)
    assigned_rows: set[int] = set()
    assigned_candidates: set[int] = set()
    for _, row_id, candidate_index in pairs:
        if row_id in assigned_rows or candidate_index in assigned_candidates:
            continue
        row = next(item for item in rows if item.id == row_id)
        _apply_zalco_ai_candidate_to_row(
            db=db,
            row=row,
            ai_candidate=ai_by_index[candidate_index],
            actor_id=actor_id,
            document_id=ddt_document.id,
        )
        assigned_rows.add(row_id)
        assigned_candidates.add(candidate_index)


def _score_zalco_ai_candidate_against_row(
    *,
    row: AcquisitionRow,
    ddt_values: dict[str, str | None],
    ai_candidate: ReaderRowSplitCandidateResponse,
) -> int:
    score = 0
    if reader_same_token(_string_or_none(row.cdq) or _string_or_none(ddt_values.get("cdq")), ai_candidate.cdq):
        score += 140
    if reader_same_token(_string_or_none(row.ddt) or _string_or_none(ddt_values.get("ddt")), ai_candidate.ddt_number):
        score += 100
    if reader_same_token(_string_or_none(row.colata) or _string_or_none(ddt_values.get("colata")), ai_candidate.colata):
        score += 90
    if reader_same_token(_string_or_none(row.diametro) or _string_or_none(ddt_values.get("diametro")), ai_candidate.diametro):
        score += 35
    if reader_weights_are_compatible(_string_or_none(row.peso) or _string_or_none(ddt_values.get("peso")), ai_candidate.peso_netto):
        score += 25
    return score


def _apply_zalco_ai_candidate_to_row(
    db: Session,
    *,
    row: AcquisitionRow,
    ai_candidate: ReaderRowSplitCandidateResponse,
    actor_id: int,
    document_id: int,
) -> bool:
    if ai_candidate.ai_row_payload_raw:
        _create_ai_payload_evidence(
            db=db,
            row_id=row.id,
            document_id=document_id,
            document_page_id=row.ddt_document.pages[0].id if row.ddt_document and row.ddt_document.pages else None,
            blocco="ddt",
            payload_text=ai_candidate.ai_row_payload_raw,
            actor_id=actor_id,
            confidence=0.72,
        )
    field_values = {
        "ddt": ai_candidate.ddt_number,
        "numero_certificato_ddt": ai_candidate.cdq,
        "cdq": ai_candidate.cdq,
        "customer_order_no": ai_candidate.customer_order_no,
        "customer_code": ai_candidate.customer_code,
        "article_code": ai_candidate.article_code,
        "product_code": ai_candidate.product_code,
        "lega": ai_candidate.lega,
        "diametro": ai_candidate.diametro,
        "colata": ai_candidate.colata,
        "peso": ai_candidate.peso_netto,
    }
    changed_fields = 0
    for field_name, field_value in field_values.items():
        normalized_value = _string_or_none(field_value)
        if normalized_value is None:
            continue
        if _has_stable_value_protected_from_ai(row, "ddt", field_name):
            continue
        _upsert_read_value_model(
            db=db,
            acquisition_row_id=row.id,
            blocco="ddt",
            campo=field_name,
            valore_grezzo=normalized_value,
            valore_standardizzato=normalized_value,
            valore_finale=normalized_value,
            stato="proposto",
            document_evidence_id=None,
            metodo_lettura="chatgpt",
            fonte_documentale="ddt",
            confidenza=0.72,
            actor_id=actor_id,
        )
        changed_fields += 1
    if changed_fields == 0:
        return False
    _sync_row_from_ddt_values(db, row)
    _sync_ddt_values_from_row_fields(db, row, actor_id=actor_id)
    _sync_row_statuses(db, row)
    db.add(row)
    _record_history_event(
        db=db,
        acquisition_row_id=row.id,
        blocco="ddt",
        azione="gruppi_riga_ai_applicati",
        user_id=actor_id,
        nota_breve=str(changed_fields),
    )
    return True


def _get_zalco_certificate_ai_payload(
    db: Session,
    *,
    certificate_document: Document,
    openai_api_key: str,
    certificate_ai_cache: dict[int, dict[str, object]] | None = None,
) -> dict[str, object]:
    cached = certificate_ai_cache.get(certificate_document.id) if certificate_ai_cache is not None else None
    if cached is not None:
        return cached
    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_images(db, certificate_document)
    if not _document_has_image_pages(certificate_document):
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload

    crops = _build_certificate_safe_crops(certificate_document.pages, supplier_key="zalco")
    page_images = {label: crop for label, crop in crops.items() if str(crop.get("role") or "").startswith(("certificate", "chemistry", "notes"))}
    if not page_images:
        empty_payload = {"match_values": {}, "supplier_fields": {}, "chemistry": {}, "properties": {}, "notes": {}}
        if certificate_ai_cache is not None:
            certificate_ai_cache[certificate_document.id] = empty_payload
        return empty_payload
    raw_payload = _extract_zalco_certificate_payload_from_openai(page_images, openai_api_key=openai_api_key)
    payload = _normalize_zalco_certificate_ai_payload(page_images, raw_payload)
    if certificate_ai_cache is not None:
        certificate_ai_cache[certificate_document.id] = payload
    return payload


def _extract_zalco_certificate_payload_from_openai(
    page_images: dict[str, dict[str, str | int]],
    *,
    openai_api_key: str,
) -> dict[str, object]:
    client = OpenAI(api_key=openai_api_key)
    content: list[dict[str, str]] = [
        {
            "type": "input_text",
            "text": (
                "Leggi questo certificato origine Zalco / Zeeland Aluminium Company. "
                "Non usare certificati Forgialluminio derivati e non usare nome file. "
                "Campi core: tally_sheet_raw e' No. AVIS / TALLY SHEET; order_raw e' No. ORDRE / ORDER Nr.; "
                "symbol_raw e' SYMBOLE/CUSTOMER ALLOY CODE; code_art_raw e' CODE/CODE ART; "
                "diameter_raw e' DIAMETER OR SIZES/FORMAT; weight_raw e' NET; cast_raw e' No. COULEE/CAST Nr. completo; "
                "alloy_raw e' lega/stato visibile come 6082 HO. "
                "Chimica: leggi solo riga valori misurati, non limiti e non testo legale. "
                "Note: verifica nota_us_control_class_a, nota_us_control_class_b, nota_rohs, nota_radioactive_free; se compaiono sia Class A sia Class B restituisci entrambe. "
                "Restituisci solo JSON con questa struttura: "
                "{\"core\":{\"tally_sheet_raw\":\"string|null\",\"order_raw\":\"string|null\",\"symbol_raw\":\"string|null\","
                "\"code_art_raw\":\"string|null\",\"diameter_raw\":\"string|null\",\"weight_raw\":\"string|null\","
                "\"cast_raw\":\"string|null\",\"alloy_raw\":\"string|null\"},"
                "\"chemistry_raw\":{\"Si\":\"string|null\",\"Fe\":\"string|null\",\"Cu\":\"string|null\",\"Mn\":\"string|null\","
                "\"Mg\":\"string|null\",\"Cr\":\"string|null\",\"Zn\":\"string|null\",\"Ti\":\"string|null\"},"
                "\"notes_raw\":{\"nota_us_control_class_a_raw\":\"string|null\",\"nota_us_control_class_b_raw\":\"string|null\","
                "\"nota_rohs_raw\":\"string|null\",\"nota_radioactive_free_raw\":\"string|null\"}}"
            ),
        }
    ]
    for image_label, crop in page_images.items():
        crop_path = _resolve_storage_path(str(crop["storage_key"]))
        encoded = base64.b64encode(crop_path.read_bytes()).decode("utf-8")
        content.append({"type": "input_text", "text": f"Image label: {image_label}; page_number: {crop.get('page_number') or 'unknown'}"})
        content.append({"type": "input_image", "image_url": f"data:image/png;base64,{encoded}", "detail": "high"})
    try:
        response = client.responses.create(
            model=settings.document_vision_model,
            input=[{"role": "user", "content": content}],
        )
    except Exception as exc:
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Zalco certificate AI extraction request failed") from exc
    return _parse_openai_json_payload_for_certificate_bundle(response.output_text)


def _normalize_zalco_certificate_ai_payload(
    page_images: dict[str, dict[str, str | int]],
    raw_payload: dict[str, object],
) -> dict[str, object]:
    first_page_crop = next(iter(page_images.values()), None)
    first_page_id = int(first_page_crop.get("page_id")) if first_page_crop and first_page_crop.get("page_id") else 0
    last_page_crop = next(reversed(page_images.values()), None) if page_images else None
    last_page_id = int(last_page_crop.get("page_id")) if last_page_crop and last_page_crop.get("page_id") else first_page_id
    source_crop = next(iter(page_images.keys()), None)
    core_payload = cast(dict[str, object], raw_payload.get("core") or {})
    core_fields = _sanitize_zalco_vision_certificate_fields(core_payload, source_crop)
    chemistry_payload = cast(dict[str, object], raw_payload.get("chemistry_raw") or {})
    chemistry_matches = _normalize_vision_numeric_matches(
        {
            field_name: {
                "value": _string_or_none(chemistry_payload.get(field_name)),
                "evidence": _string_or_none(chemistry_payload.get(field_name)),
                "source_crop": source_crop,
            }
            for field_name in ("Si", "Fe", "Cu", "Mn", "Mg", "Cr", "Zn", "Ti")
        },
        {source_crop or "page1": {"page_id": first_page_id, "page_number": first_page_crop.get("page_number") if first_page_crop else 1}},
    )
    notes_payload = cast(dict[str, object], raw_payload.get("notes_raw") or {})
    notes_source_crop = next(reversed(page_images.keys()), None) if page_images else None
    note_matches = _normalize_vision_note_matches(
        _build_vision_note_extracted_payload(notes_payload, notes_source_crop),
        {notes_source_crop or "page1": {"page_id": last_page_id, "page_number": last_page_crop.get("page_number") if last_page_crop else 1}},
    )
    tally = _normalize_zalco_tally_number(_string_or_none(core_payload.get("tally_sheet_raw")))
    cast_no = _normalize_zalco_cast_number(_string_or_none(core_payload.get("cast_raw")))
    symbol = _normalize_zalco_symbol(_string_or_none(core_payload.get("symbol_raw")))
    code_art = _normalize_zalco_code_art(_string_or_none(core_payload.get("code_art_raw")))
    return {
        "match_values": {field_name: _string_or_none(field_payload.get("value")) for field_name, field_payload in core_fields.items()},
        "supplier_fields": {
            "tally_sheet_no": tally,
            "cast_no": cast_no,
            "symbol": symbol,
            "code_art": code_art,
        },
        "core_fields": core_fields,
        "chemistry": chemistry_matches,
        "properties": {},
        "notes": note_matches,
        "debug_raw_output": json.dumps(raw_payload, ensure_ascii=False),
    }


def _sanitize_zalco_vision_certificate_fields(
    core_payload: dict[str, object],
    source_crop: str | None,
) -> dict[str, dict[str, str | None]]:
    tally = _normalize_zalco_tally_number(_string_or_none(core_payload.get("tally_sheet_raw")))
    order = _normalize_zalco_order(_string_or_none(core_payload.get("order_raw")))
    symbol = _normalize_zalco_symbol(_string_or_none(core_payload.get("symbol_raw")))
    code_art = _normalize_zalco_code_art(_string_or_none(core_payload.get("code_art_raw")))
    diameter = _normalize_zalco_diameter(_string_or_none(core_payload.get("diameter_raw")))
    weight = _normalize_zalco_weight(_string_or_none(core_payload.get("weight_raw")))
    cast_no = _normalize_zalco_cast_number(_string_or_none(core_payload.get("cast_raw")))
    alloy = _normalize_zalco_alloy(_string_or_none(core_payload.get("alloy_raw")))

    def _payload(value: str | None, evidence: str | None = None) -> dict[str, str | None]:
        return {"value": value, "evidence": evidence or value, "source_crop": source_crop}

    return {
        "numero_certificato_certificato": _payload(tally),
        "ordine_cliente_certificato": _payload(order),
        "lega_certificato": _payload(alloy),
        "diametro_certificato": _payload(diameter),
        "colata_certificato": _payload(cast_no),
        "ddt_certificato": _payload(tally),
        "peso_certificato": _payload(weight),
        "articolo_certificato": _payload(code_art),
        "codice_cliente_certificato": _payload(symbol),
    }


def _build_zalco_certificate_safe_crops(
    pages: list[DocumentPage],
) -> dict[str, dict[str, str | int]]:
    crops: dict[str, dict[str, str | int]] = {}
    image_pages = [page for page in sorted(pages, key=lambda item: item.numero_pagina) if page.immagine_pagina_storage_key]
    for index, page in enumerate(image_pages):
        image_path = get_document_page_image_path(page)
        with Image.open(image_path) as image:
            masked_page = _build_zalco_masked_page(image)
            storage_key = _save_certificate_crop(page, masked_page, f"zalco_masked_page_{page.numero_pagina}")
            width, height = masked_page.size
            role_specs = [
                ("core_page", "certificate_core_context"),
                ("chemistry_page", "chemistry_table"),
                ("notes_page", "notes_block"),
            ]
            if index > 0:
                role_specs.insert(0, ("continuation_page", "certificate_continuation"))
            for suffix, role in role_specs:
                label = f"page{page.numero_pagina}_{suffix}"
                crops[label] = {
                    "label": label,
                    "role": role,
                    "page_id": page.id,
                    "page_number": page.numero_pagina,
                    "storage_key": storage_key,
                    "bbox": f"0,0,{width},{height}",
                }
    return crops


def _build_zalco_masked_page(image: Image.Image) -> Image.Image:
    masked = image.convert("RGB")
    words = _extract_ocr_word_blocks(masked)
    if masked.height > masked.width:
        _mask_relative_rectangle(masked, (0.70, 0.035, 0.96, 0.125))
    else:
        _mask_relative_rectangle(masked, (0.70, 0.035, 0.96, 0.16))
    if words:
        line_map = _group_ocr_words_by_line(words)
        for line_words in line_map.values():
            line_text = " ".join(str(word["text"]).upper() for word in line_words)
            if any(keep in line_text for keep in ("PACKING LIST", "TALLY SHEET", "CODE ART", "CUSTOMER ALLOY", "COULEE", "CAST", "ANALYSE")):
                continue
            if "ZALCO" in line_text or "ZEELAND ALUMINIUM" in line_text:
                _mask_words_matching_terms(
                    masked,
                    line_words,
                    ("ZALCO", "ZEELAND", "ALUMINIUM", "COMPANY"),
                    left_extra=max(4, masked.width // 450),
                    right_extra=max(4, masked.width // 450),
                )
    return masked


def _normalize_zalco_tally_number(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    matches = re.findall(r"\b(0{0,5}\d{5})\b", cleaned)
    if not matches:
        return None
    return str(int(matches[-1]))


def _normalize_zalco_order(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b(20\d{6})\b", cleaned)
    if match is not None:
        return match.group(1)
    match = re.search(r"\bORDER(?:\s+NUMBER)?\s+([0-9]{1,6})\b", cleaned, re.IGNORECASE)
    if match is not None:
        return match.group(1)
    return None


def _normalize_zalco_symbol(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    matches = re.findall(r"\b(\d{5,6})\b", cleaned)
    if not matches:
        return None
    return matches[-1]


def _normalize_zalco_code_art(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    match = re.search(r"\b([0-9]{4}[A-Z])\b", cleaned.upper())
    return match.group(1) if match is not None else None


def _normalize_zalco_diameter(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    anchor_match = re.search(
        r"\b(?:FORMAT|DIAM(?:ETER|ETRE)?(?:\s+OR\s+(?:SIZES|SECTION))?)\b[^0-9]{0,30}([0-9]{2,4}(?:[.,][0-9]+)?)",
        cleaned,
        re.IGNORECASE,
    )
    if anchor_match is not None:
        return _normalize_decimal_value(anchor_match.group(1))
    size_matches = re.findall(r"\b([0-9]{2,4}(?:[.,][0-9]+)?)\b", cleaned)
    filtered = [token for token in size_matches if _normalize_decimal_value(token) not in {"5500", "5000", "5400"}]
    match = re.search(r"\b([0-9]{2,4}(?:[.,][0-9]+)?)\b", filtered[0]) if filtered else None
    return _normalize_decimal_value(match.group(1)) if match is not None else None


def _normalize_zalco_weight(value: str | None) -> str | None:
    return _normalize_value_for_field("ddt", "peso", value)


def _normalize_zalco_cast_number(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = cleaned.replace("/", "-")
    match = re.search(r"\b(20\d{2})\s*[- ]\s*(\d{5})\b", normalized)
    if match is not None:
        return f"{match.group(1)}-{match.group(2)}"
    match = re.search(r"\b(\d{5})\b", normalized)
    return match.group(1) if match is not None else None


def _normalize_zalco_alloy(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    normalized = cleaned.upper().replace("EN AW", " ").replace("-", " ")
    match = re.search(r"\b([0-9]{4})\b(?:\s*(H[O0]|T\d{1,2}|F|O))?", normalized)
    if match is None:
        return None
    temper = match.group(2)
    if temper:
        temper = temper.replace("H0", "HO")
        return f"{match.group(1)} {temper}"
    return match.group(1)


def _parse_openai_json_payload_for_fields(payload: str, field_names: list[str]) -> dict[str, dict[str, str | None]]:
    text = payload.strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text)
        text = re.sub(r"\s*```$", "", text)
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, re.DOTALL)
        if not match:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from vision extraction")
        try:
            data = json.loads(match.group(0))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from vision extraction") from exc

    if not isinstance(data, dict):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Unexpected vision payload structure")

    normalized: dict[str, dict[str, str | None]] = {}
    for field_name in field_names:
        raw_field = data.get(field_name) or {}
        if not isinstance(raw_field, dict):
            raw_field = {"value": _string_or_none(raw_field), "evidence": None, "source_crop": None}
        normalized[field_name] = {
            "value": _string_or_none(raw_field.get("value")),
            "evidence": _string_or_none(raw_field.get("evidence")),
            "source_crop": _string_or_none(raw_field.get("source_crop")),
        }
    return normalized


def _parse_openai_json_payload(payload: str) -> dict[str, dict[str, str | None]]:
    text = payload.strip()
    if text.startswith("```"):
        text = re.sub(r"^```(?:json)?\s*", "", text)
        text = re.sub(r"\s*```$", "", text)
    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        match = re.search(r"\{.*\}", text, re.DOTALL)
        if not match:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from vision extraction")
        try:
            data = json.loads(match.group(0))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Invalid JSON from vision extraction") from exc

    if not isinstance(data, dict):
        raise HTTPException(status_code=status.HTTP_502_BAD_GATEWAY, detail="Unexpected vision payload structure")

    normalized: dict[str, dict[str, str | None]] = {}
    for field_name in ("numero_certificato_ddt", "cdq", "colata", "peso", "diametro", "ordine"):
        raw_field = data.get(field_name) or {}
        if not isinstance(raw_field, dict):
            raw_field = {"value": _string_or_none(raw_field), "evidence": None, "source_crop": None}
        normalized[field_name] = {
            "value": _string_or_none(raw_field.get("value")),
            "evidence": _string_or_none(raw_field.get("evidence")),
            "source_crop": _string_or_none(raw_field.get("source_crop")),
        }
    return normalized


def _sanitize_vision_ddt_fields(
    extracted: dict[str, dict[str, str | None]],
) -> dict[str, dict[str, str | None]]:
    normalized = {field: value.copy() for field, value in extracted.items()}

    ddt_value = _sanitize_ddt_number_candidate(
        _string_or_none(normalized.get("ddt", {}).get("value")),
        _string_or_none(normalized.get("ddt", {}).get("evidence")),
    )
    if "ddt" in normalized:
        normalized["ddt"]["value"] = ddt_value

    cdq_value = _string_or_none(normalized.get("cdq", {}).get("value"))
    cdq_evidence = _string_or_none(normalized.get("cdq", {}).get("evidence"))
    if cdq_value is not None and _looks_like_invalid_cdq(cdq_value, cdq_evidence):
        normalized["cdq"] = {
            "value": None,
            "evidence": cdq_evidence,
            "source_crop": _string_or_none(normalized.get("cdq", {}).get("source_crop")),
        }

    cert_value = _string_or_none(normalized.get("numero_certificato_ddt", {}).get("value"))
    cert_evidence = _string_or_none(normalized.get("numero_certificato_ddt", {}).get("evidence"))
    cert_source_crop = _string_or_none(normalized.get("numero_certificato_ddt", {}).get("source_crop"))
    if cert_value is not None:
        cert_value = _extract_token_from_value_or_evidence(
            cert_value,
            cert_evidence,
            r"\b\d{4,7}[A-Z]?\b",
            disallow={"10204"},
        )
        if cert_value is not None and _looks_like_invalid_cdq(cert_value, cert_evidence):
            cert_value = None
    if "numero_certificato_ddt" in normalized:
        normalized["numero_certificato_ddt"] = {
            "value": cert_value,
            "evidence": cert_evidence,
            "source_crop": cert_source_crop,
        }

    peso_value = _string_or_none(normalized.get("peso", {}).get("value"))
    peso_evidence = _string_or_none(normalized.get("peso", {}).get("evidence"))
    peso_source_crop = _string_or_none(normalized.get("peso", {}).get("source_crop"))
    if peso_value is not None and _looks_like_unreliable_weight(peso_value, peso_evidence, peso_source_crop):
        normalized["peso"] = {
            "value": None,
            "evidence": peso_evidence,
            "source_crop": peso_source_crop,
        }

    ordine_value = _string_or_none(normalized.get("ordine", {}).get("value"))
    ordine_evidence = _string_or_none(normalized.get("ordine", {}).get("evidence"))
    if ordine_value is not None:
        ordine_value = _normalize_order_from_evidence(ordine_value, ordine_evidence)
        normalized["ordine"]["value"] = ordine_value
    if ordine_value is not None and _looks_like_unreliable_order(ordine_value, ordine_evidence):
        normalized["ordine"] = {
            "value": None,
            "evidence": ordine_evidence,
            "source_crop": _string_or_none(normalized.get("ordine", {}).get("source_crop")),
        }

    customer_order_value = _string_or_none(normalized.get("customer_order_no", {}).get("value"))
    customer_order_evidence = _string_or_none(normalized.get("customer_order_no", {}).get("evidence"))
    customer_order_source_crop = _string_or_none(normalized.get("customer_order_no", {}).get("source_crop"))
    if customer_order_value is not None:
        customer_order_value = _normalize_customer_order_tokens(customer_order_value) or _normalize_customer_order_tokens(customer_order_evidence)
        if not _is_normalized_customer_order(customer_order_value):
            customer_order_value = None
    if "customer_order_no" in normalized:
        normalized["customer_order_no"] = {
            "value": customer_order_value,
            "evidence": customer_order_evidence,
            "source_crop": customer_order_source_crop,
        }

    profile_code_payload = normalized.get("profile_code") or normalized.get("customer_code") or {}
    profile_code_value = _string_or_none(profile_code_payload.get("value"))
    profile_code_evidence = _string_or_none(profile_code_payload.get("evidence"))
    profile_code_source_crop = _string_or_none(profile_code_payload.get("source_crop"))
    if profile_code_value is not None:
        profile_code_value = _extract_token_from_value_or_evidence(
            profile_code_value,
            profile_code_evidence,
            r"\bA\d[0-9A-Z]{4,}\b",
        )
    if "profile_code" in normalized or "customer_code" in normalized:
        normalized["profile_code"] = {
            "value": profile_code_value,
            "evidence": profile_code_evidence,
            "source_crop": profile_code_source_crop,
        }

    article_code_value = _string_or_none(normalized.get("article_code", {}).get("value"))
    article_code_evidence = _string_or_none(normalized.get("article_code", {}).get("evidence"))
    article_code_source_crop = _string_or_none(normalized.get("article_code", {}).get("source_crop"))
    if article_code_value is not None:
        article_code_value = _extract_token_from_value_or_evidence(
            article_code_value,
            article_code_evidence,
            r"\b14BT[0-9A-Z-]+\b",
        )
    if "article_code" in normalized:
        normalized["article_code"] = {
            "value": article_code_value,
            "evidence": article_code_evidence,
            "source_crop": article_code_source_crop,
        }

    colata_value = _string_or_none(normalized.get("colata", {}).get("value"))
    colata_evidence = _string_or_none(normalized.get("colata", {}).get("evidence"))
    colata_source_crop = _string_or_none(normalized.get("colata", {}).get("source_crop"))
    if colata_value is not None:
        colata_value = _extract_token_from_value_or_evidence(
            colata_value,
            colata_evidence,
            r"\b(?:[A-Z]\d{5,}[A-Z]?|\d{5,}[A-Z]\d|\d{5,}[A-Z]|\d{5,})\b",
            disallow={"10204"},
        )
    if "colata" in normalized:
        normalized["colata"] = {
            "value": colata_value,
            "evidence": colata_evidence,
            "source_crop": colata_source_crop,
        }

    return normalized


def _extract_token_with_regex(
    text: str,
    pattern: str,
    *,
    disallow: set[str] | None = None,
) -> str | None:
    disallow_set = {token.upper() for token in (disallow or set())}
    for match in re.finditer(pattern, text.upper()):
        token = match.group(0).strip().upper()
        if token in disallow_set:
            continue
        return token
    return None


def _extract_token_from_value_or_evidence(
    value: str | None,
    evidence: str | None,
    pattern: str,
    *,
    disallow: set[str] | None = None,
) -> str | None:
    if value:
        token = _extract_token_with_regex(value, pattern, disallow=disallow)
        if token is not None:
            return token
    if evidence:
        return _extract_token_with_regex(evidence, pattern, disallow=disallow)
    return None


def _sanitize_ddt_number_candidate(value: str | None, evidence: str | None) -> str | None:
    token = _extract_token_from_value_or_evidence(value, evidence, r"\b\d{1,6}\b")
    if token is None:
        return None
    if token in {"0", "10204"}:
        return None
    return token


def _sanitize_impol_ddt_number_candidate(value: str | None, evidence: str | None) -> str | None:
    for haystack in (value, evidence):
        cleaned = _string_or_none(haystack)
        if cleaned is None:
            continue
        match = re.search(r"\b(\d{1,6}-\d{1,2})\b", cleaned)
        if match is not None:
            return match.group(1)
    return _sanitize_ddt_number_candidate(value, evidence)


def _looks_like_invalid_cdq(value: str, evidence: str | None) -> bool:
    haystack = f"{value} {evidence or ''}".lower()
    invalid_markers = (
        "en 10204",
        "inspection certificate",
        "astm",
        "ams",
        "class a",
        "class b",
        "classe a",
        "classe b",
    )
    return any(marker in haystack for marker in invalid_markers)


def _looks_like_unreliable_weight(value: str, evidence: str | None, source_crop: str | None) -> bool:
    haystack = f"{value} {evidence or ''}".lower()
    if any(marker in haystack for marker in ("totale", "total", "packing list", "colli", "imballi")):
        return True
    if source_crop and source_crop.endswith("_lower") and evidence and "peso netto" in haystack and "barra" not in haystack:
        return True
    return False


def _looks_like_unreliable_order(value: str, evidence: str | None) -> bool:
    normalized_value = value.strip().upper()
    if len(normalized_value) < 6:
        return True
    if not re.search(r"\d{4,}", normalized_value):
        return True
    if evidence:
        normalized_evidence = evidence.lower()
        if not any(marker in normalized_evidence for marker in ("ord", "odv", "ordine", "order", "rif")):
            return True
    return False


def _normalize_order_from_evidence(value: str, evidence: str | None) -> str:
    if not evidence:
        return value

    candidates = []
    for raw_candidate in re.findall(r"\d[\d./-]{5,}", evidence):
        candidate = raw_candidate.strip(" .,-")
        if re.fullmatch(r"\d{4}-\d{2}-\d{2}", candidate):
            continue
        if re.fullmatch(r"20\d{2}\.\d{6,}(?:\.\d+)+", candidate):
            candidate = candidate.split(".", 1)[1]
        candidates.append(candidate)

    if not candidates:
        return value

    candidates.sort(key=lambda item: (sum(char.isdigit() for char in item), len(item)))
    return candidates[-1]


def _can_replace_row_field(row: AcquisitionRow, field_name: str) -> bool:
    current_value = getattr(row, field_name)
    if current_value is None:
        return True

    for value in row.values:
        if value.blocco != "ddt" or value.campo != field_name:
            continue
        if value.metodo_lettura == "chatgpt" and value.stato != "confermato":
            return True
    return False


def _has_stable_value_protected_from_ai(row: AcquisitionRow, block: str, field_name: str) -> bool:
    aliases = _ai_guardrail_field_aliases(block, field_name)
    for value in row.values:
        if value.blocco != block or value.campo not in aliases:
            continue
        if value.metodo_lettura == "chatgpt" and value.stato != "confermato":
            continue
        if _final_value_for_row(value) is not None:
            return True
    if block == "ddt":
        return _ddt_row_field_fallback_value(row, field_name) is not None
    return False


def _extract_stable_aluminium_bozen_row_supplier_fields_for_match(
    *,
    row: AcquisitionRow,
    ddt_values: dict[str, str | None],
) -> dict[str, str | None]:
    article = _string_or_none(ddt_values.get("article_code"))
    if not _has_stable_value_protected_from_ai(row, "ddt", "article_code"):
        article = None

    profile_code = _string_or_none(ddt_values.get("profile_code")) or _string_or_none(ddt_values.get("customer_code"))
    if not (
        _has_stable_value_protected_from_ai(row, "ddt", "profile_code")
        or _has_stable_value_protected_from_ai(row, "ddt", "customer_code")
    ):
        profile_code = None

    customer_order = _string_or_none(ddt_values.get("customer_order_no"))
    if not _has_stable_value_protected_from_ai(row, "ddt", "customer_order_no"):
        customer_order = None

    return {
        "article": article,
        "profile_code": profile_code,
        "customer_order_normalized": customer_order,
    }


def _ai_guardrail_field_aliases(block: str, field_name: str) -> tuple[str, ...]:
    if block == "ddt":
        if field_name in {"cdq", "numero_certificato_ddt"}:
            return ("cdq", "numero_certificato_ddt")
        if field_name == "ordine":
            return ("ordine", "customer_order_no")
        if field_name in {"profile_code", "customer_code"}:
            return ("profile_code", "customer_code")
        return (field_name,)
    return (field_name,)


def _ddt_row_field_fallback_value(row: AcquisitionRow, field_name: str) -> str | None:
    if field_name in {"cdq", "numero_certificato_ddt"}:
        return _string_or_none(row.cdq)
    if field_name == "colata":
        return _string_or_none(row.colata)
    if field_name == "peso":
        return _normalize_value_for_field("ddt", "peso", row.peso)
    if field_name == "diametro":
        return _normalize_value_for_field("ddt", "diametro", row.diametro)
    if field_name == "ordine":
        return _string_or_none(row.ordine)
    if field_name == "ddt":
        return _string_or_none(row.ddt)
    if field_name == "lega":
        value = _string_or_none(row.lega_base)
        if value is not None and _resolve_row_supplier_key(row) == "aww" and not _is_valid_aww_alloy_value(value):
            return None
        return value
    return None


def _normalize_aluminium_bozen_profile_code_token(value: str | None) -> str | None:
    cleaned = _string_or_none(value)
    if cleaned is None:
        return None
    token = cleaned.upper()
    if not token.startswith("A"):
        return token
    normalized_chars = [token[0]]
    for char in token[1:]:
        if char in {"O", "Q", "D"}:
            normalized_chars.append("0")
        elif char == "I":
            normalized_chars.append("1")
        else:
            normalized_chars.append(char)
    return "".join(normalized_chars)


def _is_revisable_chatgpt_ddt_value(row: AcquisitionRow, field_name: str) -> bool:
    for value in row.values:
        if value.blocco != "ddt" or value.campo != field_name:
            continue
        if value.metodo_lettura == "chatgpt" and value.stato != "confermato":
            return True
    return False


def _is_revisable_chatgpt_match_value(row: AcquisitionRow, field_name: str) -> bool:
    for value in row.values:
        if value.blocco != "match" or value.campo != field_name:
            continue
        if value.metodo_lettura == "chatgpt" and value.stato != "confermato":
            return True
    return False


def _sync_row_from_ddt_values(db: Session, row: AcquisitionRow) -> None:
    value_map = {
        value.campo: value
        for value in (
            db.query(ReadValue)
            .filter(ReadValue.acquisition_row_id == row.id, ReadValue.blocco == "ddt")
            .all()
        )
    }

    if row.cdq is None and ("cdq" in value_map or "numero_certificato_ddt" in value_map):
        row.cdq = _final_value_for_row(value_map.get("cdq")) or _final_value_for_row(value_map.get("numero_certificato_ddt"))
    if row.colata is None and "colata" in value_map:
        row.colata = _final_value_for_row(value_map.get("colata"))
    if row.peso is None and "peso" in value_map:
        row.peso = _final_value_for_row(value_map.get("peso"))
    if row.diametro is None and "diametro" in value_map:
        row.diametro = _final_value_for_row(value_map.get("diametro"))
    if row.ordine is None and ("customer_order_no" in value_map or "ordine" in value_map):
        row.ordine = _final_value_for_row(value_map.get("customer_order_no")) or _final_value_for_row(value_map.get("ordine"))
    if "ddt" in value_map and row.ddt is None:
        row.ddt = _final_value_for_row(value_map.get("ddt"))
    if "lega" in value_map and (
        row.lega_base is None
        or (_resolve_row_supplier_key(row) == "aww" and not _is_valid_aww_alloy_value(row.lega_base))
    ):
        next_alloy = _final_value_for_row(value_map.get("lega"))
        if _resolve_row_supplier_key(row) != "aww" or _is_valid_aww_alloy_value(next_alloy):
            row.lega_base = next_alloy


def _row_ddt_core_field_value(row: AcquisitionRow, field_name: str) -> str | None:
    field_map = {
        "cdq": row.cdq,
        "numero_certificato_ddt": row.cdq,
        "colata": row.colata,
        "diametro": row.diametro,
        "peso": row.peso,
        "ordine": row.ordine,
        "ddt": row.ddt,
        "lega": _row_high_alloy_value(row),
    }
    value = field_map.get(field_name)
    if field_name in {"diametro", "peso"}:
        return _normalize_value_for_field("ddt", field_name, value)
    return _string_or_none(value)


def _sync_ddt_values_from_row_fields(
    db: Session,
    row: AcquisitionRow,
    *,
    actor_id: int,
    touched_fields: set[str] | None = None,
) -> None:
    field_dependencies = {
        "cdq": {"cdq"},
        "numero_certificato_ddt": {"cdq"},
        "colata": {"colata"},
        "diametro": {"diametro"},
        "peso": {"peso"},
        "ordine": {"ordine"},
        "ddt": {"ddt"},
        "lega": {"lega_base", "lega_designazione", "variante_lega"},
    }
    for field_name in ("cdq", "numero_certificato_ddt", "colata", "diametro", "peso", "ordine", "ddt", "lega"):
        dependencies = field_dependencies[field_name]
        if touched_fields is not None and not (dependencies & touched_fields):
            continue
        row_value = _row_ddt_core_field_value(row, field_name)
        if row_value is None and touched_fields is None:
            continue
        _upsert_read_value_model(
            db=db,
            acquisition_row_id=row.id,
            blocco="ddt",
            campo=field_name,
            valore_grezzo=row_value,
            valore_standardizzato=row_value,
            valore_finale=row_value,
            stato="proposto",
            document_evidence_id=None,
            metodo_lettura="sistema",
            fonte_documentale="ddt",
            confidenza=0.9,
            actor_id=actor_id,
        )


def _row_high_alloy_value(row: AcquisitionRow) -> str | None:
    return (
        _string_or_none(row.lega_base)
        or _string_or_none(row.lega_designazione)
        or _string_or_none(row.variante_lega)
    )


def _row_match_core_field_value(row: AcquisitionRow, field_name: str) -> str | None:
    field_map = {
        "numero_certificato_certificato": row.cdq,
        "ordine_cliente_certificato": row.ordine,
        "lega_certificato": _row_high_alloy_value(row),
        "diametro_certificato": row.diametro,
        "colata_certificato": row.colata,
        "ddt_certificato": row.ddt,
        "peso_certificato": row.peso,
    }
    return _string_or_none(field_map.get(field_name))


def _sync_match_values_from_row_fields(
    db: Session,
    row: AcquisitionRow,
    *,
    actor_id: int,
    touched_fields: set[str],
) -> None:
    field_dependencies = {
        "numero_certificato_certificato": {"cdq"},
        "ordine_cliente_certificato": {"ordine"},
        "lega_certificato": {"lega_base", "lega_designazione", "variante_lega"},
        "diametro_certificato": {"diametro"},
        "colata_certificato": {"colata"},
        "ddt_certificato": {"ddt"},
        "peso_certificato": {"peso"},
    }

    for field_name, dependencies in field_dependencies.items():
        if not dependencies & touched_fields:
            continue
        row_value = _row_match_core_field_value(row, field_name)
        _upsert_read_value_model(
            db=db,
            acquisition_row_id=row.id,
            blocco="match",
            campo=field_name,
            valore_grezzo=row_value,
            valore_standardizzato=row_value,
            valore_finale=row_value,
            stato="corretto",
            document_evidence_id=None,
            metodo_lettura="sistema",
            fonte_documentale="certificato",
            confidenza=None,
            actor_id=actor_id,
        )


def _sync_row_from_match_values(db: Session, row: AcquisitionRow) -> None:
    value_map = {
        value.campo: value
        for value in (
            db.query(ReadValue)
            .filter(ReadValue.acquisition_row_id == row.id, ReadValue.blocco == "match")
            .all()
        )
    }
    certificate_number = _final_value_for_row(value_map.get("numero_certificato_certificato"))
    if certificate_number is not None:
        row.cdq = certificate_number
    if row.ordine is None and "ordine_cliente_certificato" in value_map:
        row.ordine = _final_value_for_row(value_map.get("ordine_cliente_certificato"))
    if row.lega_base is None and "lega_certificato" in value_map:
        row.lega_base = _final_value_for_row(value_map.get("lega_certificato"))
    if row.diametro is None and "diametro_certificato" in value_map:
        row.diametro = _final_value_for_row(value_map.get("diametro_certificato"))
    if row.colata is None and "colata_certificato" in value_map:
        row.colata = _final_value_for_row(value_map.get("colata_certificato"))
    if row.ddt is None and "ddt_certificato" in value_map:
        row.ddt = _final_value_for_row(value_map.get("ddt_certificato"))
    if row.peso is None and "peso_certificato" in value_map:
        row.peso = _final_value_for_row(value_map.get("peso_certificato"))


def _sync_row_cdq_from_certificate_document(
    db: Session,
    row: AcquisitionRow,
    certificate_document: Document,
) -> None:
    match_certificate_number = _string_or_none(
        _final_value_for_row(
            db.query(ReadValue)
            .filter(
                ReadValue.acquisition_row_id == row.id,
                ReadValue.blocco == "match",
                ReadValue.campo == "numero_certificato_certificato",
            )
            .one_or_none()
        )
    )
    if match_certificate_number is not None:
        if row.cdq != match_certificate_number:
            row.cdq = match_certificate_number
            db.add(row)
            db.flush()
        return

    if not certificate_document.pages:
        certificate_document = _index_document_from_path(db, certificate_document)
    certificate_document = _ensure_document_page_ocr(db, certificate_document)
    certificate_template = resolve_supplier_template(
        row.supplier.ragione_sociale if row.supplier is not None else None,
        row.fornitore_raw,
        row.ddt_document.supplier.ragione_sociale if row.ddt_document and row.ddt_document.supplier else None,
        certificate_document.supplier.ragione_sociale if certificate_document.supplier is not None else None,
    )
    certificate_matches = reader_detect_certificate_core_matches(
        certificate_document.pages,
        supplier_key=certificate_template.supplier_key if certificate_template is not None else None,
    )
    supplier_fields = reader_extract_supplier_match_fields(
        certificate_document.pages,
        certificate_template.supplier_key if certificate_template is not None else None,
        "certificato",
    )
    certificate_number = _string_or_none(
        cast(dict[str, object], certificate_matches.get("numero_certificato_certificato") or {}).get("final")
    )
    if _certificate_number_from_local_sync_is_untrusted(
        certificate_template.supplier_key if certificate_template is not None else None,
        certificate_number,
    ):
        certificate_number = None
    delivery_note = _string_or_none(supplier_fields.get("delivery_note_no"))
    changed = False
    if certificate_number is not None:
        row.cdq = certificate_number
        changed = True
    if row.ddt is None and delivery_note is not None:
        row.ddt = delivery_note
        changed = True
    if changed:
        db.add(row)
        db.flush()


def _certificate_number_from_local_sync_is_untrusted(supplier_key: str | None, certificate_number: str | None) -> bool:
    return supplier_key == "zalco" and reader_normalize_match_token(certificate_number) == "10204"


def _final_value_for_row(value: ReadValue | None) -> str | None:
    if value is None:
        return None
    return _normalize_value_for_field(
        value.blocco,
        value.campo,
        value.valore_finale or value.valore_standardizzato or value.valore_grezzo,
    )


def _read_value_has_payload(value: ReadValue) -> bool:
    return any(
        _string_or_none(candidate) is not None
        for candidate in (
            _normalize_value_for_field(value.blocco, value.campo, value.valore_finale),
            _normalize_value_for_field(value.blocco, value.campo, value.valore_standardizzato),
            _string_or_none(value.valore_grezzo),
        )
    )


def _prune_unconfirmed_block_values(
    db: Session,
    *,
    row_id: int,
    block: str,
    keep_fields: set[str],
) -> None:
    stale_values = (
        db.query(ReadValue)
        .filter(
            ReadValue.acquisition_row_id == row_id,
            ReadValue.blocco == block,
            ReadValue.stato != "confermato",
        )
        .all()
    )
    for value in stale_values:
        if value.campo in keep_fields:
            continue
        value.valore_grezzo = None
        value.valore_standardizzato = None
        value.valore_finale = None
        value.stato = "scartato"
        value.document_evidence_id = None
        value.confidenza = None


def _upsert_read_value_model(
    db: Session,
    *,
    acquisition_row_id: int,
    blocco: str,
    campo: str,
    valore_grezzo: str | None,
    valore_standardizzato: str | None,
    valore_finale: str | None,
    stato: str,
    document_evidence_id: int | None,
    metodo_lettura: str,
    fonte_documentale: str,
    confidenza: float | None,
    actor_id: int,
) -> ReadValue:
    existing = (
        db.query(ReadValue)
        .filter(
            ReadValue.acquisition_row_id == acquisition_row_id,
            ReadValue.blocco == blocco,
            ReadValue.campo == campo,
        )
        .one_or_none()
    )

    before_value = None
    action = "valore_creato"
    if existing is None:
        existing = ReadValue(acquisition_row_id=acquisition_row_id, blocco=blocco, campo=campo)
        db.add(existing)
    else:
        before_value = existing.valore_finale or existing.valore_standardizzato or existing.valore_grezzo
        action = "valore_aggiornato"

    normalized_grezzo = _string_or_none(valore_grezzo)
    normalized_standardizzato = _normalize_value_for_field(blocco, campo, valore_standardizzato)
    normalized_finale = _normalize_value_for_field(blocco, campo, valore_finale)

    if normalized_standardizzato is None and _is_numeric_standardized_field(blocco, campo):
        normalized_standardizzato = _normalize_value_for_field(blocco, campo, normalized_grezzo)
    if normalized_finale is None and normalized_standardizzato is not None:
        normalized_finale = normalized_standardizzato

    existing.valore_grezzo = normalized_grezzo
    existing.valore_standardizzato = normalized_standardizzato
    existing.valore_finale = normalized_finale
    existing.stato = stato
    existing.document_evidence_id = document_evidence_id
    existing.metodo_lettura = metodo_lettura
    existing.fonte_documentale = fonte_documentale
    existing.confidenza = confidenza
    existing.utente_ultima_modifica_id = actor_id
    existing.timestamp_ultima_modifica = datetime.now(UTC)
    db.flush()

    after_value = existing.valore_finale or existing.valore_standardizzato or existing.valore_grezzo
    if before_value != after_value:
        db.add(
            AcquisitionValueHistory(
                acquisition_row_id=acquisition_row_id,
                value_id=existing.id,
                blocco=blocco,
                campo=campo,
                valore_prima=before_value,
                valore_dopo=after_value,
                utente_id=actor_id,
            )
        )

    _record_history_event(
        db=db,
        acquisition_row_id=acquisition_row_id,
        blocco=blocco,
        azione=action,
        user_id=actor_id,
        nota_breve=campo,
    )
    return existing


def normalize_existing_numeric_values(db: Session) -> dict[str, int]:
    updated_values = 0
    updated_rows = 0

    values = db.query(ReadValue).all()
    for value in values:
        if not _is_numeric_standardized_field(value.blocco, value.campo):
            continue

        normalized_standardizzato = _normalize_value_for_field(value.blocco, value.campo, value.valore_standardizzato)
        normalized_finale = _normalize_value_for_field(value.blocco, value.campo, value.valore_finale)

        if normalized_standardizzato is None:
            normalized_standardizzato = _normalize_value_for_field(value.blocco, value.campo, value.valore_grezzo)
        if normalized_finale is None and normalized_standardizzato is not None:
            normalized_finale = normalized_standardizzato

        if value.valore_standardizzato != normalized_standardizzato:
            value.valore_standardizzato = normalized_standardizzato
            updated_values += 1
        if value.valore_finale != normalized_finale:
            value.valore_finale = normalized_finale
            updated_values += 1

    rows = db.query(AcquisitionRow).options(selectinload(AcquisitionRow.values)).all()
    for row in rows:
        ddt_values = {value.campo: value for value in row.values if value.blocco == "ddt"}
        normalized_diametro = _final_value_for_row(ddt_values.get("diametro"))
        normalized_peso = _final_value_for_row(ddt_values.get("peso"))

        if row.diametro != normalized_diametro:
            row.diametro = normalized_diametro
            updated_rows += 1
        if row.peso != normalized_peso:
            row.peso = normalized_peso
            updated_rows += 1

    db.commit()
    return {
        "updated_values": updated_values,
        "updated_rows": updated_rows,
    }


